# ══════════════════════════════════════════════════════════════════
# CAPA IA — motor central de la app
# Prioridad: 1) Groq (gratis, llama-3.3-70b)
#            2) Claude (fallback, requiere créditos)
# Nombre _gemini() mantenido para compatibilidad.
# ══════════════════════════════════════════════════════════════════
def _gemini(prompt: str, system: str = "", use_search: bool = False,
             max_tokens: int = 500, temperature: float = 0.3,
             json_mode: bool = False) -> str:
    """
    Motor IA central — Groq primero (gratis), Claude como fallback.
    json_mode=True → pide JSON limpio.
    use_search=True → ignorado (Groq no tiene web search nativo).
    """
    import requests as _req, json as _jmod

    _sys = system or ""
    if json_mode:
        _sys += ("\nResponde SOLO con JSON válido, sin markdown, sin texto extra, "
                 "sin backticks. Solo el objeto JSON.")

    def _clean_json(raw):
        raw = raw.replace("```json","").replace("```","").strip()
        i = raw.find("{"); j = raw.rfind("}") + 1
        if i >= 0 and j > i:
            raw = raw[i:j]
        return raw

    # ── INTENTO 1: Groq llama-3.3-70b (gratis) ──────────────────
    _groq_key = GROQ_API_KEY
    if _groq_key:
        try:
            _msgs_groq = []
            if _sys.strip():
                _msgs_groq.append({"role": "system", "content": _sys.strip()})
            _msgs_groq.append({"role": "user", "content": prompt})

            _r_groq = _req.post(
                "https://api.groq.com/openai/v1/chat/completions",
                headers={"Authorization": f"Bearer {_groq_key}",
                         "Content-Type": "application/json"},
                json={
                    "model":       "llama-3.3-70b-versatile",
                    "max_tokens":  max(max_tokens, 512),
                    "temperature": temperature,
                    "messages":    _msgs_groq,
                },
                timeout=45,
            )
            if _r_groq.status_code == 200:
                raw = (_r_groq.json()
                              .get("choices",[{}])[0]
                              .get("message",{})
                              .get("content","").strip())
                if raw:
                    if json_mode:
                        raw = _clean_json(raw)
                    return raw
            elif _r_groq.status_code == 429:
                # Rate limit 70b → fallback a 8b-instant (límite separado)
                try:
                    _r_g2 = _req.post(
                        "https://api.groq.com/openai/v1/chat/completions",
                        headers={"Authorization": f"Bearer {_groq_key}",
                                 "Content-Type": "application/json"},
                        json={
                            "model":       "llama-3.1-8b-instant",
                            "max_tokens":  max(max_tokens, 512),
                            "temperature": temperature,
                            "messages":    _msgs_groq,
                        }, timeout=30,
                    )
                    if _r_g2.status_code == 200:
                        raw = (_r_g2.json()
                                    .get("choices",[{}])[0]
                                    .get("message",{})
                                    .get("content","").strip())
                        if raw:
                            if json_mode:
                                raw = _clean_json(raw)
                            return raw
                except: pass
        except: pass

    # ── INTENTO 3: Claude (fallback) ─────────────────────────────
    _cl_key = ANTHROPIC_API_KEY
    if _cl_key:
        try:
            _body_c = {
                "model":       "claude-sonnet-4-6",
                "max_tokens":  max(max_tokens, 512),
                "temperature": temperature,
                "messages":    [{"role": "user", "content": prompt}],
            }
            if _sys.strip():
                _body_c["system"] = _sys.strip()
            _r_c = _req.post(
                "https://api.anthropic.com/v1/messages",
                headers={"x-api-key": _cl_key, "anthropic-version": "2023-06-01",
                         "content-type": "application/json"},
                json=_body_c, timeout=55,
            )
            if _r_c.status_code == 200:
                raw = "\n".join(
                    blk.get("text","") for blk in _r_c.json().get("content",[])
                    if blk.get("type") == "text" and blk.get("text","").strip()
                ).strip()
                if raw:
                    if json_mode: raw = _clean_json(raw)
                    return raw
        except: pass

    # ── INTENTO 4: OpenAI GPT-4o-mini (fallback) ──────────────────
    _oai_key = globals().get("OPENAI_API_KEY","") or ""
    if _oai_key:
        try:
            _msgs_oai = []
            if _sys.strip(): _msgs_oai.append({"role":"system","content":_sys.strip()})
            _msgs_oai.append({"role":"user","content":prompt})
            _r_oai = _req.post(
                "https://api.openai.com/v1/chat/completions",
                headers={"Authorization": f"Bearer {_oai_key}",
                         "Content-Type": "application/json"},
                json={"model":"gpt-4o-mini","max_tokens":max(max_tokens,512),
                      "temperature":temperature,"messages":_msgs_oai},
                timeout=45,
            )
            if _r_oai.status_code == 200:
                raw = (_r_oai.json().get("choices",[{}])[0]
                              .get("message",{}).get("content","").strip())
                if raw:
                    if json_mode: raw = _clean_json(raw)
                    return raw
        except: pass

    # ── INTENTO 5: Grok xAI (fallback) ────────────────────────────
    _grok_key = globals().get("GROK_API_KEY","") or ""
    if _grok_key:
        try:
            _msgs_grok = []
            if _sys.strip(): _msgs_grok.append({"role":"system","content":_sys.strip()})
            _msgs_grok.append({"role":"user","content":prompt})
            _r_grok = _req.post(
                "https://api.x.ai/v1/chat/completions",
                headers={"Authorization": f"Bearer {_grok_key}",
                         "Content-Type": "application/json"},
                json={"model":"grok-3-mini","max_tokens":max(max_tokens,512),
                      "temperature":temperature,"messages":_msgs_grok},
                timeout=45,
            )
            if _r_grok.status_code == 200:
                raw = (_r_grok.json().get("choices",[{}])[0]
                               .get("message",{}).get("content","").strip())
                if raw:
                    if json_mode: raw = _clean_json(raw)
                    return raw
        except: pass

    return ""
def _gemini_json(prompt: str, system: str = "", use_search: bool = False,
                  max_tokens: int = 500) -> dict:
    """Wrapper que devuelve dict parseado, o {} si falla."""
    import json as _jj
    raw = _gemini(prompt, system=system, use_search=use_search,
                  max_tokens=max_tokens, json_mode=True)
    if not raw:
        return {}
    try:
        return _jj.loads(raw)
    except:
        return {}



