@st.cache_data(ttl=3600, show_spinner=False)
def get_form_domestic(team_id: str, cup_slug: str) -> list:
    """
    Para torneos UEFA/CONCACAF/copa: busca la forma del equipo
    en su liga doméstica (ESPN /soccer/teams/{id}/schedule)
    que trae resultados cross-liga.
    Fallback de get_form cuando cup_slug no devuelve historial.
    """
    team_id = str(team_id)
    # ESPN endpoint sin slug devuelve todo el schedule del equipo cross-liga
    data   = eg(f"https://site.api.espn.com/apis/site/v2/sports/soccer/teams/{team_id}/schedule")
    events = data.get("events", [])
    matches = []
    for ev in events:
        try:
            comp  = ev["competitions"][0]
            comps = comp["competitors"]
            state = ev.get("status", {}).get("type", {}).get("state", "")
            if state != "post": continue
            hc = next(c for c in comps if c["homeAway"] == "home")
            ac = next(c for c in comps if c["homeAway"] == "away")
            is_home = str(hc["team"]["id"]) == team_id
            my  = hc if is_home else ac
            opp = ac if is_home else hc
            gf  = parse_score(my.get("score", 0))
            gc  = parse_score(opp.get("score", 0))
            result = "W" if gf > gc else ("D" if gf == gc else "L")
            matches.append({
                "date":     ev.get("date", "")[:10],
                "result":   result,
                "gf":       gf,
                "gc":       gc,
                "xg_f":     0.0,
                "xg_c":     0.0,
                "opponent": opp["team"].get("displayName", ""),
                "is_home":  is_home,
                "league":   ev.get("name", ""),
            })
        except: continue
    matches.sort(key=lambda x: x["date"], reverse=True)
    return matches[:15]




def _clean_sheet_rate(form, is_home=None, n=8):
    """
    Racha de clean sheets — predictor directo de U2.5 y AA.
    form: lista de partidos del equipo (get_form output)
    is_home: None=todos, True=solo como local, False=solo como visitante
    Retorna: {rate, streak, n_cs, n_games}
      rate   = % de partidos sin recibir gol (últimos n)
      streak = racha activa de clean sheets consecutivos
      n_cs   = cantidad de clean sheets en últimos n
    """
    if not form:
        return {"rate": 0.0, "streak": 0, "n_cs": 0, "n_games": 0}
    filtered = [g for g in form[:n] if is_home is None or g.get("is_home") == is_home]
    if not filtered:
        filtered = form[:n]  # fallback: todos
    n_cs = sum(1 for g in filtered if g.get("gc", 1) == 0)
    # Racha activa (partidos más recientes primero)
    streak = 0
    for g in filtered:
        if g.get("gc", 1) == 0:
            streak += 1
        else:
            break
    return {
        "rate":    round(n_cs / len(filtered), 3) if filtered else 0.0,
        "streak":  streak,
        "n_cs":    n_cs,
        "n_games": len(filtered),
    }


def _fixture_congestion(form, n=14):
    """
    Congestión de fixture — fatiga real por calendario apretado.
    Calcula días promedio entre partidos en los últimos n días.
    form: lista de partidos ordenada por fecha desc (más reciente primero)
    Retorna: {congestion, days_since_last, matches_in_14d, fatigue_factor}
      fatigue_factor: multiplicador xG — <1.0 si hay fatiga, 1.0 normal
    """
    from datetime import datetime as _dt
    if not form or len(form) < 2:
        return {"congestion": False, "days_since_last": 7,
                "matches_in_14d": 0, "fatigue_factor": 1.0}
    today = _dt.now().date()
    dates = []
    for g in form:
        try:
            d = _dt.strptime(g["date"], "%Y-%m-%d").date()
            dates.append(d)
        except: continue
    if not dates:
        return {"congestion": False, "days_since_last": 7,
                "matches_in_14d": 0, "fatigue_factor": 1.0}

    days_since_last = (today - dates[0]).days if dates else 7

    # Partidos jugados en últimos 14 días
    matches_in_14d = sum(1 for d in dates if (today - d).days <= 14)

    # Fatigue factor calibrado:
    # 0-1 partidos en 14d → factor 1.00 (bien descansado)
    # 2   partidos en 14d → factor 1.00 (normal)
    # 3   partidos en 14d → factor 0.97 (leve)
    # 4   partidos en 14d → factor 0.94 (moderada)
    # 5+  partidos en 14d → factor 0.90 (severa — Champions + Liga + Copa)
    fatigue_map = {0: 1.02, 1: 1.01, 2: 1.00, 3: 0.97, 4: 0.94}
    fatigue_factor = fatigue_map.get(matches_in_14d, 0.90)

    # Si llevan +5 días sin jugar: pequeño boost (bien descansado)
    if days_since_last >= 6 and matches_in_14d <= 1:
        fatigue_factor = min(1.04, fatigue_factor + 0.02)

    return {
        "congestion":      matches_in_14d >= 4,
        "days_since_last": days_since_last,
        "matches_in_14d":  matches_in_14d,
        "fatigue_factor":  round(fatigue_factor, 3),
    }


def xg_weighted(form, is_home, odds_prior=0.0, slug="", team_id=None, team_name=""):
    """
    xG con decaimiento exponencial — partidos recientes pesan MÁS.
    Si ESPN devuelve xG real lo usa; si no, usa goles como proxy.
    Incorpora odds como prior bayesiano cuando están disponibles.

    MEJORA: xG separado home/away — usa rendimiento de local cuando juega de local,
    de visitante cuando juega de visitante. Ventaja local calibrada por liga.

    decay = 0.85 por partido (partido de hace 5 = peso 0.44x vs último)
    Ref: Dixon & Coles 1997 — time-weighting de observaciones.
    """
    # ── Ventaja local calibrada por liga ──
    # Fuentes: Pollard & Pollard (2005), Nevill & Holder (1999), Goumas (2014),
    # FBref 2015-2024, StatsBomb. Multiplicador xG del equipo local.
    # MLS es la más baja del mundo (~39.5% hw). Bolivia la más alta (altitud 3640m).
    _LEAGUE_HA = {
        # ── EUROPA TOP 5 ──
        "eng.1": 1.08,   # Premier League — referencia (45.5% hw)
        "eng.2": 1.09,   # Championship
        "eng.3": 1.09,   # League One
        "eng.4": 1.09,   # League Two
        "esp.1": 1.08,   # La Liga (46.5% hw)
        "esp.2": 1.09,   # Segunda División
        "ger.1": 1.07,   # Bundesliga (45.5% hw, ligero)
        "ger.2": 1.08,   # 2. Bundesliga
        "ita.1": 1.07,   # Serie A (44.0% hw)
        "ita.2": 1.08,   # Serie B
        "fra.1": 1.07,   # Ligue 1 (43.5% hw)
        "fra.2": 1.08,   # Ligue 2
        # ── EUROPA RESTO ──
        "por.1": 1.07,   # Primeira Liga
        "por.2": 1.08,
        "ned.1": 1.07,   # Eredivisie (45.5% hw)
        "ned.2": 1.08,
        "bel.1": 1.08,   # Pro League
        "tur.1": 1.10,   # Süper Lig — afición muy intensa (47% hw)
        "tur.2": 1.09,
        "sco.1": 1.09,   # Scottish Premiership
        "sco.2": 1.09,
        "den.1": 1.08,   # Superliga Dinamarca
        "nor.1": 1.08,   # Eliteserien
        "swe.1": 1.07,   # Allsvenskan
        "gre.1": 1.10,   # Super League Grecia — alta presión afición (46.5% hw)
        "pol.1": 1.09,   # Ekstraklasa
        "aut.1": 1.08,   # Bundesliga Austria
        "sui.1": 1.07,   # Super League Suiza
        "cze.1": 1.08,   # Czech First League
        "hun.1": 1.09,   # OTP Bank Liga
        "rum.1": 1.09,   # Liga I Romania
        "cro.1": 1.09,   # HNL Croatia
        "ser.1": 1.09,   # SuperLiga Serbia
        "ukr.1": 1.08,   # Premier League Ukraine
        "isr.1": 1.08,   # Israeli Premier League
        # ── LATINOAMÉRICA ──
        "mex.1": 1.09,   # Liga MX — viajes largos + altitud CDMX/Toluca (44.5% hw)
        "mex.2": 1.09,   # Liga de Expansión
        "bra.1": 1.09,   # Brasileirão — viajes enormes país + altitud (46% hw)
        "bra.2": 1.09,
        "arg.1": 1.10,   # Liga Argentina — afición muy intensa (46% hw)
        "arg.2": 1.09,
        "col.1": 1.10,   # Liga BetPlay — altitud Bogotá/Manizales/Armenia (45.5% hw)
        "chi.1": 1.09,   # Primera División Chile
        "uru.1": 1.09,   # Primera División Uruguay
        "per.1": 1.10,   # Liga 1 Perú — altitud Lima/Cusco/Juliaca
        "ecu.1": 1.10,   # LigaPro Ecuador — altitud Quito 2850m
        "ven.1": 1.09,   # Liga FUTVE
        "par.1": 1.09,   # División de Honor Paraguay
        "bol.1": 1.12,   # División Profesional Bolivia — La Paz 3640m MAYOR HA del mundo
        # ── NORTEAMÉRICA ──
        "usa.1": 1.04,   # MLS — ventaja local MUY baja (39.5% hw, estadios neutros, cultura)
        "can.1": 1.05,   # Canadian Premier League
        # ── MEDIO ORIENTE / ASIA / AFRICA ──
        "sau.1": 1.08,   # Saudi Pro League
        "jpn.1": 1.06,   # J1 League — cultura más neutral (41.5% hw)
        "jpn.2": 1.06,
        "kor.1": 1.07,   # K League 1
        "chn.1": 1.07,   # Chinese Super League
        "aus.1": 1.06,   # A-League Australia
        # ── UEFA COMPETICIONES ──
        "uefa.champions": 1.05,  # Champions League — casi neutral
        "uefa.europa":    1.05,  # Europa League
        "uefa.europa.conf": 1.06, # Conference League
        "uefa.cl":  1.05,  "uefa.el":  1.05,  "uefa.ecl": 1.06,  # aliases
        # ── CONCACAF ──
        "concacaf.champions": 1.08,  # CCC — ventaja real (altitud MX + viajes largos MLS)
        "concacaf.league": 1.07,
        # ── COPAS NACIONALES (single leg, más neutral) ──
        "eng.fa":    1.06,  # FA Cup
        "eng.lc":    1.06,  # League Cup
        "esp.copa":  1.06,  # Copa del Rey
        "ger.dfb":   1.06,  # DFB-Pokal
        "ita.coppa": 1.06,  # Coppa Italia
        "fra.coupe": 1.06,  # Coupe de France
        "por.cup":   1.06,
        "ned.cup":   1.06,
        "sco.cup":   1.06,
        "mex.copa":  1.07,  # Copa MX
    }
    # Detectar liga del slug
    _ha_mult = 1.08  # default
    if slug:
        for _k, _v in _LEAGUE_HA.items():
            if _k in str(slug).lower():
                _ha_mult = _v
                break

    if not form:
        return (1.25 * _ha_mult / 1.08 if is_home else 1.0)

    DECAY = 0.85

    # ── Separar forma home vs away ──
    home_matches = [r for r in form if r.get("is_home", True)]
    away_matches = [r for r in form if not r.get("is_home", True)]

    def _weighted_xg(matches):
        tw = 0.0; txg = 0.0
        for i, r in enumerate(matches):
            w = DECAY ** i
            xg_real = r.get("xg_f", 0.0)
            xg_val  = xg_real if xg_real > 0.1 else float(r.get("gf", 1.0))
            txg += w * xg_val
            tw  += w
        return txg / tw if tw > 0 else None

    # Calcular xG específico del contexto (local o visitante)
    context_xg  = _weighted_xg(home_matches if is_home else away_matches)
    overall_xg  = _weighted_xg(form)

    # Si hay suficientes partidos en el contexto correcto (≥3), usar contextual (80%) + general (20%)
    context_n = len(home_matches if is_home else away_matches)
    if context_xg is not None and context_n >= 3:
        xg_base = 0.80 * context_xg + 0.20 * (overall_xg or context_xg)
    elif overall_xg is not None:
        xg_base = overall_xg
    else:
        xg_base = 1.25 if is_home else 1.0

    # Home advantage calibrado por liga (solo para el local)
    if is_home:
        xg_base *= _ha_mult

    # Bayesian prior desde odds de mercado (si disponible)
    if odds_prior > 0.05:
        xg_from_odds = max(0.3, -math.log(max(0.01, 1 - odds_prior)) * 1.8)
        xg_base = 0.80 * xg_base + 0.20 * xg_from_odds

    # ── _LEAGUE_HISTORICAL team_stats prior ──
    # Usa datos reales de temporada (gf/ga por partido) como prior cuando hay pocos partidos ESPN.
    # Peso: 30% si forma ESPN ≥3 partidos, 50% si <3 partidos (datos escasos).
    if slug and team_name:
        try:
            _lh = _LEAGUE_HISTORICAL.get(slug, {})
            _ts = _lh.get("team_stats", {})
            _tn_norm = team_name.strip().lower()
            _ts_match = next(
                (v for k, v in _ts.items() if k.lower() == _tn_norm or
                 k.lower() in _tn_norm or _tn_norm in k.lower()),
                None
            )
            if _ts_match:
                _ts_xg = float(_ts_match["gf"])
                if not is_home:
                    _ratio = _lh.get("ratio_h", 0.545)
                    _ts_xg = _ts_xg * (1 - _ratio) / _ratio
                _ts_weight = 0.30 if len(form or []) >= 3 else 0.50
                xg_base = (1 - _ts_weight) * xg_base + _ts_weight * _ts_xg
        except: pass

    # ── Ajuste defensivo: si el RIVAL tiene ga bajo en sus team_stats, reducir xg_base ──
    # Esto captura que LAFC (ga=1.18) concede menos que el promedio MLS (1.55),
    # por lo tanto el equipo que ataca contra LAFC debería tener xG más bajo.
    # Este ajuste se aplica externamente en diamond_engine / cartelera, pero
    # aquí añadimos un leve ajuste usando rival_team_name si está disponible.
    # Nota: el parámetro rival_team_name no existe aún en la firma — ajuste queda
    # embebido en la lógica del caller que calcula ambos xG juntos.

    # ── API-Football xG real — blend si disponible ──
    # Solo enriquece, nunca reemplaza. Si no hay key o falla → xg_base sin cambio.
    # xg_for/xg_against son promedios de temporada completa, menor peso que forma reciente
    if slug and form:
        try:
            _team_name = form[0].get("opponent", "")  # proxy para nombre del equipo
            if not _team_name and len(form) > 1:
                _team_name = form[1].get("opponent", "")
            if _team_name:
                _apif = _apifootball_team_stats(_team_name, slug)
                if _apif:
                    _xg_api = _apif.get("xg_for", 0) if is_home else _apif.get("xg_for", 0)
                    if _xg_api and _xg_api > 0.2:
                        # 25% API-Football (temporada) + 75% forma reciente (más precisa)
                        xg_base = 0.75 * xg_base + 0.25 * _xg_api
        except: pass

    # ── Night Scout blend — datos investigados por IA (últimos 5 reales) ──
    if team_id:
        _ns_xg_s, _ns_xg_c = _ns_get_team_xg(str(team_id), is_home)
        if _ns_xg_s and _ns_xg_s > 0.2:
            _ns_info_w = _ns_get_team_info(str(team_id))
            _mom_w = (_ns_info_w.get("momentum","medio") or "medio").lower()
            _mom_adj_w = {"alto":1.06,"medio":1.00,"bajo":0.94}.get(_mom_w, 1.0)
            _ns_xg_adj = _ns_xg_s * _mom_adj_w
            if is_home and slug:
                # Aplicar ventaja local al xG del Night Scout también
                _ha_ns = _LEAGUE_HA.get(slug, 1.08)
                _ns_xg_adj *= (_ha_ns / 1.08)  # relativo al default 1.08
            # Blend: 55% Night Scout (forma real investigada) + 45% ESPN (xG computado)
            # Si la forma ESPN tiene pocos partidos (<3), dar más peso al Night Scout
            _espn_weight = 0.45 if len(form or []) >= 3 else 0.25
            _ns_weight   = 1 - _espn_weight
            xg_base = round(_ns_weight * _ns_xg_adj + _espn_weight * xg_base, 3)

    return round(max(0.20, min(4.5, xg_base)), 3)

@st.cache_data(ttl=7200, show_spinner=False)
def get_h2h(home_id, away_id, slug, home_name, away_name):
    home_id = str(home_id); away_id = str(away_id)
    data    = eg(f"{ESPN}/{slug}/teams/{home_id}/schedule")
    h2h     = []
    for ev in data.get("events", []):
        try:
            comp  = ev["competitions"][0]
            comps = comp["competitors"]
            if ev.get("status", {}).get("type", {}).get("state") != "post": continue
            ids   = {str(c["team"]["id"]) for c in comps}
            if away_id not in ids: continue
            hc = next(c for c in comps if c["homeAway"] == "home")
            ac = next(c for c in comps if c["homeAway"] == "away")
            gh = parse_score(hc.get("score", 0))
            ga = parse_score(ac.get("score", 0))
            hn = hc["team"]["displayName"]; an = ac["team"]["displayName"]
            win = home_name if gh > ga else (away_name if ga > gh else "Draw")
            h2h.append({"home":hn,"away":an,"gh":gh,"ga":ga,
                        "winner":win,"date":ev.get("date","")[:10],"total":gh+ga})
        except: continue
    h2h.sort(key=lambda x: x["date"], reverse=True)
    return h2h[:10]

@st.cache_data(ttl=900, show_spinner=False)
def get_standings(slug):
    """Tabla de posiciones desde ESPN."""
    data = eg(f"{ESPN}/{slug}/standings")
    rows = []
    try:
        for group in data.get("standings", {}).get("entries", []):
            t = group.get("team", {})
            stats = {s["name"]: s.get("displayValue","?") for s in group.get("stats",[])}
            rows.append({
                "pos":   stats.get("rank", group.get("rank","?")),
                "team":  t.get("displayName","?"),
                "tid":   str(t.get("id","")),
                "pj":    stats.get("gamesPlayed","?"),
                "pts":   stats.get("points","?"),
                "gf":    stats.get("pointsFor","?"),
                "gc":    stats.get("pointsAgainst","?"),
                "dif":   stats.get("pointDifferential","?"),
                "forma": stats.get("streak",""),
            })
    except: pass
    return rows


def _tabla_posicion_delta(home: str, away: str, slug: str) -> dict:
    """
    POSICIÓN EN TABLA como variable de picks.
    Si Betis (6°) vs Getafe (18°) → diferencia impacta probabilidad.
    Retorna: {delta_h, delta_a, pos_h, pos_a, pts_h, pts_a, desc}
    """
    _default = {"delta_h": 0.0, "delta_a": 0.0, "pos_h": 0, "pos_a": 0,
                "pts_h": 0, "pts_a": 0, "desc": ""}
    if not slug:
        return _default
    try:
        rows = get_standings(slug)
        if not rows:
            return _default

        def _find(name):
            n = name.lower().strip()
            best, best_score = None, 0
            for r in rows:
                tn = r.get("team","").lower()
                # exact
                if n == tn: return r
                # partial match
                words = n.split()
                score = sum(1 for w in words if w in tn or w[:5] in tn)
                if score > best_score:
                    best_score = score
                    best = r
            return best if best_score > 0 else None

        rh = _find(home)
        ra = _find(away)
        if not rh or not ra:
            return _default

        try:
            pos_h = int(rh.get("pos", 0) or 0)
            pos_a = int(ra.get("pos", 0) or 0)
            pts_h = int(rh.get("pts", 0) or 0)
            pts_a = int(ra.get("pts", 0) or 0)
            # Goles a favor/contra y diferencia de goles
            gf_h  = float(str(rh.get("gf", 0) or 0).replace("?","0") or 0)
            gc_h  = float(str(rh.get("gc", 0) or 0).replace("?","0") or 0)
            gf_a  = float(str(ra.get("gf", 0) or 0).replace("?","0") or 0)
            gc_a  = float(str(ra.get("gc", 0) or 0).replace("?","0") or 0)
            gd_h  = float(str(rh.get("dif", 0) or 0).replace("?","0") or 0) or (gf_h - gc_h)
            gd_a  = float(str(ra.get("dif", 0) or 0).replace("?","0") or 0) or (gf_a - gc_a)
            pj_h  = max(1, int(str(rh.get("pj", 1) or 1).replace("?","1") or 1))
            pj_a  = max(1, int(str(ra.get("pj", 1) or 1).replace("?","1") or 1))
        except:
            return _default

        if pos_h == 0 or pos_a == 0:
            return _default

        n_equipos = len(rows) or 20

        # ── SEÑAL 1: Posición en tabla (normalizada) ──
        rank_h = 1 - (pos_h - 1) / max(n_equipos - 1, 1)
        rank_a = 1 - (pos_a - 1) / max(n_equipos - 1, 1)
        diff   = rank_h - rank_a
        delta_h = diff * 0.14

        # ── SEÑAL 2: Diferencia de puntos (calidad acumulada) ──
        if pts_h > 0 and pts_a > 0:
            pts_diff_norm = (pts_h - pts_a) / max(pts_h, pts_a, 1)
            delta_h += pts_diff_norm * 0.05

        # ── SEÑAL 3: Goal Difference por partido (eficiencia real) ──
        # GD/partido refleja qué tan dominante es el equipo más allá de la posición
        gd_per_h = gd_h / pj_h
        gd_per_a = gd_a / pj_a
        gd_gap   = gd_per_h - gd_per_a  # positivo = local domina más
        # Normalizar: GD/partido de ±2.0 → delta ±0.06
        delta_h += max(-0.07, min(0.07, gd_gap * 0.035))

        # ── SEÑAL 4: Ataque relativo (goles anotados por partido) ──
        if pj_h > 0 and pj_a > 0:
            avg_gf_h = gf_h / pj_h
            avg_gf_a = gf_a / pj_a
            avg_gc_h = gc_h / pj_h
            avg_gc_a = gc_a / pj_a
            # Local que anota mucho + rival que encaja mucho = ventaja ofensiva
            atk_edge = (avg_gf_h - avg_gf_a) * 0.015  # hasta ±0.04
            def_edge = (avg_gc_a - avg_gc_h) * 0.015   # rival encaja más = ventaja
            delta_h += max(-0.04, min(0.04, atk_edge + def_edge))

        delta_a = -delta_h

        pos_gap = abs(pos_h - pos_a)
        # Amplificar por magnitud del gap
        if pos_gap >= 12:   delta_h *= 1.60; delta_a *= 1.60
        elif pos_gap >= 8:  delta_h *= 1.40; delta_a *= 1.40
        elif pos_gap >= 5:  delta_h *= 1.20; delta_a *= 1.20

        # Cap ±0.25
        delta_h = max(-0.25, min(0.25, delta_h))
        delta_a = max(-0.25, min(0.25, delta_a))

        # GD display
        gd_h_str = f"{gd_h:+.0f}" if gd_h != 0 else "?"
        gd_a_str = f"{gd_a:+.0f}" if gd_a != 0 else "?"
        avg_gf_h_d = round(gf_h/pj_h, 2) if pj_h > 0 else 0
        avg_gf_a_d = round(gf_a/pj_a, 2) if pj_a > 0 else 0
        avg_gc_h_d = round(gc_h/pj_h, 2) if pj_h > 0 else 0
        avg_gc_a_d = round(gc_a/pj_a, 2) if pj_a > 0 else 0

        tendencia = ("Local favorito tabla+GD" if delta_h > 0.08
                     else "Visitante favorito tabla+GD" if delta_h < -0.08
                     else "Nivel similar")
        desc = (f"Pos {pos_h}°({pts_h}pts,GD{gd_h_str}) vs {pos_a}°({pts_a}pts,GD{gd_a_str})"
                f" | Gap {pos_gap} | ∅goles {avg_gf_h_d}vs{avg_gc_h_d} / {avg_gf_a_d}vs{avg_gc_a_d}"
                f" | {tendencia}")

        return {"delta_h": delta_h, "delta_a": delta_a,
                "pos_h": pos_h, "pos_a": pos_a,
                "pts_h": pts_h, "pts_a": pts_a,
                "gf_h": gf_h, "gc_h": gc_h, "gd_h": gd_h,
                "gf_a": gf_a, "gc_a": gc_a, "gd_a": gd_a,
                "avg_gf_h": avg_gf_h_d, "avg_gc_h": avg_gc_h_d,
                "avg_gf_a": avg_gf_a_d, "avg_gc_a": avg_gc_a_d,
                "desc": desc, "pos_gap": pos_gap}
    except:
        return _default

# ══════════════════════════════════════════════════════════
# ODDS API — The Odds API (gratis 500 req/mes)
# ══════════════════════════════════════════════════════════
try:
    ODDS_API_KEY = st.secrets.get("ODDS_API_KEY", "")
except:
    ODDS_API_KEY = os.getenv("ODDS_API_KEY", "")
BOOKMAKERS   = ["bet365","pinnacle","unibet","williamhill"]

@st.cache_data(ttl=600, show_spinner=False)
def get_real_odds(home_name, away_name, league_slug):
    """
    Intenta obtener cuotas reales de The Odds API.
    Si no hay key o falla, devuelve dict vacío.
    """
    _key = st.session_state.get("runtime_odds_key", ODDS_API_KEY)
    if not _key:
        return {}
    # Mapeo de slugs ESPN → sport_key de Odds API
    slug_map = {
        "eng.1":"soccer_epl","esp.1":"soccer_spain_la_liga",
        "ger.1":"soccer_germany_bundesliga","ita.1":"soccer_italy_serie_a",
        "fra.1":"soccer_france_ligue_one","ned.1":"soccer_netherlands_eredivisie",
        "por.1":"soccer_portugal_primeira_liga","mex.1":"soccer_mexico_ligamx",
        "usa.1":"soccer_usa_mls","arg.1":"soccer_argentina_primera_division",
        "bra.1":"soccer_brazil_campeonato","tur.1":"soccer_turkey_super_league",
        "bel.1":"soccer_belgium_first_div","sco.1":"soccer_scotland_premiership",
        "uefa.champions":"soccer_uefa_champs_league","uefa.europa":"soccer_uefa_europa_league",
    }
    sport = slug_map.get(league_slug)
    if not sport: return {}
    try:
        url  = f"https://api.the-odds-api.com/v4/sports/{sport}/odds"
        resp = requests.get(url, params={
            "apiKey": st.session_state.get("runtime_odds_key", ODDS_API_KEY), "regions":"eu",
            "markets":"h2h","oddsFormat":"decimal","bookmakers": ",".join(BOOKMAKERS)
        }, timeout=8)
        if resp.status_code != 200: return {}
        for game in resp.json():
            h = game.get("home_team","").lower()
            a = game.get("away_team","").lower()
            if home_name[:6].lower() in h or away_name[:6].lower() in a:
                out = {}
                for bk in game.get("bookmakers",[]):
                    name = bk["key"]
                    for mkt in bk.get("markets",[]):
                        if mkt["key"] == "h2h":
                            outs = {o["name"].lower():o["price"] for o in mkt["outcomes"]}
                            out[name] = {
                                "h": outs.get(h, 0),
                                "d": outs.get("draw", 0),
                                "a": outs.get(a, 0),
                            }
                return out
    except: pass
    return {}


# ══════════════════════════════════════════════════════════
# FULL ODDS FETCHER — h2h + totals + btts en una sola llamada
# Devuelve cuotas reales para EV calculation
# ══════════════════════════════════════════════════════════

@st.cache_data(ttl=1800, show_spinner=False)
def get_full_odds(home_name: str, away_name: str, league_slug: str) -> dict:
    """
    Obtiene cuotas reales de Odds API para múltiples mercados:
    h2h (1X2), totals (O/U 2.5, 3.5, 1.5), btts.
    Devuelve dict con cuotas promedio entre bookmakers.
    Fallback: dict vacío → el caller usa cuotas fijas.
    """
    _key = st.session_state.get("runtime_odds_key", ODDS_API_KEY)
    if not _key:
        return {}
    _slug_map = {
        # TOP 5
        "eng.1":"soccer_epl","eng.2":"soccer_epl2","eng.fa":"soccer_fa_cup",
        "eng.league_cup":"soccer_league_cup",
        "esp.1":"soccer_spain_la_liga","esp.2":"soccer_spain_segunda_division",
        "esp.copa_del_rey":"soccer_spain_copa_del_rey",
        "ger.1":"soccer_germany_bundesliga","ger.2":"soccer_germany_bundesliga2",
        "ger.dfb_pokal":"soccer_germany_dfb_pokal",
        "ita.1":"soccer_italy_serie_a","ita.2":"soccer_italy_serie_b",
        "ita.coppa_italia":"soccer_italy_coppa_italia",
        "fra.1":"soccer_france_ligue_one","fra.2":"soccer_france_ligue_deux",
        "fra.coupe_de_france":"soccer_france_coupe_de_france",
        # EUROPA MEDIA
        "ned.1":"soccer_netherlands_eredivisie",
        "por.1":"soccer_portugal_primeira_liga",
        "tur.1":"soccer_turkey_super_league",
        "sco.1":"soccer_scotland_premiership",
        "bel.1":"soccer_belgium_first_div",
        "gre.1":"soccer_greece_super_league",
        "aut.1":"soccer_austria_bundesliga",
        "cze.1":"soccer_czech_republic_liga",
        "pol.1":"soccer_poland_ekstraklasa",
        "swe.1":"soccer_sweden_allsvenskan",
        "den.1":"soccer_denmark_superliga",
        "nor.1":"soccer_norway_eliteserien",
        "sui.1":"soccer_switzerland_superleague",
        # UEFA + CONCACAF
        "uefa.champions":"soccer_uefa_champs_league",
        "uefa.europa":"soccer_uefa_europa_league",
        "uefa.europa.conf":"soccer_uefa_europa_conference_league",
        "concacaf.champions":"soccer_concacaf_champions_cup",
        # AMÉRICAS
        "mex.1":"soccer_mexico_ligamx","mex.2":"soccer_mexico_ligamx",
        "usa.1":"soccer_usa_mls",
        "bra.1":"soccer_brazil_campeonato","bra.2":"soccer_brazil_serie_b",
        "arg.1":"soccer_argentina_primera_division",
        "col.1":"soccer_colombia_primera_a","chi.1":"soccer_chile_campeonato",
        "uru.1":"soccer_uruguay_primera_division",
        "ecu.1":"soccer_ecuador_liga_pro","per.1":"soccer_peru_primera_division",
        "conmebol.libertadores":"soccer_conmebol_copa_libertadores",
        "conmebol.sudamericana":"soccer_conmebol_copa_sudamericana",
        # ASIA
        "sau.1":"soccer_saudi_professional_league",
        "jpn.1":"soccer_japan_j_league","kor.1":"soccer_south_korea_kleague1",
    }
    sport = _slug_map.get(league_slug)
    if not sport:
        return {}
    try:
        url = f"https://api.the-odds-api.com/v4/sports/{sport}/odds"
        resp = requests.get(url, params={
            "apiKey": _key,
            "regions": "eu",
            "markets": "h2h,totals,btts",
            "oddsFormat": "decimal",
            "bookmakers": ",".join(BOOKMAKERS),
        }, timeout=10)
        if resp.status_code != 200:
            return {}
        _hn = home_name.lower()[:6]
        _an = away_name.lower()[:6]
        for game in resp.json():
            _gh = (game.get("home_team","") or "").lower()
            _ga = (game.get("away_team","") or "").lower()
            if _hn not in _gh and _an not in _ga:
                continue
            # Acumular cuotas por mercado entre todos los books
            _acc = {}  # mercado → lista de cuotas
            for bk in game.get("bookmakers", []):
                for mkt in bk.get("markets", []):
                    k = mkt["key"]
                    if k not in _acc: _acc[k] = {}
                    for out in mkt.get("outcomes", []):
                        nm = out["name"].lower()
                        pr = float(out.get("price", 0) or 0)
                        pt = out.get("point")
                        # key único por outcome
                        _okey = f"{nm}_{pt}" if pt is not None else nm
                        if _okey not in _acc[k]: _acc[k][_okey] = []
                        _acc[k][_okey].append(pr)
            # Promediar
            _avg = {}
            for mk, outs in _acc.items():
                _avg[mk] = {ok: round(sum(v)/len(v),3) for ok,v in outs.items() if v}
            # Construir resultado normalizado
            out = {}
            # 1X2
            if "h2h" in _avg:
                _h2 = _avg["h2h"]
                out["odd_h"] = _h2.get(_gh+"_None") or next((v for k,v in _h2.items() if _hn in k), 0)
                out["odd_d"] = _h2.get("draw_None", _h2.get("draw", 0))
                out["odd_a"] = _h2.get(_ga+"_None") or next((v for k,v in _h2.items() if _an in k), 0)
            # Totals — buscar líneas 1.5 / 2.5 / 3.5
            if "totals" in _avg:
                _tot = _avg["totals"]
                for _pt in ["1.5","2.5","3.5"]:
                    _o_key = f"over_{_pt}"; _u_key = f"under_{_pt}"
                    out[f"odd_o{_pt.replace('.','')}_api"] = _tot.get(_o_key, 0)
                    out[f"odd_u{_pt.replace('.','')}_api"] = _tot.get(_u_key, 0)
            # BTTS
            if "btts" in _avg:
                _bt = _avg["btts"]
                out["odd_btts_yes_api"] = _bt.get("yes_None", _bt.get("yes", 0))
                out["odd_btts_no_api"]  = _bt.get("no_None",  _bt.get("no",  0))
            return out
    except:
        pass
    return _league_odds_fallback(league_slug)

