import json as _json_mem, collections as _col

MEMORY_FILE   = "/tmp/gamblers_brain.json"

KR_CACHE_FILE = "/tmp/king_rongo_cache.json"

# ══════════════════════════════════════════════════════════
# NIGHT SCOUT — 4am CDMX daily form research via Claude AI
# Investiga los últimos 5 partidos de cada equipo en cartelera
# y guarda la información en caché para enriquecer los picks
# ══════════════════════════════════════════════════════════
NIGHT_FORM_FILE  = "/tmp/gamblers_night_form.json"
NIGHT_LOG_FILE   = "/tmp/gamblers_night_log.json"
NIGHT_SCOUT_HOUR = 4   # 4am CDMX
NIGHT_CACHE_TTL  = 20  # horas antes de re-investigar

import json as _jns

def _ns_load() -> dict:
    """Carga el caché de forma nocturna."""
    try:
        with open(NIGHT_FORM_FILE, "r") as f:
            return _jns.load(f)
    except:
        return {}

def _ns_save(data: dict):
    try:
        with open(NIGHT_FORM_FILE, "w") as f:
            _jns.dump(data, f, ensure_ascii=False, indent=2)
    except:
        pass

def _ns_log(msg: str):
    try:
        log = []
        try:
            with open(NIGHT_LOG_FILE, "r") as f:
                log = _jns.load(f)
        except:
            pass
        from datetime import datetime as _dt
        log.append({"ts": _dt.now(CDMX).isoformat(), "msg": msg})
        log = log[-200:]  # solo últimas 200 entradas
        with open(NIGHT_LOG_FILE, "w") as f:
            _jns.dump(log, f, ensure_ascii=False, indent=2)
    except:
        pass

def _ns_needs_run() -> bool:
    """
    Devuelve True si toca investigar:
    - Nunca se ha ejecutado, o
    - Última ejecución fue hace >20h, o
    - Son las 4am CDMX ± 30min y no se ejecutó hoy
    """
    try:
        data = _ns_load()
        last_run = data.get("_meta", {}).get("last_run_ts", 0)
        from datetime import datetime as _dt
        now = _dt.now(CDMX)
        elapsed_h = (now.timestamp() - last_run) / 3600
        if elapsed_h > NIGHT_CACHE_TTL:
            return True
        # También checar si son las 4am ± 30min y no se corrió en las últimas 2h
        if now.hour == NIGHT_SCOUT_HOUR and elapsed_h > 2:
            return True
        return False
    except:
        return True

def _ns_ask_claude(team_name: str, league: str, sport: str = "fútbol",
                   is_away_in_europe: bool = False, opponent: str = "") -> dict:
    """
    Llama a Claude con web_search para investigar forma reciente del equipo.
    Para UEFA: investiga también rendimiento como visitante en Europa.
    """
    if not ANTHROPIC_API_KEY:
        return {}
    if sport == "NBA":
        _unit = "partidos NBA"; _scored = "puntos anotados"; _conceded = "puntos recibidos"
        _extra = ""
    elif sport == "tenis":
        _unit = "partidos (sets ganados/perdidos)"; _scored = "sets ganados"; _conceded = "sets perdidos"
        _extra = ""
    else:
        _unit = "partidos"; _scored = "goles marcados"; _conceded = "goles recibidos"
        if is_away_in_europe:
            _extra = f"""
CONTEXTO ESPECIAL — VISITANTE EN EUROPA:
Este equipo jugará FUERA de su país en UEFA ({league}).
Investiga específicamente:
- Rendimiento como VISITANTE en Champions/Europa League últimas 2-3 temporadas
- W/D/L y goles en esos partidos europeos de visita
- ¿Cómo rinde este equipo lejos de casa en competición europea?
- Lesionados o ausencias clave para este partido vs {opponent}
- Desventaja de viaje, idioma, estadio hostil (si aplica)
Responde con "away_europe_record" y "away_europe_avg_goals" en el JSON."""
        else:
            _extra = f"""
CONTEXTO UEFA — LOCAL:
Este equipo juega en CASA en UEFA ({league}).
Investiga:
- Rendimiento como LOCAL en Champions/Europa League últimas 2-3 temporadas
- Ambiente de su estadio, aficionados (si es conocido por ser muy ruidoso)
- Lesionados o ausencias clave para este partido vs {opponent}
Responde con "home_europe_record" y "home_europe_avg_goals" en el JSON.""" if "uefa" in league.lower() or "champions" in league.lower() or "europa" in league.lower() else ""
    prompt = f"""Investiga los ÚLTIMOS 5 {_unit.upper()} de: {team_name} ({league}) — {sport}

Busca en internet los resultados más recientes de este equipo en 2025-2026.
Responde SOLO en JSON válido, sin texto adicional ni backticks markdown.
{_extra}

Formato exacto:
{{
  "team": "{team_name}",
  "league": "{league}",
  "last_5": [
    {{"date": "YYYY-MM-DD", "home": "Equipo Local", "away": "Equipo Visitante", "score": "X-Y", "result": "W/D/L", "competition": "Liga/Copa"}},
    ...
  ],
  "goals_scored_last5": <total de {_scored} en últimos 5>,
  "goals_conceded_last5": <total de {_conceded} en últimos 5>,
  "wins_last5": <0-5>,
  "form_string": "<ej: WWDLW — del más antiguo al más reciente>",
  "key_absences": "<lesionados/suspendidos importantes o 'ninguna'>",
  "momentum": "<alto/medio/bajo>",
  "avg_goals_scored": <promedio goles marcados por partido>,
  "avg_goals_conceded": <promedio goles recibidos por partido>,
  "away_europe_record": "<ej: 3W-1D-4L en últimas 8 visitas europeas, o 'sin datos'>",
  "away_europe_avg_goals": <promedio goles marcados en visitas europeas, o null>,
  "home_europe_record": "<ej: 5W-2D-1L en últimas 8 en casa europeas, o 'sin datos'>",
  "home_europe_avg_goals": <promedio goles marcados en casa europeas, o null>,
  "notes": "<dato clave: racha, cambio técnico, motivación, contexto eliminatoria, etc.>"
}}

Prioriza resultados de 2025-2026. Sé preciso con los marcadores."""

    try:
        result = _gemini_json(prompt, use_search=True, max_tokens=1200)
        return result if result else {}
    except:
        return {}

def _ns_extract_xg_from_form(form_data: dict, is_home: bool = True) -> tuple:
    """
    Convierte el resultado de _ns_ask_claude en (xg_scored, xg_conceded).
    Usa avg_goals como proxy de xG.
    Si hay datos europeos específicos (away_europe_avg_goals / home_europe_avg_goals),
    los blendea 50/50 con el promedio general para mayor precisión.
    """
    try:
        scored   = float(form_data.get("avg_goals_scored", 1.2))
        conceded = float(form_data.get("avg_goals_conceded", 1.1))
        momentum = form_data.get("momentum", "medio").lower()
        # Blendear con datos europeos si existen
        if is_home:
            _eu_scored = form_data.get("home_europe_avg_goals")
        else:
            _eu_scored = form_data.get("away_europe_avg_goals")
        if _eu_scored and str(_eu_scored).replace(".","").isdigit():
            try:
                _eu_f = float(_eu_scored)
                # 50% datos europeos + 50% liga doméstica
                scored = round(0.50 * _eu_f + 0.50 * scored, 3)
            except: pass
        _m_adj = {"alto": 1.08, "medio": 1.00, "bajo": 0.92}.get(momentum, 1.0)
        scored   = round(scored * _m_adj, 3)
        conceded = round(conceded / _m_adj, 3)
        return max(0.30, scored), max(0.25, conceded)
    except:
        return 1.2, 1.1

def _night_scout_run():
    """
    Worker del hilo nocturno. Investiga todos los equipos en cartelera
    y guarda resultados en NIGHT_FORM_FILE.
    Corre a las 4am CDMX diariamente.
    """
    import time as _time
    from datetime import datetime as _dt

    _ns_log("🌙 Night Scout iniciado")
    cache = _ns_load()
    cache["_meta"] = cache.get("_meta", {})
    cache["_meta"]["last_run_ts"] = _dt.now(CDMX).timestamp()
    cache["_meta"]["run_date"] = _dt.now(CDMX).strftime("%Y-%m-%d")
    _ns_save(cache)  # marcar inicio

    teams_done  = 0
    teams_fail  = 0

    try:
        # ── Recopilar equipos de todos los deportes ──
        all_teams = {}  # team_id → (team_name, league_slug)
        # Fútbol
        try:
            matches = get_cartelera()
            for m in matches:
                slug = m.get("slug","")
                if m.get("home_id"):
                    all_teams[str(m["home_id"])] = (m.get("home",""), slug)
                if m.get("away_id"):
                    all_teams[str(m["away_id"])] = (m.get("away",""), slug)
        except:
            pass
        # NBA
        try:
            nba_games = get_nba_cartelera()
            for g in nba_games:
                hid = str(g.get("home_id","") or g.get("hid","") or "")
                aid = str(g.get("away_id","") or g.get("aid","") or "")
                if hid: all_teams[hid] = (g.get("home",""), "nba")
                if aid: all_teams[aid] = (g.get("away",""), "nba")
        except:
            pass
        # Tenis
        try:
            ten_matches = get_tennis_cartelera()
            for t in ten_matches:
                p1 = t.get("p1","") or t.get("home","")
                p2 = t.get("p2","") or t.get("away","")
                i1 = str(t.get("home_id","") or t.get("p1_id","") or p1)
                i2 = str(t.get("away_id","") or t.get("p2_id","") or p2)
                tour = t.get("tournament","") or t.get("slug","tennis")
                if p1 and i1: all_teams[i1] = (p1, f"tennis:{tour}")
                if p2 and i2: all_teams[i2] = (p2, f"tennis:{tour}")
        except:
            pass

        # ── Slug → nombre legible para el prompt ──
        _SLUG_NAME = {
            "mex.1":"Liga MX", "mex.2":"Liga de Expansión MX",
            "esp.1":"La Liga", "eng.1":"Premier League",
            "ger.1":"Bundesliga", "ita.1":"Serie A", "fra.1":"Ligue 1",
            "usa.1":"MLS", "bra.1":"Brasileirao", "arg.1":"Liga Argentina",
            "col.1":"Liga BetPlay", "chi.1":"Primera División Chile",
            "por.1":"Primeira Liga", "ned.1":"Eredivisie",
            "tur.1":"Süper Lig", "sco.1":"Scottish Premiership",
            "sau.1":"Saudi Pro League", "bel.1":"Pro League Bélgica",
            "den.1":"Superliga Dinamarca", "nor.1":"Eliteserien",
            "gre.1":"Super League Grecia",
            "uefa.champions":"UEFA Champions League",
            "uefa.europa":"UEFA Europa League",
            "uefa.europa.conf":"UEFA Conference League",
            "concacaf.champions":"CONCACAF Champions Cup",
            "nba":"NBA",
        }

        total = len(all_teams)
        _ns_log(f"🔍 Investigando {total} equipos...")

        for i, (tid, (tname, slug)) in enumerate(all_teams.items()):
            if not tname:
                continue
            if slug.startswith("tennis:"):
                league_name = slug.replace("tennis:","").strip() or "ATP/WTA"
            else:
                league_name = _SLUG_NAME.get(slug, slug)
            _ns_log(f"[{i+1}/{total}] {tname} ({league_name})")

            try:
                # Adaptar prompt por deporte
                _ns_sport = "tenis" if slug.startswith("tennis:") else ("NBA" if slug == "nba" else "fútbol")
                # Para UEFA: marcar si es visitante europeo
                _is_away_eur = False
                _opp_name = ""
                if _ns_sport == "fútbol" and slug in {"uefa.champions","uefa.europa","uefa.europa.conf","concacaf.champions"}:
                    # Buscar rival en el partido
                    for _mm in (matches if "matches" in dir() else []):
                        _hid_m = str(_mm.get("home_id",""))
                        _aid_m = str(_mm.get("away_id",""))
                        if tid == _aid_m:
                            _is_away_eur = True
                            _opp_name = _mm.get("home","")
                            break
                        elif tid == _hid_m:
                            _opp_name = _mm.get("away","")
                            break
                form = _ns_ask_claude(tname, league_name, sport=_ns_sport,
                                      is_away_in_europe=_is_away_eur, opponent=_opp_name)
                if form and form.get("last_5"):
                    xg_s, xg_c = _ns_extract_xg_from_form(form, is_home=not _is_away_eur)
                    cache[tid] = {
                        "team":                 tname,
                        "slug":                 slug,
                        "form":                 form,
                        "xg_scored":            xg_s,
                        "xg_conceded":          xg_c,
                        "fetched_at":           _dt.now(CDMX).isoformat(),
                        "form_string":          form.get("form_string","?????"),
                        "momentum":             form.get("momentum","medio"),
                        "key_absences":         form.get("key_absences",""),
                        "notes":                form.get("notes",""),
                        "wins_last5":           form.get("wins_last5",2),
                        "goals_scored":         form.get("goals_scored_last5",6),
                        "goals_conceded":       form.get("goals_conceded_last5",5),
                        "away_europe_record":   form.get("away_europe_record",""),
                        "away_europe_avg_goals":form.get("away_europe_avg_goals"),
                        "home_europe_record":   form.get("home_europe_record",""),
                        "home_europe_avg_goals":form.get("home_europe_avg_goals"),
                        "is_away_europe":       _is_away_eur,
                        "opponent":             _opp_name,
                    }
                    teams_done += 1
                else:
                    teams_fail += 1
            except:
                teams_fail += 1

            _ns_save(cache)
            # Pausa entre llamadas para no saturar la API
            _time.sleep(2.5)

        cache["_meta"]["teams_done"]   = teams_done
        cache["_meta"]["teams_fail"]   = teams_fail
        cache["_meta"]["finished_at"]  = _dt.now(CDMX).isoformat()
        _ns_save(cache)
        _ns_log(f"✅ Night Scout completo: {teams_done} OK, {teams_fail} fallidos")

    except Exception as _e:
        _ns_log(f"❌ Night Scout error: {_e}")
        cache["_meta"]["error"] = str(_e)
        _ns_save(cache)

def _ns_get_team_xg(team_id: str, is_home: bool) -> tuple:
    """
    Devuelve (xg_att, xg_def) del caché nocturno para un equipo.
    xg_att = promedio de goles marcados
    xg_def = promedio de goles concedidos
    Retorna (None, None) si no hay datos.
    """
    try:
        cache = _ns_load()
        entry = cache.get(str(team_id))
        if not entry:
            return None, None
        return float(entry.get("xg_scored", 1.2)), float(entry.get("xg_conceded", 1.1))
    except:
        return None, None

def _ns_get_team_info(team_id: str) -> dict:
    """Devuelve el dict completo de forma para un equipo del caché nocturno."""
    try:
        cache = _ns_load()
        return cache.get(str(team_id), {})
    except:
        return {}

def _ns_start_if_needed():
    """
    Lanza _night_scout_run() en hilo daemon si toca ejecutar.
    Llamado desde el bootstrap de Streamlit.
    """
    if not _ns_needs_run():
        return
    import threading as _tns
    _tns.Thread(target=_night_scout_run, daemon=True, name="NightScout").start()
    _ns_log("🚀 Night Scout lanzado en background")


def _load_brain():
    try:
        with open(MEMORY_FILE,"r") as f: return _json_mem.load(f)
    except: return {"picks":[],"stats":{},"patterns":{},"version":2}

def _save_brain(b):
    try:
        with open(MEMORY_FILE,"w") as f: _json_mem.dump(b,f,ensure_ascii=False,indent=2)
    except: pass

def init_califica_memory():
    if "brain" not in st.session_state:
        st.session_state["brain"] = _load_brain()

def _update_patterns(brain):
    picks=[p for p in brain["picks"] if p.get("resultado") in ["✅","❌"]]
    if len(picks)<2: brain["patterns"]={}; return
    mkt_s=_col.defaultdict(lambda:{"w":0,"l":0})
    spt_s=_col.defaultdict(lambda:{"w":0,"l":0})
    cq_s={"bajo":{"w":0,"l":0},"medio":{"w":0,"l":0},"alto":{"w":0,"l":0},"muy_alto":{"w":0,"l":0}}
    ed_s={"neg":{"w":0,"l":0},"0_5":{"w":0,"l":0},"5_10":{"w":0,"l":0},"mas10":{"w":0,"l":0}}
    for p in picks:
        k="w" if p.get("correcto") else "l"
        mkt_s[str(p.get("mercado","?")).split()[0].lower()[:12]][k]+=1
        spt_s[str(p.get("deporte","?"))][k]+=1
        c=float(p.get("cuota",0))
        cq_s["bajo" if c<1.5 else ("medio" if c<2.2 else ("alto" if c<3.5 else "muy_alto"))][k]+=1
        e=float(p.get("edge_pct",0))
        ed_s["neg" if e<0 else ("0_5" if e<5 else ("5_10" if e<10 else "mas10"))][k]+=1
    def pct(d): return round(d["w"]/(d["w"]+d["l"])*100,1) if (d["w"]+d["l"])>0 else None
    brain["patterns"]={
        "mercados":{k:{"pct":pct(v),"n":v["w"]+v["l"]} for k,v in mkt_s.items() if v["w"]+v["l"]>=2},
        "deportes":{k:{"pct":pct(v),"n":v["w"]+v["l"]} for k,v in spt_s.items() if v["w"]+v["l"]>=2},
        "cuotas":{k:{"pct":pct(v),"n":v["w"]+v["l"]} for k,v in cq_s.items()},
        "edges":{k:{"pct":pct(v),"n":v["w"]+v["l"]} for k,v in ed_s.items()},
    }
    tot=len(picks); w=sum(1 for p in picks if p.get("correcto"))
    brain["stats"]={"total":tot,"wins":w,"losses":tot-w,
        "roi":round(sum((float(p.get("cuota",1))-1) if p.get("correcto") else -1 for p in picks)/tot*100,1) if tot>0 else 0}

def add_califica_result(mercado,cuota,resultado,correcto,deporte="",equipos="",edge_pct=0,prob_real=0,prob_implicita=0,puntuacion=0):
    init_califica_memory()
    brain=st.session_state["brain"]
    brain["picks"].append({"fecha":datetime.now(CDMX).strftime("%Y-%m-%d %H:%M"),
        "deporte":deporte,"equipos":equipos,"mercado":mercado,"cuota":float(cuota) if cuota else 0,
        "resultado":resultado,"correcto":correcto,"edge_pct":float(edge_pct),
        "prob_real":float(prob_real),"prob_implicita":float(prob_implicita),"puntuacion":int(puntuacion)})
    brain["picks"]=brain["picks"][-500:]
    _update_patterns(brain); _save_brain(brain); st.session_state["brain"]=brain

def get_memory_context():
    init_califica_memory()
    brain=st.session_state["brain"]
    stats=brain.get("stats",{}); patterns=brain.get("patterns",{})
    n=stats.get("total",0)
    if n==0: return ""
    w=stats.get("wins",0); roi=stats.get("roi",0)
    ctx=f"CEREBRO ESTADÍSTICO ({n} picks registrados, {w} correctos, ROI={roi:+.1f}%). "
    mkts=patterns.get("mercados",{})
    best=sorted([(k,v) for k,v in mkts.items() if v["n"]>=2 and v["pct"] is not None],key=lambda x:-x[1]["pct"])[:3]
    worst=sorted([(k,v) for k,v in mkts.items() if v["n"]>=2 and v["pct"] is not None],key=lambda x:x[1]["pct"])[:3]
    if best: ctx+=f"Mercados CON MÁS ACIERTO: {', '.join([f'{k}({v['pct']}%,n={v['n']})' for k,v in best])}. "
    if worst: ctx+=f"Mercados CON MÁS FALLOS: {', '.join([f'{k}({v['pct']}%,n={v['n']})' for k,v in worst])}. "
    edges=patterns.get("edges",{})
    for rng,label in [("mas10","edge>10%"),("5_10","edge 5-10%"),("0_5","edge 0-5%"),("neg","edge negativo")]:
        if edges.get(rng,{}).get("n",0)>=2:
            ctx+=f"{label}: {edges[rng]['pct']}% acierto en {edges[rng]['n']} picks. "
    sports=patterns.get("deportes",{})
    for s,v in sports.items():
        if v.get("n",0)>=2: ctx+=f"{s}: {v['pct']}% acierto ({v['n']} picks). "
    return ctx


# ══════════════════════════════════════════════════════════
# RESULTADOS DB — Base de datos interna de partidos
# Se actualiza cada 2 horas automáticamente
# ══════════════════════════════════════════════════════════
RESULTS_FILE   = "/tmp/gamblers_results.json"
LAST_UPDATE_F  = "/tmp/gamblers_last_update.txt"
PICKS_SNAP_F   = "/tmp/gamblers_picks_snap.json"  # snapshot de picks automáticos

def _load_results_db():
    try:
        with open(RESULTS_FILE,"r") as f:
            db = _json_mem.load(f)
    except:
        return {"partidos":[],"ultima_actualizacion":"","version":1}
    # Limpiar partidos con nombres vacíos — copiar p1/p2 a home/away si faltan
    for p in db.get("partidos", []):
        if not p.get("home") or p.get("home") == "?":
            p["home"] = p.get("p1","?")
        if not p.get("away") or p.get("away") == "?":
            p["away"] = p.get("p2","?")
        if not p.get("p1") or p.get("p1") == "?":
            p["p1"] = p.get("home","?")
        if not p.get("p2") or p.get("p2") == "?":
            p["p2"] = p.get("away","?")
    return db

def _save_results_db(db):
    try:
        with open(RESULTS_FILE,"w") as f: _json_mem.dump(db,f,ensure_ascii=False,indent=2)
    except: pass

def _load_picks_snap():
    """Carga snapshot de picks. Usa session_state como backup de /tmp."""
    file_snap = {}
    try:
        with open(PICKS_SNAP_F,"r") as f: file_snap = json.load(f)
    except: pass
    try:
        ss_snap = st.session_state.get("_picks_snap_mem", {})
    except: ss_snap = {}
    return {**file_snap, **ss_snap}

def _save_picks_snap(snap):
    """Guarda en /tmp Y session_state para sobrevivir reboots de /tmp."""
    try:
        with open(PICKS_SNAP_F,"w") as f: json.dump(snap, f, ensure_ascii=False, indent=2)
    except: pass
    try:
        st.session_state["_picks_snap_mem"] = snap
    except: pass


def _snap_auto_pick(partido_id, pick_data, state="pre", force=False):
    """Guarda pick automático en snapshot.
    force=True: sobreescribe siempre (usado por la cartelera con datos completos).
    force=False: no sobreescribe partidos ya terminados (comportamiento por defecto)."""
    if not partido_id or not pick_data: return
    snap = _load_picks_snap()
    # Proteger picks ya congelados (partido en juego o terminado) — excepto force
    if not force and partido_id in snap:
        existing = snap[partido_id]
        # Solo proteger si el partido ya empezó o está congelado explícitamente
        if existing.get("frozen") or state in ("in", "post"):
            return
    # Con force=True Y state=="pre": siempre actualizar (pick más reciente de cartelera)
    # Con force=True Y state=="in/post": solo si no hay pick pre-partido guardado ya
    if force and state in ("in","post") and partido_id in snap:
        existing = snap[partido_id]
        if existing.get("pick") and not existing.get("frozen"):
            # Ya hay pick pre-partido — congelarlo y no sobreescribir
            snap[partido_id]["frozen"] = True
            _save_picks_snap(snap)
            return
    snap[partido_id] = {
        "pick":       pick_data.get("pick",""),
        "prob":       pick_data.get("prob",0),
        "mkt":        pick_data.get("mkt","") or pick_data.get("src","🤖 Modelo"),
        "odd":        pick_data.get("odd",0),
        "src":        pick_data.get("src","🤖 Modelo"),
        "all_picks":  pick_data.get("all_picks", []),
        "home":       pick_data.get("home",""),
        "away":       pick_data.get("away",""),
        "sport":      pick_data.get("sport","futbol"),
        "fecha":      pick_data.get("fecha",""),
        "fecha_gen":  datetime.now(CDMX).strftime("%Y-%m-%d %H:%M"),
        "frozen":     state in ("in","post"),
        # 2° pick (O/U para NBA/tenis, 2° mercado UEFA para fútbol)
        "pick2":      pick_data.get("pick2",""),
        "pick2_prob": pick_data.get("pick2_prob",0),
        "pick2_mkt":  pick_data.get("pick2_mkt",""),
    }
    _save_picks_snap(snap)

def _needs_update():
    """Returns True if last update was >15 minutes ago or never."""
    try:
        with open(LAST_UPDATE_F,"r") as f: last = f.read().strip()
        last_dt = datetime.fromisoformat(last).replace(tzinfo=pytz.UTC)
        return (datetime.now(pytz.UTC) - last_dt).total_seconds() > 900
    except: return True

def _mark_updated():
    try:
        with open(LAST_UPDATE_F,"w") as f: f.write(datetime.now(pytz.UTC).isoformat())
    except: pass

def _needs_daily_reset():
    """Returns True if it's past 2am CDMX and we haven't reset today."""
    now = datetime.now(CDMX)
    reset_key = f"/tmp/gamblers_reset_{now.strftime('%Y%m%d')}.txt"
    if now.hour >= 2 and not os.path.exists(reset_key):
        try:
            open(reset_key,"w").close()
            return True
        except: return False
    return False

def fetch_soccer_results(days_back=4):
    """
    Fetch resultados de fútbol día a día desde ESPN (últimos N días + hoy).
    Consulta cada slug de LIGAS para cada fecha — igual que NBA.
    IMPORTANTE: no usa get_cartelera() que solo retorna partidos futuros.
    """
    now     = datetime.now(CDMX)
    cutoff  = (now - timedelta(days=days_back)).strftime("%Y-%m-%d")
    hoy     = now.strftime("%Y-%m-%d")
    partidos = []
    seen_ids = set()
    # Slugs prioritarios para resultados (los más activos)
    _result_slugs = [
        # Top 5
        "esp.1","eng.1","ger.1","ita.1","fra.1",
        "esp.2","eng.2","ger.2","ita.2","fra.2",
        "eng.fa","esp.copa_del_rey","ger.dfb_pokal","ita.coppa_italia",
        # Américas
        "mex.1","mex.2","usa.1","bra.1","bra.2",
        "arg.1","col.1","chi.1","uru.1","ecu.1","per.1",
        "conmebol.libertadores","conmebol.sudamericana",
        # Europa media
        "por.1","ned.1","tur.1","sco.1","bel.1","gre.1",
        "aut.1","cze.1","pol.1","swe.1","den.1","nor.1",
        # UEFA + CONCACAF
        "uefa.champions","uefa.europa","uefa.europa.conf","concacaf.champions",
        # Asia
        "sau.1","jpn.1","kor.1",
    ]
    # Parallel fetch — todos los slugs × fechas en paralelo
    import concurrent.futures as _cf_res2
    _res_task_list = []
    for _day_off_r in range(days_back, -1, -1):
        _dr  = now - timedelta(days=_day_off_r)
        _dsr = _dr.strftime("%Y%m%d")
        _fdr = _dr.strftime("%Y-%m-%d")
        if _fdr < cutoff: continue
        for slug in _result_slugs:
            _res_task_list.append((slug, _dsr, _fdr))

    def _res_fetch_one(tsk):
        _slg, _dsr2, _fdr2 = tsk
        return _slg, _fdr2, eg(f"{ESPN}/{_slg}/scoreboard", {"dates": _dsr2, "limit": 100})

    _all_res_data = []
    try:
        with _cf_res2.ThreadPoolExecutor(max_workers=20) as _rex2:
            _rfmap2 = {_rex2.submit(_res_fetch_one, t): t for t in _res_task_list}
            for _rfk2 in _cf_res2.as_completed(_rfmap2, timeout=30):
                try: _all_res_data.append(_rfk2.result())
                except: pass
    except: pass

    for slug, fd, data in _all_res_data:
        for ev in data.get("events", []):
            try:
                eid = ev.get("id","")
                if eid in seen_ids: continue
                comp  = ev["competitions"][0]
                state = ev.get("status",{}).get("type",{}).get("state","")
                if state != "post": continue  # solo finalizados
                comps = comp["competitors"]
                hc = next(c for c in comps if c["homeAway"]=="home")
                ac = next(c for c in comps if c["homeAway"]=="away")
                utc_str = ev.get("date","")
                try:
                    utc_dt = datetime.strptime(utc_str[:19],"%Y-%m-%dT%H:%M:%S").replace(tzinfo=pytz.UTC)
                    fecha  = utc_dt.astimezone(CDMX).strftime("%Y-%m-%d")
                    hora   = utc_dt.astimezone(CDMX).strftime("%H:%M")
                except:
                    fecha = fd; hora = "00:00"
                if fecha < cutoff: continue
                sh = parse_score(hc.get("score",0))
                sa = parse_score(ac.get("score",0))
                seen_ids.add(eid)
                partidos.append({
                    "id":       eid,
                    "deporte":  "futbol",
                    "liga":     LIGAS.get(slug, slug),
                    "slug":     slug,
                    "home":     hc["team"]["displayName"],
                    "away":     ac["team"]["displayName"],
                    "home_id":  str(hc["team"]["id"]),
                    "away_id":  str(ac["team"]["id"]),
                    "home_rec": "0-0-0",
                    "away_rec": "0-0-0",
                    "odd_h":    0, "odd_d": 0, "odd_a": 0,
                    "score_h":  sh,
                    "score_a":  sa,
                    "fecha":    fecha,
                    "state":    "post",
                    "hora":     hora,
                })
            except: continue
    return partidos



@st.cache_data(ttl=900)  # 15min — results don't change every second
def fetch_nba_results(days_back=10):
    """Fetch last N days of NBA results."""
    partidos = []
    now = datetime.now(CDMX)
    for day_offset in range(days_back, -1, -1):
        d = now - timedelta(days=day_offset)
        ds = d.strftime("%Y%m%d")
        try:
            data = eg(f"{NBA_ESPN}/scoreboard", {"dates": ds, "limit": 30})
            for ev in data.get("events",[]):
                try:
                    comp  = ev["competitions"][0]
                    state = ev.get("status",{}).get("type",{}).get("state","")
                    comps = comp["competitors"]
                    hc = next(c for c in comps if c["homeAway"]=="home")
                    ac = next(c for c in comps if c["homeAway"]=="away")
                    utc   = datetime.strptime(ev["date"],"%Y-%m-%dT%H:%MZ").replace(tzinfo=pytz.UTC)
                    fecha = utc.astimezone(CDMX).strftime("%Y-%m-%d")
                    ou_line = 0.0
                    try:
                        odds = comp.get("odds",[])
                        if odds: ou_line = float(odds[0].get("overUnder",0) or 0)
                    except: pass
                    hora_nba = utc.astimezone(CDMX).strftime("%H:%M")
                    partidos.append({
                        "id":ev.get("id",""), "deporte":"nba",
                        "liga":"NBA 🏀", "slug":"nba", "_sport":"nba",
                        "home":hc["team"]["displayName"],
                        "away":ac["team"]["displayName"],
                        "home_id":str(hc["team"]["id"]),
                        "away_id":str(ac["team"]["id"]),
                        "score_h":parse_score(hc.get("score",0)) if state=="post" else -1,
                        "score_a":parse_score(ac.get("score",0)) if state=="post" else -1,
                        "ou_line":ou_line,
                        "hora":hora_nba, "fecha":fecha, "state":state,
                    })
                except: continue
        except: continue
    return partidos

@st.cache_data(ttl=900)  # 15min cache
def fetch_tennis_results(days_back=14):
    """
    Trae partidos de tenis finalizados (state=post) de los últimos N días.
    Usa dos fuentes: TENNIS_API histórico + get_tennis_cartelera state=post del día.
    """
    now   = datetime.now(CDMX)
    hoy   = now.strftime("%Y-%m-%d")
    desde = (now - timedelta(days=days_back)).strftime("%Y-%m-%d")
    results = []
    seen_ids = set()

    # ── FUENTE 1: Tennis API histórico ──
    try:
        r = requests.get(TENNIS_API, params={
            "method":  "get_fixtures",
            "APIkey":  TENNIS_API_KEY,
            "date_start": desde,
            "date_stop":  hoy,
        }, headers=H, timeout=12)
        data = r.json() if r.status_code == 200 else {}
        for ev in data.get("result", []):
            try:
                fecha = ev.get("event_date","")
                hora  = ev.get("event_time","00:00")
                try:
                    utc_t = datetime.strptime(f"{fecha} {hora}", "%Y-%m-%d %H:%M").replace(tzinfo=pytz.UTC)
                    hora  = utc_t.astimezone(CDMX).strftime("%H:%M")
                    fecha = utc_t.astimezone(CDMX).strftime("%Y-%m-%d")
                except: pass
                if fecha < desde or fecha > hoy: continue
                tour_type = ev.get("event_type_type","").upper()
                if not any(x in tour_type for x in ["ATP","WTA","GRAND SLAM","MASTERS"]):
                    continue
                tour = "WTA" if "WTA" in tour_type else "ATP"
                ev_status   = str(ev.get("event_status","")).lower()
                ev_finished = str(ev.get("event_final","0"))
                is_post = (ev_finished == "1" or
                           any(x in ev_status for x in ["finished","ft","final","completed","awarded",
                                                         "retired","ret.","walkover","w/o","withdraw"]))
                if not is_post: continue
                p1 = ev.get("event_first_player","?")
                p2 = ev.get("event_second_player","?")
                if str(p2).lower().strip() in ("unknown","tbd","tba","","?","bye","n/a"): continue
                sc1_raw = str(ev.get("event_first_player_result","0"))
                sc2_raw = str(ev.get("event_second_player_result","0"))
                try:  sc1 = max(0, int(sc1_raw))
                except: sc1 = 0
                try:  sc2 = max(0, int(sc2_raw))
                except: sc2 = 0
                # ID idéntico al que usa get_tennis_cartelera → snap coincide con resultado
                eid = str(ev.get("event_key",""))
                eid_alt = f"ten_{eid}"  # alias legacy
                if eid in seen_ids or eid_alt in seen_ids: continue
                seen_ids.add(eid); seen_ids.add(eid_alt)
                results.append({
                    "id": eid, "deporte":"tenis",
                    "home":p1, "away":p2, "p1":p1, "p2":p2,
                    "liga":f"{tour} · {ev.get('tournament_name','')}",
                    "tour":tour, "torneo":ev.get("tournament_name",""),
                    "fecha":fecha, "hora":hora, "state":"post",
                    "score_h":sc1, "score_a":sc2,
                })
            except: continue
    except: pass

    # ── FUENTE 2: Cartelera tenis de hoy — partidos state=post ──
    try:
        cartelera_ten = get_tennis_cartelera()
        for m in cartelera_ten:
            if m.get("state") != "post": continue
            # Usar mismo ID que cartelera para que snap coincida
            _raw_tid = str(m.get("id",""))
            eid = _raw_tid  # igual que cartelera
            eid_alt = f"ten_live_{_raw_tid}"
            if eid in seen_ids or eid_alt in seen_ids: continue
            seen_ids.add(eid); seen_ids.add(eid_alt)
            sc1 = m.get("score_p1", m.get("score_h", 0))
            sc2 = m.get("score_p2", m.get("score_a", 0))
            try: sc1 = max(0, int(str(sc1)))
            except: sc1 = 0
            try: sc2 = max(0, int(str(sc2)))
            except: sc2 = 0
            results.append({
                "id": eid, "deporte":"tenis",
                "home":m["p1"], "away":m["p2"], "p1":m["p1"], "p2":m["p2"],
                "liga":f"{m.get('tour','ATP')} · {m.get('torneo','')}",
                "tour":m.get("tour","ATP"), "torneo":m.get("torneo",""),
                "fecha":m.get("fecha",hoy), "hora":m.get("hora",""),
                "state":"post", "score_h":sc1, "score_a":sc2,
            })
    except: pass

    # ── FUENTE 3: Claude web_search — ATP + WTA — PRIORIDAD MÁXIMA ──
    # Web search va PRIMERO. Los seeds son solo fallback para lo que la web no encontró.
    _web_pairs = set()  # jugadores ya cubiertos por web search (para no sobreescribir con seeds)
    if ANTHROPIC_API_KEY:
        web_results = _fetch_tennis_results_web(desde, hoy)
        for wr in web_results:
            eid = f"ten_web_{wr['p1'][:6]}_{wr['p2'][:6]}_{wr['fecha']}"
            if eid in seen_ids: continue
            _wr_p1 = wr.get("p1","").lower().strip()
            _wr_p2 = wr.get("p2","").lower().strip()
            _wr_f  = wr.get("fecha","")
            # Dedup contra fuentes 1 y 2 (API histórico + cartelera live)
            _duplicate = False
            for _ex in results:
                _ex_p1 = _ex.get("p1","").lower().strip()
                _ex_p2 = _ex.get("p2","").lower().strip()
                _ex_f  = _ex.get("fecha","")
                if _ex_f == _wr_f and {_ex_p1,_ex_p2} == {_wr_p1,_wr_p2}:
                    _duplicate = True
                    break
            if _duplicate: continue
            seen_ids.add(eid)
            wr["id"] = eid
            results.append(wr)
            # Registrar que este par ya está cubierto por web
            _web_pairs.add(frozenset([_wr_p1, _wr_p2, _wr_f]))

    # ── FUENTE 4 SEMILLA: Fallback hardcodeado — solo si web search no encontró el partido ──
    # A medida que avanza el torneo estos seeds se vuelven obsoletos automáticamente
    # porque la web search los cubre. Solo sirven si la web falla completamente.
