        _dup = any(
            r.get("fecha","") == _sf and {r.get("p1","").lower(), r.get("p2","").lower()} == {_sp1, _sp2}
            for r in results
        )
        if _dup: continue
        seen_ids.add(_sid)
        # Si score es 0-0 y la fecha es HOY → estado pre/in (aún no empezó o en curso)
        _seed_state = "post" if (_s["sh"] > 0 or _s["sa"] > 0) else (
            "pre" if _s["f"] >= hoy else "post"
        )
