def _soccer_pick_selector(markets, ph, pa, odd_h=0, odd_a=0, odd_d=0):
    """
    FUNCIÓN CENTRAL de selección de picks para fútbol.
    Usada por cartelera, KR y Telegram — misma lógica en todos lados.

    Regla única:
      • Si ML favorito ≥ 57%  → Pick 1 = ML favorito
      • Si ML favorito < 57%  → Pick 1 = DO favorito
      • Pick 2 = mejor mercado alternativo (OU, AA, GCM, TG) con prob ≥ 55%
                 que NO sea el mismo tipo que Pick 1

    markets: lista de (label, prob, odd, grupo)
      grupos: "1X2", "DO", "OU", "AA", "GCM", "TG"
    ph, pa: probabilidad home/away del modelo
    """
    _ML_THRESHOLD = 0.57   # ML solo si favorito tiene ≥57%

    # Favorito ML (home o away, excluir empate)
    _ml_opts = [(l,p,o,mk) for l,p,o,mk in markets if mk == "1X2" and "Empate" not in l and "Draw" not in l]
    _fav_ml  = max(_ml_opts, key=lambda x: x[1]) if _ml_opts else None
    _fav_p   = _fav_ml[1] if _fav_ml else 0
    _fav_lbl = _fav_ml[0] if _fav_ml else ""
    _fav_is_home = (ph >= pa)

    # DO del favorito (mismo equipo que el favorito ML)
    _do_tag = "🔵 DO" if _fav_is_home else "🟣 DO"
    _do_fav = next(((l,p,o,mk) for l,p,o,mk in markets
                    if mk == "DO" and _do_tag in l), None)

    # ── PICK 1: regla ML vs DO ──
    if _fav_p >= _ML_THRESHOLD:
        pick1 = _fav_ml   # ML porque el favorito es suficientemente claro
    elif _do_fav and _do_fav[1] >= 0.55:
        pick1 = _do_fav   # DO porque el partido está más equilibrado
    elif _fav_ml:
        pick1 = _fav_ml   # fallback ML aunque esté bajo el threshold
    else:
        pick1 = max(markets, key=lambda x: x[1]) if markets else None

    # ── PICK 2: mejor mercado alternativo (distinto tipo al Pick 1) ──
    _p1_grupo = pick1[3] if pick1 else ""
    # Candidatos alternativos: no del mismo grupo que pick1, prob ≥ 55%
    # Prioridad: OU > AA > GCM > TG > 1X2 > DO
    _alt_priority = ["OU", "AA", "GCM", "TG", "1X2", "DO"]
    _alt_pool = [(l,p,o,mk) for l,p,o,mk in markets
                 if mk != _p1_grupo and p >= 0.55
                 and not ("Over 1.5" in l and p < 0.80)]  # O1.5 solo si ≥80%
    pick2 = None
    for grp in _alt_priority:
        if grp == _p1_grupo: continue
        _cands = [(l,p,o,mk) for l,p,o,mk in _alt_pool if mk == grp]
        if _cands:
            pick2 = max(_cands, key=lambda x: x[1])
            break

    return pick1, pick2


def _best_market_soccer(m, dp, mc):
    """
    Evalúa todos los mercados con cuotas REALES de Odds API (fallback fijas -22%).
    Selecciona el de MAYOR EV con prob ≥52% y EV > 0.
    """
    _fo  = get_full_odds(m.get("home",""), m.get("away",""), m.get("slug",""))
    _d3  = 0.78
    def _ro(k, fb): v=float(_fo.get(k,0) or 0); return v if v>1.01 else fb
    _o_o25  = _ro("odd_o25_api",  1.85*_d3)
    _o_u25  = _ro("odd_u25_api",  2.00*_d3)
    _o_o35  = _ro("odd_o35_api",  2.50*_d3)
    _o_u35  = _ro("odd_u35_api",  1.50*_d3)
    _o_aa   = _ro("odd_btts_yes_api", 1.75*_d3)
    opts = []
    # 1X2
    if m.get("odd_h",0)>1: opts.append(("🏠 "+m["home"][:15]+" gana",    dp["ph"], m["odd_h"], dp["ph"]-(1/m["odd_h"]), "ML"))
    if m.get("odd_d",0)>1: opts.append(("🤝 Empate",                      dp["pd"], m["odd_d"], dp["pd"]-(1/m["odd_d"]), "X"))
    if m.get("odd_a",0)>1: opts.append(("✈️ "+m["away"][:15]+" gana",      dp["pa"], m["odd_a"], dp["pa"]-(1/m["odd_a"]), "ML"))
    # DO (cuotas fijas — raramente en API)
    opts.append((f"🔵 DO {m['home'][:13]} o Emp", min(0.95,dp["ph"]+dp["pd"]), 1.30*_d3, min(0.95,dp["ph"]+dp["pd"])-(1/(1.30*_d3)), "DO"))
    opts.append((f"🟣 DO {m['away'][:13]} o Emp", min(0.95,dp["pa"]+dp["pd"]), 1.50*_d3, min(0.95,dp["pa"]+dp["pd"])-(1/(1.50*_d3)), "DO"))
    # Totals + BTTS con cuotas reales
    opts.append(("⚽ Over 2.5",          mc["o25"],       _o_o25, mc["o25"]-(1/_o_o25),        "O25"))
    opts.append(("⚽⚽ Over 3.5",        mc["o35"],       _o_o35, mc["o35"]-(1/_o_o35),        "O35"))
    opts.append(("🔒 Under 2.5",         1-mc["o25"],     _o_u25, (1-mc["o25"])-(1/_o_u25),   "U25"))
    opts.append(("🔒 Under 3.5",         1-mc["o35"],     _o_u35, (1-mc["o35"])-(1/_o_u35),   "U35"))
    opts.append(("⚡ Ambos Anotan (AA)", mc["btts"],      _o_aa,  mc["btts"]-(1/_o_aa),        "AA"))
    # GCM si disponible
    if mc.get("gcm_h",0)>0.10: opts.append((f"🌓 {m['home'][:13]} gana c/mitad", mc["gcm_h"], 1.55*_d3, mc["gcm_h"]-(1/(1.55*_d3)), "GCM"))
    if mc.get("gcm_a",0)>0.10: opts.append((f"🌓 {m['away'][:13]} gana c/mitad", mc["gcm_a"], 1.65*_d3, mc["gcm_a"]-(1/(1.65*_d3)), "GCM"))
    # Filtrar: EV+ y prob ≥52%
    valid = [o for o in opts if o[3] > 0.0 and o[1] >= 0.52]
    valid.sort(key=lambda x: -x[3])
    return valid[0] if valid else None

def escanear_y_enviar(matches):
    """Escanea todos los partidos y manda picks a Telegram.
    El pick de cada partido es el mercado de MAYOR probabilidad con edge positivo."""
    picks = []
    for m in matches:
        if m["state"] != "pre": continue
        _msl = m.get("slug","")
        if _msl in _UEFA_CUP_SLUGS:
            hf = get_form_domestic(str(m.get("home_id","")), _msl)
            af = get_form_domestic(str(m.get("away_id","")), _msl)
            for _ug, _ulist in [(get_form(m["home_id"], _msl), hf), (get_form(m["away_id"], _msl), af)]:
                _ud = {g["date"] for g in _ulist}
                for g in _ug:
                    if g["date"] not in _ud: _ulist.append(g)
                _ulist.sort(key=lambda x: x["date"], reverse=True)
            hf = hf[:15]; af = af[:15]
        else:
            hf  = get_form(m["home_id"], m["slug"])
            af  = get_form(m["away_id"], m["slug"])
        hxg = _cup_enriched_xg(m, True,  hf, af)
        axg = _cup_enriched_xg(m, False, hf, af)
        # ── Tabla+GD ajusta xG antes del ensemble (bot Telegram) ──
        try:
            _tbl_bot = _tabla_posicion_delta(m["home"], m["away"], m.get("slug",""))
            if _tbl_bot.get("pos_h", 0) > 0:
                _xg_adj_bot = _tbl_bot["delta_h"] * 0.25
                hxg = max(0.30, hxg + _xg_adj_bot)
                axg = max(0.30, axg - _xg_adj_bot)
        except: pass
        h2h = get_h2h(m["home_id"],m["away_id"],m["slug"],m["home"],m["away"])
        h2s = h2h_stats(h2h, m["home"], m["away"])
        mc  = ensemble_football(hxg, axg, h2s, hf, af, m["home_id"], m["away_id"], odd_h=m.get("odd_h",0), odd_a=m.get("odd_a",0), odd_d=m.get("odd_d",0), slug=m.get("slug",""))
        # Merge mc50k markets (h_o05, h_o15, gcm_h, etc) que ensemble no devuelve
        _mc50k_extra = mc50k(hxg, axg)
        mc = {**_mc50k_extra, **mc}  # ensemble wins on overlapping keys (ph/pd/pa/o25)
        dp  = diamond_engine(mc, h2s, hf, af)
        # Construir tabla de mercados y usar función central de picks
        _dp2 = dp; _mc2 = mc
        _ph2 = _dp2["ph"]; _pa2 = _dp2["pa"]
        _tg_markets = [
            (f"🏠 {m['home'][:15]} gana",   _ph2,              m.get("odd_h",0) or 3.0,  "1X2"),
            (f"✈️ {m['away'][:15]} gana",    _pa2,              m.get("odd_a",0) or 3.0,  "1X2"),
            ("🤝 Empate",                      _dp2.get("pd",0.25), m.get("odd_d",0) or 3.4, "1X2"),
            (f"🔵 DO {m['home'][:13]}",      min(0.95,_ph2+_dp2.get("pd",0.25)), 1.30, "DO"),
            (f"🟣 DO {m['away'][:13]}",      min(0.95,_pa2+_dp2.get("pd",0.25)), 1.50, "DO"),
            ("⚽ Over 2.5",                   _mc2["o25"],  1.85, "OU"),
            ("🔒 Under 2.5",                  1-_mc2["o25"], 2.00, "OU"),
            ("⚡ Ambos Anotan",                _mc2["btts"], 1.75, "AA"),
        ]
        _tg_markets = [(l,p,o,g) for l,p,o,g in _tg_markets if p >= 0.10]
        _tg_p1, _tg_p2 = _soccer_pick_selector(_tg_markets, _ph2, _pa2,
            odd_h=m.get("odd_h",0), odd_a=m.get("odd_a",0), odd_d=m.get("odd_d",0))
        best = _tg_p1  # pick principal para Telegram
        if best:
            _tg_edge = best[1] - (1/best[2]) if best[2] > 1 else 0.05
            best = (best[0], best[1], best[2], _tg_edge)  # (lbl, prob, odd, edge)
        if best and best[3] >= 0.05:  # edge mínimo 5%
            p = best[1]; b = (best[2]-1) if best[2]>1 else 1
            kelly = max(0, (b*p-(1-p))/b*100) if b>0 else 0
            picks.append({**m,"dp":dp,"mc":mc,"edge":best[3],"kelly":kelly,
                          "pick_label":best[0],"pick_prob":best[1],"pick_odd":best[2]})

    if not picks:
        tg_send("🛡️ *Escáner Diario:* No hay picks con Edge ≥ 5% hoy. Mantén el dinero en la bolsa.")
        return 0

    msg  = "🦅 *THE GAMBLERS DEN | ESCÁNER DIARIO* 🦅\n"
    msg += f"_{datetime.now(CDMX).strftime('%d/%m/%Y')} — {len(picks)} picks_\n\n"
    for p in sorted(picks, key=lambda x:-x["pick_prob"]):
        msg += f"🚨 *{p['league']}*\n"
        msg += f"⚽ *{p['home']}* vs *{p['away']}*\n"
        msg += f"🕒 {p['hora']} CDMX\n"
        msg += f"\n🎯 *{p.get('pick_label','?')}* — {p['pick_prob']*100:.1f}%"
        if p.get('pick_odd',0)>1: msg += f" @{p['pick_odd']:.2f}"
        msg += f" | Edge {p['edge']*100:.1f}%\n"
        msg += f"📐 xG proy: {p['mc'].get('hxg','?')} — {p['mc'].get('axg','?')}\n"
        # Tabla+GD en Telegram
        try:
            _bot_tbl = _tabla_posicion_delta(p["home"], p["away"], p.get("slug",""))
            if _bot_tbl.get("pos_h",0) > 0:
                _bth=_bot_tbl.get("pos_h",0); _bta=_bot_tbl.get("pos_a",0)
                _bgdh=_bot_tbl.get("gd_h",0); _bgda=_bot_tbl.get("gd_a",0)
                msg += f"📊 Tabla: #{_bth} (GD{_bgdh:+.0f}) vs #{_bta} (GD{_bgda:+.0f})\n"
        except: pass
        msg += "━━━━━━━━━━━━━━━━━━━\n\n"
    msg += "_Que la varianza esté a nuestro favor._ 🎲"
    tg_send(msg)
    return len(picks)

def get_nba_public_pct(home, away):
    """Action Network NBA — % público vs sharp en ML y O/U."""
    data = get_action_network_nba(home, away)
