def escanear_nba_y_enviar(games):
    """Escanea NBA y manda el mejor O/U + mejor ML por probabilidad a Telegram."""
    picks = []
    for g in games:
        if g["state"] != "pre": continue
        try:
            res = nba_ou_model(g["home_id"], g["away_id"], g["ou_line"],
                           odd_h=g.get("odd_h",0), odd_a=g.get("odd_a",0),
                           odd_over=g.get("odd_over",0), odd_under=g.get("odd_under",0))
        except:
            res = {"p_over":0.52,"p_under":0.48,"line":g.get("ou_line",220.5),
                   "p_h_win":0.55,"proj":220,"net_h":0,"net_a":0}
        ph = res.get("p_h_win", 0.55); pa = 1 - ph
        ou_p   = max(res["p_over"], res["p_under"])
        ou_lbl = f"{'🔥 Over' if res['p_over'] >= res['p_under'] else '❄️ Under'} {res['line']}"
        ml_p   = max(ph, pa)
        ml_lbl = f"{'🏠' if ph >= pa else '✈️'} {(g['home'] if ph >= pa else g['away'])[:18]} ML"
        ml_odd = (g.get("odd_h",0) if ph >= pa else g.get("odd_a",0)) or 1.91
        if ou_p >= 0.52 or ml_p >= 0.52:
            picks.append({**g, "res": res,
                "ou_p": ou_p, "ou_lbl": ou_lbl,
                "ml_p": ml_p, "ml_lbl": ml_lbl, "ml_odd": ml_odd,
                "ph": ph, "pa": pa, "best_p": max(ou_p, ml_p)})
    if not picks:
        tg_send("🏀 *NBA Scanner:* Sin partidos con señal hoy.")
        return 0
    msg  = "🏀 *THE GAMBLERS DEN | NBA PICKS* 🏀\n"
    msg += f"_{datetime.now(CDMX).strftime('%d/%m/%Y')} — {len(picks)} juegos_\n\n"
    for p in sorted(picks, key=lambda x: -x["best_p"]):
        res_p = p["res"]
        _oh = p.get("odd_h",0) or 1.91; _oa = p.get("odd_a",0) or 1.91
        msg += f"🏀 *{p['away']}* @ *{p['home']}*\n"
        msg += f"🕒 {p['hora']} CDMX\n"
        # Pick principal (mayor prob entre O/U y ML)
        if p["ou_p"] >= p["ml_p"]:
            _pick_lbl = p["ou_lbl"]; _pick_p = p["ou_p"]; _pick_odd = "1.91"
        else:
            _pick_lbl = p["ml_lbl"]; _pick_p = p["ml_p"]; _pick_odd = f"{p['ml_odd']:.2f}"
        msg += f"\n🎯 *{_pick_lbl}* — {_pick_p*100:.1f}% @{_pick_odd}\n"
        msg += f"📐 Proy: *{res_p.get('proj','?')}* pts | Línea: {res_p['line']}\n"
        msg += "━━━━━━━━━━━━━━━━━━━\n\n"
    msg += "_Que la varianza esté a nuestro favor._ 🎲"
    tg_send(msg)
    return len(picks)

def escanear_tenis_y_enviar(matches):
    """Escanea ATP/WTA y manda ML picks con prob >= 62% a Telegram."""
    _smap = {"Indian Wells":"hard","Miami":"hard","Roland Garros":"clay",
             "Wimbledon":"grass","US Open":"hard","Australian Open":"hard",
             "Monte Carlo":"clay","Madrid":"clay","Barcelona":"clay",
             "Rome":"clay","Cincinnati":"hard","Toronto":"hard",
             "Halle":"grass","Queen":"grass","Dubai":"hard","Doha":"hard"}
    picks = []
    for m in matches:
        if m["state"] != "pre": continue
        try:
            tor = m.get("torneo", m.get("tour",""))
            srf = next((v for k,v in _smap.items() if k.lower() in tor.lower()), "hard")
            r1 = m.get("rank1",0) or 0; r2 = m.get("rank2",0) or 0
            p1n = m.get("p1",""); p2n = m.get("p2","")
            if r1 <= 0 or r1 >= 150:
                r1 = _resolve_rank(p1n, _KNOWN_RANKS) or _resolve_rank_local(p1n) or 120
            if r2 <= 0 or r2 >= 150:
                r2 = _resolve_rank(p2n, _KNOWN_RANKS) or _resolve_rank_local(p2n) or 120
            _vd = veredicto_academico_tenis(p1n, p2n, r1, r2,
                                             m.get("odd_1",0), m.get("odd_2",0), srf, tor)
            best_p = _vd["_fav_prob"]
            fav    = _vd["_fav_name"]
            odd    = m.get("odd_1",0) if fav == p1n else m.get("odd_2",0)
            conf   = _vd["_label"]
            if best_p >= 0.62:
                picks.append({**m, "fav": fav, "best_p": best_p, "odd": odd, "conf": conf,
                               "r1": r1, "r2": r2, "srf": srf})
        except: continue
    if not picks:
        tg_send("🎾 *Tennis Scanner:* Sin picks ML con valor hoy.")
        return 0
    msg  = "🎾 *THE GAMBLERS DEN | TENNIS PICKS* 🎾\n"
    msg += f"_{datetime.now(CDMX).strftime('%d/%m/%Y')} — {len(picks)} picks_\n\n"
    for p in sorted(picks, key=lambda x: -x["best_p"]):
        odd_txt = f"@{p['odd']:.2f}" if p["odd"] > 1 else "N/D"
        msg += f"🚨 {p.get('tour','')} — {p.get('torneo','')}\n"
        msg += f"🎾 {p['p1']} vs {p['p2']}\n"
        msg += f"🕒 {p.get('hora','')} CDMX · {p.get('srf','hard').title()} · Rk#{p['r1']} vs #{p['r2']}\n"
        msg += f"👉 *{p['fav']} gana* {odd_txt}\n"
        msg += f"📊 Prob: {p['best_p']*100:.1f}%  •  {p['conf']}\n"
        msg += "━━━━━━━━━━━━━━━━━━━\n"
    msg += "\n_Que la varianza esté a nuestro favor._ 🎲"
    tg_send(msg)
    return len(picks)

def _pach_call(pregunta: str, sport_label: str, context_data: dict) -> str:
    """
    PACH — AI analyst con búsqueda web real.
    Stack: Tavily (búsqueda) + Groq (análisis) — 100% gratis.
    Fallback análisis: Claude si está disponible.
    """
    import requests as _rq

    _tav_key  = TAVILY_API_KEY
    _groq_key = GROQ_API_KEY
    _cl_key   = ANTHROPIC_API_KEY

    if not _groq_key and not _cl_key:
        return "❌ PACH necesita GROQ_API_KEY en Streamlit secrets (gratis en groq.com)"

    fecha_hoy = datetime.now(CDMX).strftime("%d/%m/%Y")
    hora_hoy  = datetime.now(CDMX).strftime("%H:%M")
    fecha_iso = datetime.now(CDMX).strftime("%Y-%m-%d")

    # ── Contexto de partidos del día ──
    partidos_txt = ""
    for p in context_data.get("partidos", [])[:10]:
        try:
            _oh = p.get("odd_h",0); _od = p.get("odd_d",0); _oa = p.get("odd_a",0)
            _odds = f"{_oh:.2f}/{_od:.2f}/{_oa:.2f}" if _oh else "s/d"
            partidos_txt += f"  • {p.get('home','?')} vs {p.get('away','?')} | {p.get('hora','?')} | {_odds}\n"
        except: pass

    kr_pick = context_data.get("kr_pick", "")
    villar  = context_data.get("villar", "")

    # ── Stats avanzados del partido mencionado ──
    _adv_ctx = ""
    try:
        _q_lower = pregunta.lower()
        _p_list  = context_data.get("partidos", [])
        for _p in _p_list:
            _ph = _p.get("home","").lower(); _pa = _p.get("away","").lower()
            if _ph and (_ph in _q_lower or any(w in _q_lower for w in _ph.split() if len(w)>3)):
                _sport_k = {"⚽ Fútbol":"futbol","🏀 NBA":"nba","🎾 Tenis":"tenis"}.get(sport_label,"futbol")
                _adv_ctx = _fetch_advanced_stats_for_match(_p.get("home",""), _p.get("away",""), _sport_k, _p.get("slug",""))
                break
            if _pa and (_pa in _q_lower or any(w in _q_lower for w in _pa.split() if len(w)>3)):
                _sport_k = {"⚽ Fútbol":"futbol","🏀 NBA":"nba","🎾 Tenis":"tenis"}.get(sport_label,"futbol")
                _adv_ctx = _fetch_advanced_stats_for_match(_p.get("home",""), _p.get("away",""), _sport_k, _p.get("slug",""))
                break
    except: pass

    # ── PASO 1: Tavily busca info actual en internet ──────────────
    _web_ctx = ""
    if _tav_key:
        try:
            # Construir queries inteligentes según la pregunta
            _queries = [pregunta]
            # Agregar query de lesiones/alineaciones si aplica
            _q_lower = pregunta.lower()
            if any(w in _q_lower for w in ["lesion","alineacion","lineup","baja","titular"]):
                _queries.append(f"lesiones alineaciones {pregunta} hoy {fecha_iso}")
            elif any(w in _q_lower for w in ["parlay","combinada","multi"]):
                _queries.append(f"mejores picks apuestas {sport_label} hoy {fecha_iso}")
            else:
                _queries.append(f"{pregunta} {fecha_iso} apuestas estadisticas")

            _web_results = []
            # 1 sola búsqueda para ahorrar tokens
            _q1 = _queries[0] if _queries else pregunta
            _r_tav = _rq.post(
                "https://api.tavily.com/search",
                headers={"Content-Type": "application/json"},
                json={
                    "api_key":      _tav_key,
                    "query":        _q1[:150],
                    "search_depth": "basic",
                    "max_results":  3,
                    "include_answer": True,
                },
                timeout=15,
            )
            if _r_tav.status_code == 200:
                _td = _r_tav.json()
                if _td.get("answer"):
                    _web_results.append(_td["answer"][:200])
                for _res in _td.get("results", [])[:2]:
                    _snip = _res.get("content","")[:120]
                    if _snip:
                        _web_results.append(_snip)

            if _web_results:
                _web_ctx = " | ".join(_web_results[:3])
        except: pass

    # ── PASO 2: Groq/Claude analiza con el contexto web ──────────
    # Prompts cortos para no quemar tokens de Groq (límite 100k/día)
    system_prompt = (
        f"Eres PACH, analista de apuestas. {sport_label}. {fecha_hoy}.\n"
        f"KR pick: {(kr_pick or 'N/D')[:60]}\n"
        f"Responde en español, máx 5 líneas. Termina: VEREDICTO: JUGAR/NO JUGAR/ESPERAR — XX%."
    )

    # Contexto web recortado a 400 chars máximo
    _web_short = _web_ctx[:400] if _web_ctx else ""
    user_msg = (
        f"Q: {pregunta[:200]}\n"
        + (f"Web: {_web_short}\n" if _web_short else "")
    )

    # Groq primero
    if _groq_key:
        _groq_err = ""
        try:
            _r_groq = _rq.post(
                "https://api.groq.com/openai/v1/chat/completions",
                headers={"Authorization": f"Bearer {_groq_key}",
                         "Content-Type": "application/json"},
                json={
                    "model": "llama-3.3-70b-versatile",
                    "max_tokens": 400, "temperature": 0.35,
                    "messages": [
                        {"role": "system", "content": system_prompt},
                        {"role": "user",   "content": user_msg},
                    ],
                }, timeout=45,
            )
            if _r_groq.status_code == 200:
                _txt = (_r_groq.json().get("choices",[{}])[0]
                               .get("message",{}).get("content","").strip())
                if _txt:
                    _src = "🔍 Tavily + Groq" if _web_ctx else "🤖 Groq"
                    return f"{_txt}\n\n_Fuente: {_src}_"
            else:
                try:
                    _groq_err = _r_groq.json().get("error",{}).get("message", f"HTTP {_r_groq.status_code}")
                except:
                    _groq_err = f"HTTP {_r_groq.status_code}"
        except Exception as _ge:
            _groq_err = str(_ge)[:120]

    # Claude fallback
    if _cl_key:
        _cl_err = ""
        try:
            _r_cl = _rq.post(
                "https://api.anthropic.com/v1/messages",
                headers={"x-api-key": _cl_key, "anthropic-version": "2023-06-01",
                         "content-type": "application/json"},
                json={
                    "model": "claude-sonnet-4-6", "max_tokens": 1024,
                    "temperature": 0.35, "system": system_prompt,
                    "messages": [{"role": "user", "content": user_msg}],
                }, timeout=60,
            )
            if _r_cl.status_code == 200:
                txt = "\n".join(
                    blk.get("text","") for blk in _r_cl.json().get("content",[])
                    if blk.get("type") == "text" and blk.get("text","").strip()
                ).strip()
                if txt:
                    return f"{txt}\n\n_Fuente: Tavily + Claude_"
            else:
                try:
                    _cl_err = _r_cl.json().get("error",{}).get("message", f"HTTP {_r_cl.status_code}")
                except:
                    _cl_err = f"HTTP {_r_cl.status_code}"
        except Exception as _ce:
            _cl_err = str(_ce)[:120]

    # Mostrar error diagnóstico para que el usuario pueda corregir
    _diag = []
    if _groq_key and _groq_err: _diag.append(f"Groq: {_groq_err}")
    if _cl_key   and _cl_err:   _diag.append(f"Claude: {_cl_err}")
    if not _groq_key and not _cl_key:
        return "❌ PACH necesita GROQ_API_KEY en Streamlit secrets (gratis en groq.com)"
    _diag_str = " | ".join(_diag) if _diag else "sin respuesta"
    return f"⚠️ PACH error: {_diag_str}"
def render_pach(sport_label: str, context_data: dict):
    """
    🤖 PACH — Chat AI analista integrado en el tab de Bot.
    1 pregunta a la vez, respuesta con web_search en vivo.
    """
    api_ok = bool(GROQ_API_KEY or TAVILY_API_KEY or ANTHROPIC_API_KEY)

    st.markdown(f"""
    <div style='background:linear-gradient(135deg,#0a0020,#001a10);
    border:2px solid #bb00ff88;border-radius:7px;padding:7px 9px;margin-bottom:10px'>
      <div style='display:flex;align-items:center;gap:5px;margin-bottom:5px'>
        <div style='font-size:2.4rem'>🤖</div>
        <div style='flex:1'>
          <div style='font-size:1.56rem;font-weight:900;color:#cc44ff;letter-spacing:.08em'>PACH</div>
          <div style='font-size:1.08rem;color:#888'>Analista AI · Powered by Groq + Tavily · Busca en internet en tiempo real</div>
        </div>
        <div style='font-size:0.975rem;padding:4px 10px;border-radius:8px;
        background:{"#00ff8820" if api_ok else "#ff000020"};
        color:{"#00ff88" if api_ok else "#ff4444"};
        border:1px solid {"#00ff8855" if api_ok else "#ff444455"};white-space:nowrap'>
        {"● ONLINE" if api_ok else "● SIN API KEY"}</div>
      </div>
      <div style='background:#ffffff08;border-radius:10px;padding:5px 8px;
      border-left:3px solid #cc44ff;margin-bottom:10px'>
        <div style='color:#cc44ff;font-size:1.08rem;font-weight:700;margin-bottom:4px'>💬 PACH DICE:</div>
        <div style='color:#ddd;font-size:1.32rem;font-style:italic'>
          "Pregúntame cualquier apuesta deportiva y te ayudo. Analizo handicaps, spreads, 
          over de sets, player props, triple dobles, corners, parlays... lo que quieras. 
          Busco la info en internet antes de responderte."
        </div>
      </div>
      <div style='display:flex;gap:6px;flex-wrap:wrap'>
        <span style='background:#1a0a2e;color:#bb00ff;font-size:0.975rem;padding:3px 8px;border-radius:12px;border:1px solid #bb00ff44'>Handicaps</span>
        <span style='background:#1a0a2e;color:#bb00ff;font-size:0.975rem;padding:3px 8px;border-radius:12px;border:1px solid #bb00ff44'>Over/Under sets</span>
        <span style='background:#1a0a2e;color:#bb00ff;font-size:0.975rem;padding:3px 8px;border-radius:12px;border:1px solid #bb00ff44'>Player Props</span>
        <span style='background:#1a0a2e;color:#bb00ff;font-size:0.975rem;padding:3px 8px;border-radius:12px;border:1px solid #bb00ff44'>Triple dobles</span>
        <span style='background:#1a0a2e;color:#bb00ff;font-size:0.975rem;padding:3px 8px;border-radius:12px;border:1px solid #bb00ff44'>Corners · Tarjetas</span>
        <span style='background:#1a0a2e;color:#bb00ff;font-size:0.975rem;padding:3px 8px;border-radius:12px;border:1px solid #bb00ff44'>Parlays combinados</span>
      </div>
    </div>""", unsafe_allow_html=True)

    if not api_ok:
        st.warning("Agrega `GROQ_API_KEY` en Streamlit secrets para activar PACH (gratis en groq.com).")
        return

    # Historial de la sesión (solo últimas 6 para no saturar UI)
    hist_key = f"pach_hist_{sport_label}"
