    with col_clear:
        if st.button("🗑️", key=_ck, help="Limpiar historial"):
            st.session_state[hist_key] = []
            st.rerun()

    # Fix color de texto en chat_input (Streamlit lo pone amarillo/dorado en tema oscuro)
