@st.cache_data(ttl=3600, show_spinner=False)

def _sort_cartelera(matches, hoy_str, hora_now):
    """Ordena cartelera: hoy primero, en vivo arriba, oculta pasados si >= 12:00."""
    if hora_now >= 12:
        matches = [m for m in matches
                   if m.get("fecha","") >= hoy_str or m.get("state") in ("in","pre")]
    def _key(m):
        f = m.get("fecha","9999-99-99")
        h = m.get("hora","99:99")
        s = m.get("state","")
        return (0 if f==hoy_str else 1, 0 if s=="in" else (1 if s=="pre" else 2), h)
    matches.sort(key=_key)
    return matches

@st.cache_data(ttl=120, show_spinner=False)
def get_nba_cartelera():
    now = datetime.now(CDMX)
    dates = [(now+timedelta(days=i)).strftime("%Y%m%d") for i in range(-1,3)]  # incluir ayer (partidos tardíos)
    hoy = now.strftime("%Y-%m-%d")
    ayer = (now-timedelta(days=1)).strftime("%Y-%m-%d")
    games, seen = [], set()
    for ds in dates:
        data = eg(f"{NBA_ESPN}/scoreboard", {"dates": ds, "limit": 50})
        for ev in data.get("events",[]):
            eid = ev.get("id","")
            if eid in seen: continue
            seen.add(eid)
            try:
                comp  = ev["competitions"][0]
                comps = comp["competitors"]
                hc = next(c for c in comps if c["homeAway"]=="home")
                ac = next(c for c in comps if c["homeAway"]=="away")
                utc   = datetime.strptime(ev["date"],"%Y-%m-%dT%H:%MZ").replace(tzinfo=pytz.UTC)
                hora  = utc.astimezone(CDMX).strftime("%H:%M")
                fecha = utc.astimezone(CDMX).strftime("%Y-%m-%d")
                state = ev["status"]["type"]["state"]
                # Corregir state: ESPN a veces deja partidos terminados como "in"
                _st_detail = ev.get("status",{}).get("type",{}).get("detail","")
                _st_desc   = ev.get("status",{}).get("type",{}).get("description","").lower()
                if state == "in" and ("final" in _st_desc or "final" in _st_detail.lower()):
                    state = "post"
                # También: si "period" es Q4 u OT y el reloj es 0:00 → post
                if state == "in":
                    _clock = ev.get("status",{}).get("displayClock","")
                    _per   = ev.get("status",{}).get("period", 0)
                    if _per >= 4 and _clock in ("0:00","00:00","0.0"):
                        state = "post"
                # Permitir ayer solo si el partido ya terminó (state=post) — para NBA tardío
                if fecha < ayer: continue
                if fecha == ayer and state != "post": continue
                if fecha > (now+timedelta(days=2)).strftime("%Y-%m-%d"): continue
                ou_line = 0.0
                try:
                    odds = comp.get("odds",[])
                    if odds: ou_line = float(odds[0].get("overUnder",0) or 0)
                except: pass
                games.append({
                    "id":eid,"home":hc["team"]["displayName"],
                    "away":ac["team"]["displayName"],
                    "home_id":str(hc["team"]["id"]),"away_id":str(ac["team"]["id"]),
                    "hora":hora,"fecha":fecha,"state":state,"ou_line":ou_line,
                    "score_h":parse_score(hc.get("score",0)),
                    "score_a":parse_score(ac.get("score",0)),
                })
            except: continue
    _now2 = datetime.now(CDMX)
    games = _sort_cartelera(games, _now2.strftime("%Y-%m-%d"), int(_now2.strftime("%H")))
    return games

@st.cache_data(ttl=28800, show_spinner=False)
def get_nba_team_stats(team_id):
    """
    Extrae stats avanzadas de ESPN NBA:
    PPG, OppPPG, Pace, eFG%, TurnoverRate, FTRate
    Estos son los drivers reales del total de puntos.
    """
    data = eg(f"{NBA_ESPN}/teams/{team_id}/statistics")
    stats = {"ppg":110.0,"opp_ppg":110.0,"pace":100.0,
             "efg":0.52,"tov_rate":0.14,"ft_rate":0.23,
             "ortg":112.0,"drtg":112.0,"net_rtg":0.0,"fouls_pg":20.0}
    try:
        for cat in data.get("results",{}).get("stats",{}).get("categories",[]):
            for s in cat.get("stats",[]):
                n = s.get("name","").lower()
                v = float(s.get("value",0) or 0)
                if n in ("pointspergame","ppg"):            stats["ppg"]      = v
                elif n in ("opponentpointspergame","oppg"): stats["opp_ppg"]  = v
                elif n == "pace":                           stats["pace"]     = v
                elif n in ("effectivefgpct","efgpct"):      stats["efg"]      = v
                elif n in ("turnoverpct","tovpct"):         stats["tov_rate"] = v
                elif n in ("offensiverating","ortg"):       stats["ortg"]     = v
                elif n in ("defensiverating","drtg"):       stats["drtg"]     = v
                elif n in ("fouls","foulspergame","pf","pfpg"): stats["fouls_pg"] = v
    except: pass
    # Net rating
    stats["net_rtg"] = stats["ortg"] - stats["drtg"]
    return stats


@st.cache_data(ttl=7200, show_spinner=False)
def get_nba_recent_form(team_id, n_games=10):
    """
    Últimos N partidos NBA — detecta racha, back-to-back fatigue,
    promedio de puntos reciente (más relevante que promedio de temporada).
    v2: agrega Q4 pts, días de descanso exactos, ortg/drtg por partido.
    """
    data = eg(f"{NBA_ESPN}/teams/{team_id}/schedule")
    events = data.get("events", [])
    results = []
    for ev in events:
        try:
            comp  = ev["competitions"][0]
            state = ev.get("status",{}).get("type",{}).get("state","")
            if state != "post": continue
            comps = comp["competitors"]
            hc = next(c for c in comps if c["homeAway"]=="home")
            ac = next(c for c in comps if c["homeAway"]=="away")
            is_home = str(hc["team"]["id"]) == str(team_id)
            my  = hc if is_home else ac
            opp = ac if is_home else hc
            pts_for     = parse_score(my.get("score",0))
            pts_against = parse_score(opp.get("score",0))

            # ── Q4 pts — clutch performance ──
            q4_for = q4_against = 0
            try:
                my_ls  = my.get("linescores", [])
                opp_ls = opp.get("linescores", [])
                if len(my_ls) >= 4:
                    q4_for     = int(float(my_ls[3].get("value", 0) or 0))
                    q4_against = int(float(opp_ls[3].get("value", 0) or 0)) if len(opp_ls) >= 4 else 0
            except: pass

            # ── Ortg/Drtg por partido (estimado desde puntos + pace proxy) ──
            # Usamos 100 posesiones estimadas: ortg = pts_for/poss*100
            # Posesiones ≈ (pts_for + pts_against) / 2 / 1.08 (factor estimado)
            try:
                poss_est = max(80, (pts_for + pts_against) / 2.16)
                ortg_game = round(pts_for / poss_est * 100, 1)
                drtg_game = round(pts_against / poss_est * 100, 1)
            except:
                ortg_game = drtg_game = 110.0

            results.append({
                "date":        ev.get("date","")[:10],
                "pts_for":     pts_for,
                "pts_against": pts_against,
                "total":       pts_for + pts_against,
                "won":         pts_for > pts_against,
                "result":      "W" if pts_for > pts_against else "L",
                "is_home":     is_home,
                "q4_for":      q4_for,
                "q4_against":  q4_against,
                "ortg_game":   ortg_game,
                "drtg_game":   drtg_game,
            })
        except: continue
    results.sort(key=lambda x: x["date"], reverse=True)
    results = results[:n_games]

    # ── Días de descanso exactos (post-sort) ──
    from datetime import datetime as _dt
    today = _dt.now().date()
    for i, g in enumerate(results):
        try:
            gd = _dt.strptime(g["date"], "%Y-%m-%d").date()
            if i == 0:
                g["days_rest"] = (today - gd).days   # días desde último partido
            else:
                prev_d = _dt.strptime(results[i-1]["date"], "%Y-%m-%d").date()
                g["days_rest"] = (prev_d - gd).days  # días entre partidos
        except:
            g["days_rest"] = 2
    return results



# ══════════════════════════════════════════════════════════════
# NBA SELF-LEARNING CALIBRATION SYSTEM
# Guarda picks históricos, mide bias real (proj vs real),
# y ajusta automáticamente nba_ou_model en futuras predicciones.
# ══════════════════════════════════════════════════════════════

def _nba_exact_rest(form):
    """
    Días de descanso exactos hasta el partido de hoy.
    Más granular que solo detectar back-to-back (0 días).
    Retorna factor multiplicador de proyección:
      0 días (B2B)  → 0.935 (-6.5%)
      1 día         → 0.970 (-3.0%)
      2 días        → 1.000 (normal)
      3 días        → 1.010 (+1.0%)
      4+ días       → 1.018 (+1.8%)  frescos pero pueden estar fríos
    Ref: Estudio Lamas et al. 2018 — descanso y rendimiento ofensivo NBA
    """
    if not form: return {"days": 2, "factor": 1.0}
    days = form[0].get("days_rest", 2) if form else 2
    factor_map = {0: 0.935, 1: 0.970, 2: 1.000, 3: 1.010}
    factor = factor_map.get(days, 1.018 if days >= 4 else 1.000)
    return {"days": days, "factor": round(factor, 3)}


def _nba_rolling_ratings(form, n=5):
    """
    Ortg y Drtg de los últimos N partidos — más relevante que la temporada completa.
    Captura equipos que mejoran/empeoran en el tramo final de temporada.
    Retorna: {ortg_5, drtg_5, net_5, n_used}
    """
    games = [g for g in form[:n] if g.get("ortg_game", 0) > 0]
    if len(games) < 3:
        return {"ortg_5": None, "drtg_5": None, "net_5": None, "n_used": 0}
    # Decay: partidos más recientes pesan más
    DECAY = 0.88
    w_ortg = w_drtg = w_tot = 0.0
    for i, g in enumerate(games):
        w = DECAY ** i
        w_ortg += w * g["ortg_game"]
        w_drtg += w * g["drtg_game"]
        w_tot  += w
    ortg = w_ortg / w_tot
    drtg = w_drtg / w_tot
    return {
        "ortg_5": round(ortg, 1),
        "drtg_5": round(drtg, 1),
        "net_5":  round(ortg - drtg, 1),
        "n_used": len(games),
    }


def _nba_clutch_factor(form, n=8):
    """
    Rendimiento en 4° cuarto — equipos clutch vs equipos que colapsan.
    Calcula diferencial Q4 promedio (q4_for - q4_against).
    NBA promedio Q4: ~28 pts por equipo (≈ 56 total Q4).
    Retorna factor para ajuste de ML probability:
      Q4 diff +3.0+ → equipo clutch → +0.03 prob
      Q4 diff -3.0- → equipo colapsa → -0.03 prob
    """
    games = [g for g in form[:n] if g.get("q4_for", 0) > 0]
    if len(games) < 4:
        return {"q4_diff": 0.0, "factor": 0.0, "n_used": 0}
    diffs = [g["q4_for"] - g["q4_against"] for g in games]
    avg_diff = sum(diffs) / len(diffs)
    # Factor: cada punto de diferencial Q4 = 0.008 de prob
    factor = max(-0.04, min(0.04, avg_diff * 0.008))
    return {
        "q4_diff":  round(avg_diff, 1),
        "factor":   round(factor, 4),
        "n_used":   len(games),
    }


def _nba_calib_load():
    """Carga el historial de calibración NBA."""
    import json as _j
    try:
        if os.path.exists(NBA_CALIB_FILE):
            with open(NBA_CALIB_FILE, "r") as _f:
                return _j.load(_f)
    except: pass
    return {"picks": [], "bias": 0.0, "n": 0, "last_update": ""}

def _nba_calib_save(data):
    """Guarda historial de calibración NBA."""
    import json as _j
    try:
        with open(NBA_CALIB_FILE, "w") as _f:
            _j.dump(data, _f)
    except: pass

def _nba_calib_register_pick(game_id, home, away, proj, ou_line, pick_side, fecha):
    """
    Registra un pick NBA al momento de hacerlo.
    pick_side: 'over' | 'under'
    """
    data = _nba_calib_load()
    # Evitar duplicados
    ids = {p["game_id"] for p in data["picks"]}
    if game_id in ids:
        return
    data["picks"].append({
        "game_id":  game_id,
        "home":     home,
        "away":     away,
        "proj":     proj,
        "ou_line":  ou_line,
        "pick":     pick_side,
        "fecha":    fecha,
        "real":     None,   # se llena después con el resultado
        "error":    None,   # proj - real (positivo = sobreestimé)
        "result":   None,   # 'W' | 'L'
    })
    _nba_calib_save(data)

def _nba_calib_update_result(game_id, real_total):
    """
    Registra el resultado real y recalcula bias global.
    Llamar desde update_results_db cuando llegan scores NBA.
    """
    data = _nba_calib_load()
    updated = False
    for p in data["picks"]:
        if p["game_id"] == game_id and p["real"] is None:
            p["real"]   = real_total
            p["error"]  = round(p["proj"] - real_total, 1)  # + = sobreestimé
            if p["pick"] == "over":
                p["result"] = "W" if real_total > p["ou_line"] else "L"
            else:
                p["result"] = "W" if real_total < p["ou_line"] else "L"
            updated = True
    if updated:
        # Recalcular bias global con picks resueltos (últimos 30)
        resolved = [p for p in data["picks"] if p["error"] is not None][-30:]
        if resolved:
            data["bias"]        = round(sum(p["error"] for p in resolved) / len(resolved), 2)
            data["n"]           = len(resolved)
            data["last_update"] = datetime.now(CDMX).strftime("%Y-%m-%d %H:%M")
            # Breakdown Over vs Under
            over_errs  = [p["error"] for p in resolved if p["pick"]=="over"]
            under_errs = [p["error"] for p in resolved if p["pick"]=="under"]
            data["bias_over"]  = round(sum(over_errs)/len(over_errs), 2) if over_errs else 0.0
            data["bias_under"] = round(sum(under_errs)/len(under_errs), 2) if under_errs else 0.0
            data["wr_over"]    = round(sum(1 for p in resolved if p["pick"]=="over"  and p["result"]=="W") / max(1,len(over_errs)) * 100, 1)
            data["wr_under"]   = round(sum(1 for p in resolved if p["pick"]=="under" and p["result"]=="W") / max(1,len(under_errs)) * 100, 1)
            data["avg_miss_over"]  = round(sum(abs(p["error"]) for p in resolved if p["pick"]=="over"  and p["result"]=="L") / max(1, sum(1 for p in resolved if p["pick"]=="over"  and p["result"]=="L")), 1)
            data["avg_miss_under"] = round(sum(abs(p["error"]) for p in resolved if p["pick"]=="under" and p["result"]=="L") / max(1, sum(1 for p in resolved if p["pick"]=="under" and p["result"]=="L")), 1)
        _nba_calib_save(data)
    return updated

def _nba_calib_get_adjustment():
    """
    Devuelve ajuste de proyección basado en bias histórico.
    Si el modelo sobreestima sistemáticamente N pts, se corrige en -N.
    Cappado a ±8 pts para no sobre-corregir.
    """
    data = _nba_calib_load()
    bias = data.get("bias", 0.0)
    n    = data.get("n", 0)
    if n < 5:
        return 0.0  # no suficientes datos para ajustar
    # Corrección gradual: 50% del bias si n<15, 80% si n>=15
    factor = 0.5 if n < 15 else 0.80
    adj = -bias * factor  # bias positivo = sobreestimo → restar
    return max(-8.0, min(8.0, adj))


# ══════════════════════════════════════════════════════════════════════════════
# SOCCER AUTO-CALIBRATION — aprende de cada pick resuelto
# Calibra por liga: bias de probabilidad, win-rate real vs esperado,
# y ajusta xG scale factor para que el modelo converja a la realidad.
# ══════════════════════════════════════════════════════════════════════════════

def _soc_calib_load():
    try:
        if os.path.exists(SOC_CALIB_FILE):
            with open(SOC_CALIB_FILE) as f: return json.load(f)
    except: pass
    return {"picks": [], "global": {}, "by_liga": {}, "n": 0, "last_update": ""}

def _soc_calib_save(data):
    try:
        with open(SOC_CALIB_FILE, "w") as f: json.dump(data, f)
    except: pass

def _soc_calib_register(match_id, home, away, liga, slug,
                         ph, pa, pd, pick_lbl, pick_prob, odd, fecha):
    """Registra un pick de fútbol antes del partido."""
    data = _soc_calib_load()
    ids = {p["match_id"] for p in data["picks"]}
    if match_id in ids: return
    data["picks"].append({
        "match_id": match_id, "home": home, "away": away,
        "liga": liga, "slug": slug,
        "ph": round(ph,4), "pa": round(pa,4), "pd": round(pd,4),
        "pick": pick_lbl, "prob": round(pick_prob,4), "odd": round(odd,2),
        "fecha": fecha, "score_h": None, "score_a": None,
        "result": None,   # W | L | D (result of pick)
        "outcome": None,  # H | A | D (match outcome)
        "ev_real": None,  # ph*odd_h - 1  (realized EV)
    })
    _soc_calib_save(data)

def _soc_calib_resolve(match_id, score_h, score_a):
    """Llena resultado cuando el partido termina."""
    data = _soc_calib_load()
    updated = False
    for p in data["picks"]:
        if p["match_id"] == match_id and p["result"] is None:
            p["score_h"] = score_h
            p["score_a"] = score_a
            outcome = "H" if score_h > score_a else ("A" if score_a > score_h else "D")
            p["outcome"] = outcome
            lbl = p["pick"].lower()
            if "gana" in lbl or "home" in lbl or "local" in lbl:
                if "away" in lbl or "✈" in lbl or "visita" in lbl:
                    p["result"] = "W" if outcome == "A" else "L"
                else:
                    p["result"] = "W" if outcome == "H" else "L"
            elif "empate" in lbl or "draw" in lbl or "🤝" in lbl:
                p["result"] = "W" if outcome == "D" else "L"
            elif "over" in lbl:
                p["result"] = "W" if (score_h + score_a) > 2.5 else "L"
            elif "under" in lbl:
                p["result"] = "W" if (score_h + score_a) < 2.5 else "L"
            elif "ambos" in lbl or "btts" in lbl:
                p["result"] = "W" if (score_h > 0 and score_a > 0) else "L"
            elif "o emp" in lbl or "doble" in lbl:
                if "✈" in lbl or "away" in lbl:
                    p["result"] = "W" if outcome in ("A","D") else "L"
                else:
                    p["result"] = "W" if outcome in ("H","D") else "L"
            else:
                p["result"] = "W" if outcome == "H" else "L"
            # EV realizado: ganó → odd-1, perdió → -1
            odd = p.get("odd", 0)
            if odd > 1:
                p["ev_real"] = round((odd - 1) if p["result"] == "W" else -1.0, 3)
            updated = True
            break

    if updated:
        _soc_calib_recalc(data)
        _soc_calib_save(data)
    return updated

def _soc_calib_recalc(data):
    """Recalcula bias global y por liga con los picks resueltos."""
    resolved = [p for p in data["picks"] if p["result"] is not None]
    if not resolved: return

    # ── Global stats ──
    last50 = resolved[-50:]
    wr     = sum(1 for p in last50 if p["result"] == "W") / len(last50)
    # Brier score: (prob - outcome)^2  lower=better
    brier  = sum((p["prob"] - (1 if p["result"]=="W" else 0))**2 for p in last50) / len(last50)
    # Calibration bias: avg(prob_predicha - prob_real)
    # Si bias > 0 → el modelo sobreestima (genera picks con 60% que ganan al 50%)
    bias   = sum(p["prob"] for p in last50) / len(last50) - wr
    ev_avg = sum(p["ev_real"] for p in last50 if p["ev_real"] is not None) / max(1, sum(1 for p in last50 if p["ev_real"] is not None))

    data["global"] = {
        "n": len(last50), "wr": round(wr, 4),
        "brier": round(brier, 4), "bias": round(bias, 4),
        "ev_avg": round(ev_avg, 4),
        "last_update": datetime.now(CDMX).strftime("%Y-%m-%d %H:%M"),
    }
    data["n"] = len(resolved)

    # ── By liga (mín 5 picks para estadística válida) ──
    by_liga = {}
    for p in resolved:
        lig = p.get("liga","?")
        by_liga.setdefault(lig, []).append(p)

    data["by_liga"] = {}
    for lig, picks in by_liga.items():
        if len(picks) < 3: continue
        last_lig = picks[-20:]
        wr_l = sum(1 for p in last_lig if p["result"]=="W") / len(last_lig)
        bias_l = sum(p["prob"] for p in last_lig)/len(last_lig) - wr_l
        data["by_liga"][lig] = {
            "n": len(last_lig), "wr": round(wr_l,4),
            "bias": round(bias_l,4),
        }

def _soc_calib_get_adj(liga=None):
    """
    Devuelve factor de ajuste de probabilidad para una liga.
    Si el modelo sobreestima en 8pp en Liga MX → reduce prob predicha un 8pp.
    Caps: ±12pp, solo aplica si n >= 8 picks resueltos.
    """
    data = _soc_calib_load()
    # Liga específica primero
    if liga:
        lig_data = data.get("by_liga", {}).get(liga)
        if lig_data and lig_data.get("n",0) >= 8:
            bias = lig_data["bias"]
            # Corrección gradual: 40% del bias si n<15, 65% si n>=15
            f = 0.40 if lig_data["n"] < 15 else 0.65
            return max(-0.12, min(0.12, -bias * f))
    # Global fallback
    g = data.get("global", {})
    if g.get("n",0) >= 10:
        bias = g.get("bias", 0)
        f = 0.40 if g["n"] < 20 else 0.65
        return max(-0.12, min(0.12, -bias * f))
    return 0.0

def _soc_calib_get_liga_params(slug):
    """
    Parámetros especializados por liga basados en historial real.
    Retorna dict con: xg_scale (multiplicador xG), market_weight (peso cuotas),
    decay (decaimiento exponencial forma), min_ev (umbral EV mínimo).
    Empieza con defaults; se ajustan automáticamente según calibración.
    """
    # Defaults por tipo de liga
    LIGA_DEFAULTS = {
        # Ligas con mercados muy eficientes → más peso al mercado
        "eng.1": {"xg_scale":1.00, "market_w":0.20, "decay":0.85, "min_ev":0.02},
        "esp.1": {"xg_scale":1.00, "market_w":0.20, "decay":0.85, "min_ev":0.02},
        "ger.1": {"xg_scale":1.00, "market_w":0.20, "decay":0.85, "min_ev":0.02},
        "ita.1": {"xg_scale":1.00, "market_w":0.18, "decay":0.85, "min_ev":0.02},
        "fra.1": {"xg_scale":1.00, "market_w":0.18, "decay":0.85, "min_ev":0.02},
        # Ligas LATAM — mercados menos eficientes, más ruido
        "mex.1": {"xg_scale":0.95, "market_w":0.14, "decay":0.82, "min_ev":0.03},
        "mex.2": {"xg_scale":0.93, "market_w":0.12, "decay":0.80, "min_ev":0.03},
        "bra.1": {"xg_scale":0.95, "market_w":0.14, "decay":0.82, "min_ev":0.03},
        "arg.1": {"xg_scale":0.93, "market_w":0.13, "decay":0.82, "min_ev":0.03},
        # UEFA — partidos de ida/vuelta, rotación
        "uefa.champions": {"xg_scale":1.02, "market_w":0.22, "decay":0.88, "min_ev":0.025},
        "uefa.europa":    {"xg_scale":1.00, "market_w":0.18, "decay":0.86, "min_ev":0.025},
    }
    base = LIGA_DEFAULTS.get(slug, {"xg_scale":0.97, "market_w":0.15, "decay":0.83, "min_ev":0.025})

    # Ajuste dinámico: si tenemos calibración de esta liga, afinar market_weight
    data = _soc_calib_load()
    lig_cal = data.get("by_liga", {})
    # Buscar por slug o por nombre de liga
    for k, v in lig_cal.items():
        if slug in k or k in slug:
            if v.get("n",0) >= 10:
                wr = v.get("wr", 0.5)
                bias = v.get("bias", 0)
                # Si win rate < 45% → aumentar min_ev (ser más selectivo)
                if wr < 0.45:
                    base["min_ev"] = min(0.06, base["min_ev"] + 0.015)
                elif wr > 0.58:
                    base["min_ev"] = max(0.01, base["min_ev"] - 0.005)
                # Si bias alto → confiar más en mercado
                if abs(bias) > 0.06:
                    base["market_w"] = min(0.30, base["market_w"] + 0.05)
            break
    return base



def nba_ou_model(home_id, away_id, ou_line, referee_names=None,
                 odd_h=0.0, odd_a=0.0, odd_over=0.0, odd_under=0.0):
    """
    NBA O/U + ML — mejoras v2:
    1. HCA calibrada: +2.8 pts (57.8% real NBA 2024, BBRef)
    2. Pace sin cap: escala lineal, no truncado a ±5%
    3. Sigma dinámico: usa varianza real últimos 7 partidos por equipo
    4. ML integrado: combina net_rating + diferencial de proyección de puntos
    5. Foul-rate real: usa fouls/game del equipo vs árbitros (ESPN)
    """
    h_stats = get_nba_team_stats(home_id)
    a_stats = get_nba_team_stats(away_id)
    h_form  = get_nba_recent_form(home_id, 10)
    a_form  = get_nba_recent_form(away_id, 10)

    # ── NBA Stats API — enriquecimiento silencioso ──
    # Si stats.nba.com responde → blend con ESPN. Si no → ESPN solo.
    try:
        _nba_id_h = _ESPN_TO_NBASTATS.get(str(home_id), "")
        _nba_id_a = _ESPN_TO_NBASTATS.get(str(away_id), "")
        if _nba_id_h:
            _adv_h = _nba_stats_team_advanced(_nba_id_h)
            _l5_h  = _nba_stats_last_n(_nba_id_h, 5)
            # Blend: si NBA Stats da net_rtg → 50/50 con ESPN
            if _adv_h.get("net_rtg"):
                h_stats["net_rtg"] = 0.5*h_stats["net_rtg"] + 0.5*_adv_h["net_rtg"]
                h_stats["ortg"]    = 0.5*h_stats["ortg"]    + 0.5*_adv_h.get("off_rtg", h_stats["ortg"])
                h_stats["drtg"]    = 0.5*h_stats["drtg"]    + 0.5*_adv_h.get("def_rtg", h_stats["drtg"])
                h_stats["pace"]    = 0.5*h_stats["pace"]     + 0.5*_adv_h.get("pace", h_stats["pace"])
            if _l5_h.get("ppg"):
                h_stats["ppg"] = 0.4*h_stats["ppg"] + 0.6*_l5_h["ppg"]  # últimos 5 pesan más
        if _nba_id_a:
            _adv_a = _nba_stats_team_advanced(_nba_id_a)
            _l5_a  = _nba_stats_last_n(_nba_id_a, 5)
            if _adv_a.get("net_rtg"):
                a_stats["net_rtg"] = 0.5*a_stats["net_rtg"] + 0.5*_adv_a["net_rtg"]
                a_stats["ortg"]    = 0.5*a_stats["ortg"]    + 0.5*_adv_a.get("off_rtg", a_stats["ortg"])
                a_stats["drtg"]    = 0.5*a_stats["drtg"]    + 0.5*_adv_a.get("def_rtg", a_stats["drtg"])
                a_stats["pace"]    = 0.5*a_stats["pace"]     + 0.5*_adv_a.get("pace", a_stats["pace"])
            if _l5_a.get("ppg"):
                a_stats["ppg"] = 0.4*a_stats["ppg"] + 0.6*_l5_a["ppg"]
    except: pass

    # ── PPG con decay exponencial ──
    DECAY = 0.88
    def decay_ppg(form, fallback):
        if not form: return fallback
        w_total = w_pts = 0
        for i, g in enumerate(form):
            w = DECAY**i; w_pts += w*g["pts_for"]; w_total += w
        return w_pts/w_total if w_total > 0 else fallback

    h_recent_ppg = decay_ppg(h_form, h_stats["ppg"])
    a_recent_ppg = decay_ppg(a_form, a_stats["ppg"])

    # ── FIX 1: Pace sin cap — escala lineal completa ──
    # Liga promedio pace ≈ 100. Por cada punto de pace sobre/bajo promedio:
    # total proyectado sube/baja ~0.9 pts (calibrado FBRef 2022-24)
    avg_pace = (h_stats["pace"] + a_stats["pace"]) / 2
    pace_delta = (avg_pace - 100.0) * 0.009   # +pace → +pts, sin cap

    # ── FIX 2: HCA correcta — +2.8 pts reales (no 1.4%) ──
    # NBA 2018-24: home teams win 57.8%, avg margin +2.8 pts (BBRef)
    HCA_PTS = 2.8
    h_proj = h_recent_ppg + HCA_PTS * 0.5   # local anota más
    a_proj = a_recent_ppg - HCA_PTS * 0.5   # visitante anota menos

    # ── Descanso exacto (reemplaza back-to-back binario) ──
    _rest_h = _nba_exact_rest(h_form)
    _rest_a = _nba_exact_rest(a_form)
    b2b_h = _rest_h["days"] == 0
    b2b_a = _rest_a["days"] == 0
    h_proj = h_proj * _rest_h["factor"]
    a_proj = a_proj * _rest_a["factor"]

    # Net rating adjustment
    net_diff = h_stats["net_rtg"] - a_stats["net_rtg"]

    # ── ortg/drtg últimos 5 — más relevante que temporada completa ──
    _roll_h = _nba_rolling_ratings(h_form, n=5)
    _roll_a = _nba_rolling_ratings(a_form, n=5)
    # Si hay suficientes datos, blend 60% temporada + 40% últimos 5
    try:
        if _roll_h["net_5"] is not None and _roll_a["net_5"] is not None:
            net_diff = 0.60 * net_diff + 0.40 * (_roll_h["net_5"] - _roll_a["net_5"])
            # Proyección: ajustar por ortg reciente vs temporada
            _ortg_adj_h = (_roll_h["ortg_5"] - h_stats["ortg"]) * 0.40
            _ortg_adj_a = (_roll_a["ortg_5"] - a_stats["ortg"]) * 0.40
            h_proj = h_proj + _ortg_adj_h
            a_proj = a_proj + _ortg_adj_a
    except: pass

    # Defensive matchup
    try:
        _h_def_adj, _a_def_adj = _nba_defensive_matchup(h_stats, a_stats)
        h_proj = h_proj * _h_def_adj
        a_proj = a_proj * _a_def_adj
    except: pass

    # Estrellas ausentes
    try:
        _h_inj = [g.get("injury_report","") for g in h_form[:3] if g.get("injury_report")]
        _a_inj = [g.get("injury_report","") for g in a_form[:3] if g.get("injury_report")]
        _h_star_delta, _h_spread_delta, _ = _star_nba_adjustment(home_id or "", _h_inj)
        _a_star_delta, _a_spread_delta, _ = _star_nba_adjustment(away_id or "", _a_inj)
        h_proj = max(80, h_proj + _h_star_delta)
        a_proj = max(80, a_proj + _a_star_delta)
        _net_star_spread = _h_spread_delta - _a_spread_delta
    except:
        _net_star_spread = 0.0

    # B2B fatigue — ahora manejado por _rest_h factor, este es residual severo
    if b2b_h: h_proj -= 1.5   # reducido: rest factor ya aplicó -6.5%
    if b2b_a: a_proj -= 1.2

    # ── FIX 3: Foul-rate real del equipo (no árbitros que ESPN no da) ──
    # Equipos con alta tasa de faltas → más FT → más pts → total más alto
    # fouls_per_game promedio NBA: ~20. Cada foul extra ≈ +0.35 pts (FTRate calibrado)
    try:
        h_fouls = h_stats.get("fouls_pg", 20.0)
        a_fouls = a_stats.get("fouls_pg", 20.0)
        avg_fouls = (h_fouls + a_fouls) / 2
        foul_adj = (avg_fouls - 20.0) * 0.35   # desviación vs promedio
    except:
        foul_adj = 0.0

    proj = h_proj + a_proj + net_diff * 0.15 + pace_delta + foul_adj

    # Auto-calibración bias histórico
    _calib_adj = _nba_calib_get_adjustment()
    if _calib_adj != 0.0:
        proj   += _calib_adj
        h_proj += _calib_adj * 0.5
        a_proj += _calib_adj * 0.5

    line = ou_line if ou_line > 0 else proj

    # ── FIX 4: Sigma dinámico por equipo ──
    # Usa desviación estándar real de los últimos N partidos
    # Si no hay datos: fallback 11.5 (promedio histórico NBA)
    def team_sigma(form, fallback=11.5):
        pts = [g["pts_for"] for g in form if g.get("pts_for")]
        if len(pts) >= 4:
            mu = sum(pts)/len(pts)
            var = sum((p-mu)**2 for p in pts)/len(pts)
            return max(7.0, min(16.0, var**0.5))  # cap 7-16
        return fallback

    h_sigma = team_sigma(h_form)
    a_sigma = team_sigma(a_form)

    # Monte Carlo 50k con sigma por equipo
    rng    = np.random.default_rng(seed=None)
    h_sims = rng.normal(h_proj, h_sigma, 10_000)
    a_sims = rng.normal(a_proj, a_sigma, 10_000)
    tots   = h_sims + a_sims

    p_over  = float((tots > line).mean())
    p_under = 1 - p_over

    # ── FIX 5: ML integrado — net_rating + diferencial proyectado ──
    # Dos señales independientes y complementarias:
    # A) Net rating → quién es el mejor equipo de la temporada
    # B) Proyección de puntos → quién está mejor AHORA (forma, lesiones, B2B)
    net_h = h_stats["net_rtg"]; net_a = a_stats["net_rtg"]
    net_diff_ml = net_h - net_a

    # Diferencial de proyección (h_proj - a_proj) ya incluye HCA, B2B, lesiones
    proj_diff = h_proj - a_proj  # positivo = local favorito

    # ── MODELO 3: Win% reciente (últimos 10 partidos, ponderado local/visita) ──
    # Señal independiente del net_rating (temporada completa) y proyección (puntos)
    # Captura rachas, momentum, equipos que mejoran/empeoran en el tramo final
    try:
        def _recent_wr(form, is_home, n=10):
            if not form: return None
            games = form[:n]
            if len(games) < 4: return None
            w_wins = w_tot = 0.0
            for g in games:
                same = g.get("is_home", is_home) == is_home
                weight = 1.4 if same else 1.0   # más peso si es en la misma condición
                w_wins += weight * (1.0 if g.get("result") == "W" else 0.0)
                w_tot  += weight
            return w_wins / w_tot if w_tot > 0 else None

        _h_wr_nba = _recent_wr(h_form, True)
        _a_wr_nba = _recent_wr(a_form, False)

        if _h_wr_nba is not None and _a_wr_nba is not None:
            # Win% diferencial → logit → probabilidad
            _wr_diff = (_h_wr_nba - _a_wr_nba) * 10.0  # escala similar a net_rating
            _p_h_wr  = 1 / (1 + math.exp(-_wr_diff * 0.12))
        else:
            _p_h_wr = 0.5
        _has_wr = _h_wr_nba is not None and _a_wr_nba is not None
    except:
        _p_h_wr = 0.5; _has_wr = False

    # Blend 3 modelos independientes — número impar garantiza desempate
    # 40% net_rtg (quién es mejor en temporada) + 35% proj_diff (quién está mejor HOY)
    # + 25% win% reciente (momentum y racha — ignora puntos, solo victorias)
    if _has_wr:
        combined_diff = 0.40 * net_diff_ml + 0.35 * proj_diff + 0.25 * (_p_h_wr - 0.5) * 20
    else:
        combined_diff = 0.55 * net_diff_ml + 0.45 * proj_diff

    # HCA ya está en proj_diff, agregar efecto psicológico residual (+0.8 pts)
    combined_diff += 0.8

    try: combined_diff += _net_star_spread
    except: pass

    # ── Clutch Q4 — equipos que ganan/pierden partidos cerrados ──
    try:
        _clutch_h = _nba_clutch_factor(h_form)
        _clutch_a = _nba_clutch_factor(a_form)
        # Diferencial clutch: local clutch vs visita clutch
        _clutch_net = _clutch_h["factor"] - _clutch_a["factor"]
        # Convertir a pts equivalentes para el blend (factor 0.04 → ~3.3 pts)
        combined_diff += _clutch_net * 25.0
    except:
        _clutch_h = _clutch_a = {"q4_diff": 0.0, "factor": 0.0, "n_used": 0}

    # Escala calibrada: 1 pt diferencial ≈ 3% probabilidad (NBA empirical)
    p_h_win = 1 / (1 + math.exp(-combined_diff * 0.12))
    p_a_win = 1 - p_h_win

    # ── Blend cuotas ML: el mercado NBA es extremadamente eficiente ──
    # Las líneas de Las Vegas incorporan lesiones de último minuto, viajes,
    # motivación, reportes de práctica — info que ESPN no tiene.
    # Peso mercado: 40% cuando hay odds claras, 25% cuando son cerradas.
    _odd_h = float(odd_h or 0); _odd_a = float(odd_a or 0)
    if _odd_h > 1 and _odd_a > 1:
        _vig_nba = 1/_odd_h + 1/_odd_a
        _mkt_ph  = (1/_odd_h) / _vig_nba
        _mkt_pa  = (1/_odd_a) / _vig_nba
        _mkt_fav = max(_mkt_ph, _mkt_pa)
        # Más peso al mercado cuando hay un favorito claro (>60%)
        _mkt_w = 0.45 if _mkt_fav >= 0.62 else (0.35 if _mkt_fav >= 0.56 else 0.25)
        p_h_win = (1 - _mkt_w) * p_h_win + _mkt_w * _mkt_ph
        p_a_win = 1 - p_h_win

    # ── Blend cuotas O/U: la línea del mercado es el mejor prior disponible ──
    # Si el mercado pone Over/Under con cuota <1.85 (implícita >54%), nuestro
    # modelo debe converger hacia ese lado. Peso 35% al mercado.
    _odd_ov = float(odd_over or 0); _odd_un = float(odd_under or 0)
    if _odd_ov > 1 and _odd_un > 1:
        _vig_ou  = 1/_odd_ov + 1/_odd_un
        _mkt_ov  = (1/_odd_ov) / _vig_ou
        _mkt_un  = (1/_odd_un) / _vig_ou
        _ou_fav  = max(_mkt_ov, _mkt_un)
        _ou_w    = 0.40 if _ou_fav >= 0.58 else 0.30
        p_over   = (1 - _ou_w) * p_over  + _ou_w * _mkt_ov
        p_under  = 1 - p_over

    return {
        "proj":         round(proj, 1),
        "line":         round(line, 1),
        "p_over":       round(p_over, 4),
        "p_under":      round(p_under, 4),
        "p_h_win":      round(p_h_win, 4),
        "p_a_win":      round(p_a_win, 4),
        "h_proj":       round(h_proj, 1),
        "a_proj":       round(a_proj, 1),
        "b2b_h":        b2b_h,
        "b2b_a":        b2b_a,
        "net_h":        round(net_h, 1),
        "net_a":        round(net_a, 1),
        "pace":         round(avg_pace, 1),
        "h_sigma":      round(h_sigma, 1),
        "a_sigma":      round(a_sigma, 1),
        "h_recent_ppg": round(h_recent_ppg, 1),
        "a_recent_ppg": round(a_recent_ppg, 1),
        "pace_delta":   round(pace_delta, 1),
        "foul_adj":     round(foul_adj, 1),
        "h_days_rest":  _rest_h["days"],
        "a_days_rest":  _rest_a["days"],
        "h_net5":       _roll_h.get("net_5"),
        "a_net5":       _roll_a.get("net_5"),
        "h_q4_diff":    _clutch_h.get("q4_diff", 0.0),
        "a_q4_diff":    _clutch_a.get("q4_diff", 0.0),
        "rec":          "OVER 🔥" if p_over>0.54 else ("UNDER ❄️" if p_over<0.46 else "NEUTRAL ⚖️"),
    }

# ══════════════════════════════════════════════════════════
# TENIS DATA
# ══════════════════════════════════════════════════════════
TENNIS_API = "https://api.api-tennis.com/tennis/"

# ── ATP/WTA Rankings reales ──
# Extraídos de la propia tennis API o fallback a lookup table de jugadores conocidos.
# Se cachean 24h — los rankings cambian semanalmente, no diario.
_ATP_RANK_CACHE: dict = {}
_ATP_RANK_DATE: str   = ""

@st.cache_data(ttl=86400, show_spinner=False)
@st.cache_data(ttl=3600, show_spinner=False)
def _fetch_atp_rankings_raw(tour="ATP"):
    """
    Descarga el ranking ATP/WTA actual desde la tennis API.
    Devuelve dict {nombre_normalizado: ranking_int}
    """
    try:
        endpoint = "get_standings" if tour=="ATP" else "get_standings"
        r = requests.get(TENNIS_API, params={
            "method":  "get_standings",
            "APIkey":  TENNIS_API_KEY,
            "tour_key": "2" if tour=="ATP" else "3",  # 2=ATP, 3=WTA
        }, headers=H, timeout=10)
        if r.status_code != 200: return {}
        data = r.json()
        ranks = {}
        for entry in data.get("result", []):
            name = str(entry.get("player_name","")).strip()
            pos  = entry.get("standing_place") or entry.get("rank") or 999
            try: pos = int(pos)
            except: pos = 999
            if name:
                # Normalizar: "Djokovic N." → "djokovic", "Carlos Alcaraz" → "alcaraz"
                parts = name.lower().split()
                for p in parts:
                    if len(p) > 3 and not p.endswith("."):
                        ranks[p] = min(ranks.get(p, 999), pos)
                ranks[name.lower()] = pos
        return ranks
    except:
        return {}

# Rankings reales ATP/WTA — actualizados 7 marzo 2026 (fuente AP / WTA oficial)
