def _resolve_rank(player_name: str, api_ranks: dict) -> int:
    """
    Resuelve el ranking de un jugador:
    1. Busca en rankings en vivo de la API
    2. Fallback a tabla de jugadores conocidos
    3. Fallback a 200 (jugador no top)
    """
    if not player_name or player_name == "?":
        return 200
    name_low = player_name.lower().strip()

    # 1. Exact match en API
    if name_low in api_ranks:
        return api_ranks[name_low]

    # 2. Partial match en API (apellido)
    parts = name_low.split()
    for part in parts:
        if len(part) > 3 and part in api_ranks:
            return api_ranks[part]

    # 3. Known ranks table
    for key, rank in _KNOWN_RANKS.items():
        if key in name_low or name_low in key:
            return rank

    # 4. Partial match en known ranks
    for part in parts:
        if len(part) > 3:
            for key, rank in _KNOWN_RANKS.items():
                if part in key or key in part:
                    return rank

    return 120   # jugador fuera del top conocido — rank conservador


@st.cache_data(ttl=600, show_spinner=False)
def get_tennis_cartelera():
    now  = datetime.now(CDMX)
    hoy  = now.strftime("%Y-%m-%d")
    ayer = (now - timedelta(days=1)).strftime("%Y-%m-%d")
    fin  = (now + timedelta(days=4)).strftime("%Y-%m-%d")
    matches = []
    try:
        r = requests.get(TENNIS_API, params={
            "method":     "get_fixtures",
            "APIkey":     TENNIS_API_KEY,
            "date_start": ayer,   # incluir ayer para partidos finalizados nocturnos
            "date_stop":  fin,
        }, headers=H, timeout=12)
        data = r.json() if r.status_code == 200 else {}
        for ev in data.get("result", []):
            try:
                fecha = ev.get("event_date","")
                hora  = ev.get("event_time","00:00")
                # Convertir hora a CDMX (API devuelve UTC)
                try:
                    utc_t = datetime.strptime(f"{fecha} {hora}", "%Y-%m-%d %H:%M").replace(tzinfo=pytz.UTC)
                    cdmx_t = utc_t.astimezone(CDMX)
                    hora  = cdmx_t.strftime("%H:%M")
                    fecha = cdmx_t.strftime("%Y-%m-%d")  # convertir fecha UTC→CDMX
                except: pass
                if fecha < ayer or fecha > fin: continue
                tour_type   = ev.get("event_type_type","").upper()
                tour_name   = ev.get("tournament_name","").upper()
                league_name = ev.get("league_name","").upper()
                all_text    = tour_type + " " + tour_name + " " + league_name

                # Detectar ITF/Challenger (excluir) — queremos ATP, WTA y Grand Slams
                p1n = ev.get("event_first_player","")
                p2n = ev.get("event_second_player","")
                # Skip doubles: player names contain "/" or "&"
                if "/" in p1n or "/" in p2n: continue
                if "&" in p1n or "&" in p2n: continue  # some APIs use & for doubles pairs
                if any(x in all_text for x in ["ITF","JUNIOR","WHEELCHAIR","EXHIBITION","DOUBLES","DOUBLE","DBL"]):
                    continue
                # Skip if either player name has multiple last names separated by / or looks like pair
                if len(p1n.split("/")) > 1 or len(p2n.split("/")) > 1: continue

                # Determinar tour por nombre del torneo + tipo
                if "WTA" in all_text:
                    tour = "WTA"
                elif "ATP" in all_text or "GRAND SLAM" in all_text or "MASTERS" in all_text:
                    tour = "ATP"
                elif any(x in all_text for x in ["CHALLENGER","FUTURES"]):
                    continue  # skip challengers
                else:
                    # Si es femenino por jugadoras conocidas o tournament_type = "WTA"
                    ev_gender = ev.get("event_type","").upper()
                    tour = "WTA" if "WTA" in ev_gender or "WOMEN" in ev_gender else "ATP"
                    # Sin contexto — incluir igual, clasificar como ATP por defecto
                ev_status   = str(ev.get("event_status","")).lower()
                ev_finished = str(ev.get("event_final","0"))
                is_live     = ev.get("event_live","0") == "1"
                # Retiros y walkovers también son partidos terminados
                _retired_keywords = ["finished","ft","final","completed","awarded",
                                     "retired","ret.","walkover","w/o","walkover","withdraw",
                                     "abandoned","cancelled","default","disqualified"]
                is_post = (ev_finished == "1" or
                           any(x in ev_status for x in _retired_keywords))
                is_walkover = any(x in ev_status for x in ["retired","ret.","walkover","w/o","withdraw"])
                t_state = "post" if is_post else ("in" if is_live else "pre")
                # Sanity check: si el partido dice "pre" pero la hora ya pasó > 3h, marcar post
                if t_state == "pre" and fecha == datetime.now(CDMX).strftime("%Y-%m-%d"):
                    try:
                        _ph, _pm = int(hora.split(":")[0]), int(hora.split(":")[1])
                        _now_cdmx_min = datetime.now(CDMX).hour*60 + datetime.now(CDMX).minute
                        if (_ph*60+_pm) < _now_cdmx_min - 180:  # más de 3h atrás
                            t_state = "post"  # marcar como finalizado
                    except: pass
                # Score for tennis
                sc1 = str(ev.get("event_first_player_result",""))
                sc2 = str(ev.get("event_second_player_result",""))
                # Si hay retiro, el ganador = quien tiene más sets (o sc1 si ambos 0)
                # Marcamos con retiro para mostrar en UI
                p1_name = ev.get("event_first_player","?").strip()
                p2_name = ev.get("event_second_player","?").strip()
                # Clean "vs" artifacts: if name contains " vs " split it
                if " vs " in p1_name:
                    _parts = p1_name.split(" vs ", 1)
                    p1_name = _parts[0].strip()
                    if p2_name in ("?", "") and len(_parts) > 1:
                        p2_name = _parts[1].strip()
                # Normalize: "Last, First" → "First Last"
                for _pv, _pn in [(p1_name, "p1"), (p2_name, "p2")]:
                    if "," in _pv:
                        _parts2 = _pv.split(",", 1)
                        if _pn == "p1": p1_name = f"{_parts2[1].strip()} {_parts2[0].strip()}"
                        else: p2_name = f"{_parts2[1].strip()} {_parts2[0].strip()}"
                # Try to get real rank from API event fields first
                r1_api = ev.get("event_first_player_ranking") or ev.get("player1_rank") or 0
                r2_api = ev.get("event_second_player_ranking") or ev.get("player2_rank") or 0
                try: r1_api = int(r1_api)
                except: r1_api = 0
                try: r2_api = int(r2_api)
                except: r2_api = 0
                # If API didn't give rank, resolve from rankings table
                if r1_api <= 0 or r1_api >= 999:
                    _api_r = _fetch_atp_rankings_raw(tour)
                    r1_api = _resolve_rank(p1_name, _api_r)
                if r2_api <= 0 or r2_api >= 999:
                    _api_r = _fetch_atp_rankings_raw(tour)
                    r2_api = _resolve_rank(p2_name, _api_r)
                matches.append({
                    "id":    str(ev.get("event_key","")),
                    "p1":    p1_name, "home": p1_name,
                    "p2":    p2_name, "away": p2_name,
                    "rank1": r1_api,
                    "rank2": r2_api,
                    "tour":  tour,
                    "torneo": ev.get("tournament_name",""),
                    "hora":  hora,
                    "fecha": fecha,
                    "state": t_state,
                    "score_p1": sc1, "score_p2": sc2,
                    "score_h":  (int(sc1) if str(sc1).isdigit() else
                                 # Parsear "7-6 6-3" → contar cuántos sets ganó p1
                                 len([s for s in str(sc1).split() if "-" in s
                                      and int(s.split("-")[0]) > int(s.split("-")[1])])
                                 if sc1 and str(sc1).strip() else 0),
                    "score_a":  (int(sc2) if str(sc2).isdigit() else
                                 len([s for s in str(sc2).split() if "-" in s
                                      and int(s.split("-")[0]) > int(s.split("-")[1])])
                                 if sc2 and str(sc2).strip() else 0),
                    "is_walkover": is_walkover,
                    "walkover_note": "RET." if is_walkover else "",
                    "odd_1": 0.0, "odd_2": 0.0,
                    "_sport": "tennis",
                    "league": f"{tour} · {ev.get('tournament_name','')}",
                    "liga":   f"{tour} · {ev.get('tournament_name','')}",
                })
            except: continue
    except Exception as e:
        pass
    _now3 = datetime.now(CDMX)
    matches = _sort_cartelera(matches, _now3.strftime("%Y-%m-%d"), int(_now3.strftime("%H")))
    return matches


@st.cache_data(ttl=3600, show_spinner=False)
def _tennis_h2h(p1_name: str, p2_name: str) -> dict:
    """
    H2H directo entre dos jugadores desde la API de tenis.
    Retorna: {p1_wins, p2_wins, total, p1_h2h_rate, advantage}
    La variable más predictiva en tenis después del ranking.
    Ref: Barnett & Clarke 2005 — H2H como corrector del ranking.
    """
    default = {"p1_wins": 0, "p2_wins": 0, "total": 0,
               "p1_h2h_rate": 0.5, "advantage": 0.0}
    try:
        r = requests.get(TENNIS_API, params={
            "method":   "get_H2H",
            "APIkey":   TENNIS_API_KEY,
            "player_1": p1_name,
            "player_2": p2_name,
        }, headers=H, timeout=6)
        if r.status_code != 200: return default
        data = r.json().get("result", {})
        matches = data.get("player_1_vs_player_2", [])
        if not matches: return default

        p1_wins = p2_wins = 0
        for m in matches[:20]:   # últimos 20 máximo
            w = m.get("event_winner", "")
            if not w: continue
            if p1_name.split()[-1].lower() in w.lower():
                p1_wins += 1
            elif p2_name.split()[-1].lower() in w.lower():
                p2_wins += 1

        total = p1_wins + p2_wins
        if total < 2: return default   # muy poco historial

        p1_rate = p1_wins / total
        # Advantage: cuánto ajustar sobre el prior del modelo
        # 5+ partidos con 70%+ → fuerte ventaja
        advantage = (p1_rate - 0.5) * min(1.0, total / 8)
        return {
            "p1_wins":      p1_wins,
            "p2_wins":      p2_wins,
            "total":        total,
            "p1_h2h_rate":  round(p1_rate, 3),
            "advantage":    round(advantage, 3),
        }
    except:
        return default


@st.cache_data(ttl=3600, show_spinner=False)
def _tennis_surface_form(player_name: str, surface: str, n: int = 10) -> dict:
    """
    Forma reciente del jugador en la superficie específica.
    Filtra get_last_results por superficie — más relevante que ranking general.
    Ej: Nadal en arcilla vs Nadal en hierba son distintos jugadores.
    Retorna: {wins, losses, win_rate, n_games, surface_adj}
      surface_adj: ajuste de prob basado en rendimiento real en esta superficie
    """
    default = {"wins": 0, "losses": 0, "win_rate": 0.5,
               "n_games": 0, "surface_adj": 0.0}
    try:
        r = requests.get(TENNIS_API, params={
            "method":  "get_last_results",
            "APIkey":  TENNIS_API_KEY,
            "player":  player_name,
            "count":   30,
        }, headers=H, timeout=6)
        if r.status_code != 200: return default
        results = r.json().get("result", [])
        if not results: return default

        surf_lower = surface.lower()
        # Mapeo de nombres de superficie
        surf_aliases = {
            "hard":  ["hard", "dura", "indoor hard", "outdoor hard"],
            "clay":  ["clay", "tierra", "arcilla"],
            "grass": ["grass", "hierba", "césped"],
        }
        aliases = surf_aliases.get(surf_lower, [surf_lower])

        wins = losses = 0
        for m in results:
            court = m.get("event_surface", m.get("tournament_surface", "")).lower()
            if not any(a in court for a in aliases):
                continue   # superficie distinta, skip
            winner = m.get("event_winner", "")
            if not winner: continue
            if player_name.split()[-1].lower() in winner.lower():
                wins += 1
            else:
                losses += 1
            if wins + losses >= n: break

        total = wins + losses
        if total < 3: return default

        win_rate = wins / total
        # Ajuste sobre prior 0.5: rendimiento real en superficie
        # Con n=3-5: peso 30%, n=6-9: peso 50%, n=10+: peso 70%
        weight = 0.30 if total < 6 else (0.50 if total < 10 else 0.70)
        surface_adj = (win_rate - 0.5) * weight
        return {
            "wins":        wins,
            "losses":      losses,
            "win_rate":    round(win_rate, 3),
            "n_games":     total,
            "surface_adj": round(surface_adj, 3),
        }
    except:
        return default


@st.cache_data(ttl=1800, show_spinner=False)
def _tennis_tournament_fatigue(player_name: str, torneo: str) -> dict:
    """
    Fatiga del torneo actual — cuántos partidos lleva el jugador esta semana.
    3+ partidos en 4 días = fatiga real (Grand Slams en 5 sets especialmente).
    Retorna: {matches_in_tourney, fatigue_factor, days_since_last}
      fatigue_factor: multiplicador de prob (< 1.0 si fatigado)
    """
    default = {"matches_in_tourney": 0, "fatigue_factor": 1.0, "days_since_last": 3}
    try:
        r = requests.get(TENNIS_API, params={
            "method":  "get_last_results",
            "APIkey":  TENNIS_API_KEY,
            "player":  player_name,
            "count":   10,
        }, headers=H, timeout=5)
        if r.status_code != 200: return default
        results = r.json().get("result", [])
        if not results: return default

        from datetime import datetime as _dt, timedelta as _td
        today = _dt.now().date()
        torneo_lower = torneo.lower()[:20]

        # Contar partidos en el mismo torneo en los últimos 10 días
        matches_in_tourney = 0
        days_since_last = 3
        for i, m in enumerate(results):
            t_name = m.get("tournament_name", "").lower()[:20]
            fecha_str = m.get("event_date", "")
            try:
                fecha = _dt.strptime(fecha_str[:10], "%Y-%m-%d").date()
                days_ago = (today - fecha).days
            except:
                days_ago = 99

            if days_ago > 14: break   # más de 2 semanas, ya no es relevante

            # Mismo torneo o torneo reciente (puede haber cambio de nombre)
            same_tourney = (torneo_lower in t_name or t_name in torneo_lower
                           or (len(torneo_lower) > 5 and torneo_lower[:6] in t_name))
            if same_tourney and days_ago <= 10:
                matches_in_tourney += 1
                if i == 0: days_since_last = days_ago

        # Factor de fatiga:
        # 0-1 partidos en torneo → fresco → 1.00
        # 2 partidos → normal → 1.00
        # 3 partidos → leve fatiga → 0.97
        # 4 partidos → moderada → 0.94  (semis en GS)
        # 5+ partidos → severa → 0.90   (final en GS)
        fatigue_map = {0: 1.00, 1: 1.00, 2: 1.00, 3: 0.97, 4: 0.94}
        fatigue_factor = fatigue_map.get(matches_in_tourney, 0.90)

        return {
            "matches_in_tourney": matches_in_tourney,
            "fatigue_factor":     round(fatigue_factor, 3),
            "days_since_last":    days_since_last,
        }
    except:
        return default


def tennis_model(rank1, rank2, odd_1=0, odd_2=0, surface="hard",
                 p1_name="", p2_name="", torneo=""):
    """
    Weibull+Markov (Klaassen&Magnus 2001) — modelo base.
    v2: blend con H2H directo + forma en superficie + fatiga del torneo.
    Nuevas señales solo se usan si hay datos suficientes (n mínimo por función).
    """
    try:
        wm = weibull_match_prob(rank1, rank2, odd_1, odd_2, surface)
        p1, p2 = wm["p1"], wm["p2"]
    except:
        r1=max(1,rank1); r2=max(1,rank2); _ls=math.log(r2)+math.log(r1)
        p1_rank=math.log(r2)/_ls if _ls>0 else 0.5
        p1 = 0.5*p1_rank+0.5*(1/odd_1)/(1/odd_1+1/odd_2) if odd_1>1 and odd_2>1 else p1_rank
        p2 = 1-p1

    # ── H2H directo ──
    _h2h_adj = 0.0
    _h2h_data = {}
    if p1_name and p2_name:
        try:
            _h2h_data = _tennis_h2h(p1_name, p2_name)
            # advantage ya está normalizado por número de partidos
            # Peso máximo 35% (si H2H tiene 8+ partidos)
            _h2h_weight = min(0.35, _h2h_data["total"] / 8 * 0.35)
            _h2h_adj = _h2h_data["advantage"] * _h2h_weight * 2
        except: pass

    # ── Forma en superficie ──
    _surf_adj = 0.0
    _surf1 = _surf2 = {}
    if p1_name and p2_name:
        try:
            _surf1 = _tennis_surface_form(p1_name, surface)
            _surf2 = _tennis_surface_form(p2_name, surface)
            # Diferencial de rendimiento en esta superficie
            _surf_adj = _surf1["surface_adj"] - _surf2["surface_adj"]
        except: pass

    # ── Fatiga del torneo ──
    _fat1 = _fat2 = {"fatigue_factor": 1.0, "matches_in_tourney": 0}
    if p1_name and torneo:
        try:
            _fat1 = _tennis_tournament_fatigue(p1_name, torneo)
            _fat2 = _tennis_tournament_fatigue(p2_name, torneo)
        except: pass

    # ── Blend final ──
    # Base: Weibull (ranking + superficie + odds)
    # Ajustes aditivos independientes sobre p1
    p1_adj = p1 + _h2h_adj + _surf_adj

    # Fatiga: multiplicar la "ventaja" de cada jugador por su factor
    # Si p1 está más fatigado que p2 → su ventaja sobre 0.5 se reduce
    if _fat1["fatigue_factor"] != 1.0 or _fat2["fatigue_factor"] != 1.0:
        fat_ratio = _fat1["fatigue_factor"] / max(0.85, _fat2["fatigue_factor"])
        # fat_ratio < 1 → p1 más cansado → acercar a 0.5
        p1_adj = 0.5 + (p1_adj - 0.5) * fat_ratio

    # Clamp y normalizar
    p1_final = max(0.05, min(0.95, p1_adj))
    p2_final = 1 - p1_final

    edge_1 = round(p1_final - (1/odd_1), 3) if odd_1 > 1 else 0
    edge_2 = round(p2_final - (1/odd_2), 3) if odd_2 > 1 else 0
    conf = "💎 DIAMANTE" if max(p1_final,p2_final) > 0.68 else (
           "🔥 ALTA"    if max(p1_final,p2_final) > 0.58 else "⚡ MEDIA")

    return {
        "p1":           round(p1_final, 3),
        "p2":           round(p2_final, 3),
        "p1_base":      round(p1, 3),
        "edge_1":       edge_1,
        "edge_2":       edge_2,
        "conf":         conf,
        "h2h_adj":      round(_h2h_adj, 3),
        "surf_adj":     round(_surf_adj, 3),
        "h2h_total":    _h2h_data.get("total", 0),
        "fat1":         _fat1.get("matches_in_tourney", 0),
        "fat2":         _fat2.get("matches_in_tourney", 0),
        "surf_wr1":     _surf1.get("win_rate", 0.5),
        "surf_wr2":     _surf2.get("win_rate", 0.5),
    }


def tennis_expert_analysis(p1_name, p2_name, rank1, rank2, odd_1, odd_2,
                            surface, torneo, model_p1=0.5, model_p2=0.5):
    """Wrapper con caché en disco — llama al análisis real si no hay resultado cacheado."""
    import hashlib, json as _j, os as _os, time as _t
    # Clave basada solo en jugadores + superficie + torneo (no en probs flotantes)
    key = hashlib.md5(f"{p1_name}|{p2_name}|{surface}|{torneo}".encode()).hexdigest()[:16]
    today = __import__('datetime').datetime.now().strftime("%Y-%m-%d")
    cache_path = f"/tmp/tenis_ai_{key}_{today}.json"
    # Intentar leer del disco primero
    if _os.path.exists(cache_path):
        try:
            with open(cache_path) as f: return _j.load(f)
        except: pass
    result = _tennis_expert_analysis_raw(p1_name, p2_name, rank1, rank2,
                                          odd_1, odd_2, surface, torneo, model_p1, model_p2)
    if result:
        try:
            with open(cache_path, 'w') as f: _j.dump(result, f)
        except: pass
    return result

def _tennis_expert_analysis_raw(p1_name, p2_name, rank1, rank2, odd_1, odd_2,
                            surface, torneo, model_p1, model_p2):
    """
    Einstein experto en tenis:
    - Analiza H2H real de ambos jugadores
    - Forma reciente en esta superficie específica
    - Historial en este torneo
    - Lesiones conocidas, fatiga
    - Da probabilidades REALES, no siempre 58/42
    """
    if not ANTHROPIC_API_KEY: return None
    prompt = f"""Eres EINSTEIN TENIS, el analista de tenis más avanzado del mundo.
Analiza en PROFUNDIDAD este partido ATP/WTA y da probabilidades REALES.

PARTIDO: {p1_name} vs {p2_name}
TORNEO: {torneo} — SUPERFICIE: {surface.upper()}
RANKING: {p1_name} #{rank1 if rank1<900 else "?"} vs {p2_name} #{rank2 if rank2<900 else "?"}
MOMIOS: {f"{p1_name} @{odd_1:.2f}" if odd_1>1 else "N/D"} / {f"{p2_name} @{odd_2:.2f}" if odd_2>1 else "N/D"}
MODELO WEIBULL BASE: {p1_name} {model_p1*100:.1f}% / {p2_name} {model_p2*100:.1f}%

ANALIZA EXHAUSTIVAMENTE:
1. H2H histórico entre estos dos jugadores (¿cuántos partidos? ¿quién domina? ¿en qué superficie?)
2. Forma reciente de {p1_name}: últimos 5-10 torneos, W/L, superficie actual, lesiones
3. Forma reciente de {p2_name}: últimos 5-10 torneos, W/L, superficie actual, lesiones  
4. Historial específico en {torneo} de ambos
5. Estadísticas en {surface}: % victorias, profundidad de torneo habitual
6. Variables ocultas: fatiga (cuántos sets esta semana), altura del torneo, temperatura
7. Motivación: ¿quién NECESITA más esta victoria para ranking/clasificación?
8. Estilo de juego: ¿el surface favorece más a uno? (servidor en hierba, defensor en tierra)

REGLAS CRÍTICAS:
- Si hay clara diferencia de nivel: da probabilidades reales (70/30, 75/25, etc.)
- Si es parejo de verdad: 55/45 o 52/48 está bien
- NO des siempre 58/42 — eso es inventar, no analizar
- Si un jugador viene de lesión o jugó mucho: refléjalo en la prob
- Basa el % final en los datos reales que conoces

RESPONDE SOLO JSON:
{{
  "p1_pct": <float 0-100, prob real {p1_name}>,
  "p2_pct": <float 0-100, prob real {p2_name}>,
  "h2h_resumen": "<H2H: X-Y a favor de ?, en qué superficie domina>",
  "forma_p1": "<últimos 5 resultados, lesiones, superficie>",
  "forma_p2": "<últimos 5 resultados, lesiones, superficie>",
  "factor_decisivo": "<qué factor inclina la balanza>",
  "surface_ventaja": "<quién se beneficia más de {surface}>",
  "resumen": "<2-3 líneas: análisis concreto con datos reales>",
  "confianza_analisis": "<alta/media/baja>",
  "edge_p1": <float, edge vs momio>,
  "edge_p2": <float, edge vs momio>
}}"""
    try:
        r = type("_R",(),{"status_code":200,"json":lambda s=None:{"content":[{"type":"text","text":_gemini(prompt,use_search=True,max_tokens=900)}]}})()  # gemini
        if r.status_code!=200: return None
        raw = r.json()["content"][0]["text"].strip().replace("```json","").replace("```","").strip()
        if "{" in raw: raw=raw[raw.find("{"):raw.rfind("}")+1]
        import json as _jt; d = _jt.loads(raw)
        p1 = max(5,min(95,float(d.get("p1_pct",model_p1*100))))/100
        p2 = 1-p1
        conf = "💎 DIAMANTE" if max(p1,p2)>0.68 else ("🔥 ALTA" if max(p1,p2)>0.62 else "⚡ MEDIA")
        return {
            "p1": round(p1,3), "p2": round(p2,3), "conf": conf,
            "h2h": d.get("h2h_resumen",""), "forma_p1": d.get("forma_p1",""),
            "forma_p2": d.get("forma_p2",""), "factor": d.get("factor_decisivo",""),
            "surface_adv": d.get("surface_ventaja",""), "resumen": d.get("resumen",""),
            "confianza": d.get("confianza_analisis","media"),
            "edge_p1": float(d.get("edge_p1",0)), "edge_p2": float(d.get("edge_p2",0)),
        }
    except: return None


def _kr_edge(prob, odd):
    """Edge real vs casas. Sin cuota: edge vs 50-50."""
    if odd > 1.01:
        return prob - (1.0 / odd)
    return prob - 0.50


def _kr_kelly(prob, odd, cap=0.08):
    """Fracción Kelly, cappada al 8%."""
    if odd <= 1.01 or prob <= 0:
        return 0.0
    k = (prob * (odd - 1) - (1 - prob)) / (odd - 1)
    return round(max(0.0, min(k, cap)) * 100, 1)


def _kr_conf(prob, edge, spread_pp):
    """Devuelve (emoji, label, color) de confianza."""
    penalizado = spread_pp > _KR_CONFLICT_PP
    if prob >= _KR_DIAMOND_PROB and edge >= 0.07 and not penalizado:
        return "💎", "DIAMANTE", "#FFD700"
    if prob >= _KR_GOLD_PROB and edge >= _KR_MIN_EDGE and not penalizado:
        return "🔥", "ALTA",     "#00ff88"
    if prob >= 0.57 and not penalizado:
        return "⚡", "MEDIA",    "#00ccff"
    if prob >= 0.52:
        return "⚠️", "BAJA",     "#ff9500"
    return "🔻", "NO APOSTAR",  "#ff4444"



