def _king_rongo_scan_all(matches_fut, nba_games, ten_matches, pick_history=None):
    if pick_history is None:
        pick_history = st.session_state.get("pick_history", [])
    """
    Corre TODOS los modelos sobre todos los partidos pre-match.
    Retorna: (el_pick, contradicciones, todos_ordenados)
    """
    candidates = []

    # ── PRE-FETCH get_form en paralelo — evita llamadas secuenciales ──────
    _fut_slice = [m for m in (matches_fut or [])[:12] if m.get("state","pre") != "post"]
    _form_cache_kr = {}
    try:
        import concurrent.futures as _cf_kr_form
        _form_args = []
        for _m in _fut_slice:
            _hid = _m.get("home_id",""); _aid = _m.get("away_id",""); _sl = _m.get("slug","")
            if _hid and _sl: _form_args.append((_hid, _sl))
            if _aid and _sl: _form_args.append((_aid, _sl))
        _form_args = list(dict.fromkeys(_form_args))  # dedup
        with _cf_kr_form.ThreadPoolExecutor(max_workers=min(len(_form_args), 20)) as _fx:
            _ffmap = {_fx.submit(get_form, a[0], a[1]): a for a in _form_args}
            for _ff in _cf_kr_form.as_completed(_ffmap, timeout=15):
                _fa = _ffmap[_ff]
                try: _form_cache_kr[_fa] = _ff.result() or []
                except: _form_cache_kr[_fa] = []
    except: pass

    # ── ⚽ FÚTBOL ─────────────────────────────────────────────────────────
    try:
        for m in _fut_slice:
            # KR: solo partidos desde ahora (no pasados)
            _kr_state = m.get('state','pre')
            if _kr_state == 'post': continue
            # Fútbol en vivo: filtrar por minuto real (independiente de hora)
            if _kr_state == 'in':
                _min_kr = int(m.get('minute', 0) or 0)
                if _min_kr < 5 or _min_kr >= 70: continue  # min<5 aún no empieza / min>=70 casi terminado
            # Pre-partido: solo partidos que empiezan desde ahora en adelante
            if _kr_state != 'in':
                _hora_kr = m.get('hora','') or ''
                if ':' not in _hora_kr:
                    continue  # sin hora → no incluir
                try:
                    from datetime import datetime as _dt_kr
                    import pytz as _pz_kr
                    _now_kr = _dt_kr.now(_pz_kr.timezone('America/Mexico_City'))
                    _hh_kr,_mm_kr = int(_hora_kr.split(':')[0]),int(_hora_kr.split(':')[1])
                    _gdt_kr = _now_kr.replace(hour=_hh_kr,minute=_mm_kr,second=0,microsecond=0)
                    if (_now_kr - _gdt_kr).total_seconds() > 0:
                        continue  # ya empezó (estado pre pero hora pasada) → skip
                except:
                    continue  # error → skip por seguridad
            # King Rongo analiza todos los partidos del día (pre, in, post)
            try:
                home_id = m.get("home_id",""); away_id = m.get("away_id",""); slug = m.get("slug","")
                if not home_id or not slug: continue
                if slug in _UEFA_CUP_SLUGS:
                    hf = _form_cache_kr.get((home_id, slug)) or get_form_domestic(home_id, slug) or []
                    af = _form_cache_kr.get((away_id, slug)) or get_form_domestic(away_id, slug) or []
                    # Añadir resultados UEFA si existen
                    for _ug, _ulist, _uid in [(get_form(home_id, slug), hf, home_id),
                                               (get_form(away_id, slug), af, away_id)]:
                        _ud = {g["date"] for g in _ulist}
                        for g in _ug:
                            if g["date"] not in _ud: _ulist.append(g)
                        _ulist.sort(key=lambda x: x["date"], reverse=True)
                    hf = hf[:15]; af = af[:15]
                else:
                    hf = _form_cache_kr.get((home_id, slug)) if (home_id, slug) in _form_cache_kr else (get_form(home_id, slug) or [])
                    af = _form_cache_kr.get((away_id, slug)) if (away_id, slug) in _form_cache_kr else (get_form(away_id, slug) or [])
                if slug in _UEFA_CUP_SLUGS:
                    hxg = _cup_enriched_xg(m, True,  hf, af)
                    axg = _cup_enriched_xg(m, False, hf, af)
                else:
                    hxg = xg_weighted(hf, True,  1/m["odd_h"] if m.get("odd_h",0)>1 else 0, slug=slug, team_id=m.get("home_id",""), team_name=m.get("home","")) \
                          if hf else _cup_enriched_xg(m, True,  hf, af)
                    axg = xg_weighted(af, False, 1/m["odd_a"] if m.get("odd_a",0)>1 else 0, slug=slug, team_id=m.get("away_id",""), team_name=m.get("away","")) \
                          if af else _cup_enriched_xg(m, False, hf, af)
                # ── Ajuste defensivo cruzado con ga de team_stats ──
                # Si el equipo rival tiene ga bajo (defensa sólida), el atacante debería generar menos xG.
                # Ej: si LAFC (ga=1.18) vs liga promedio MLS (ga≈1.55), Alajuelense debe reducir su xG.
                try:
                    _lh_def = _LEAGUE_HISTORICAL.get(slug, {})
                    _ts_def = _lh_def.get("team_stats", {})
                    _avg_ga_league = _lh_def.get("avg_goals", 3.0) / 2  # promedio por equipo
                    def _get_ga(tname):
                        _tn = (tname or "").strip().lower()
                        _match = next((v for k, v in _ts_def.items() if k.lower() == _tn or k.lower() in _tn or _tn in k.lower()), None)
                        return float(_match["ga"]) if _match and "ga" in _match else None
                    _ga_home = _get_ga(m.get("home",""))  # cuánto recibe el local (rival del visita)
                    _ga_away = _get_ga(m.get("away",""))  # cuánto recibe el visita (rival del local)
                    # Si el local concede menos que el promedio → reducir axg (visitante atacando al local)
                    if _ga_home is not None and _avg_ga_league > 0:
                        _def_ratio_h = _ga_home / _avg_ga_league  # <1 = mejor defensa que promedio
                        axg = round(max(0.20, axg * (0.70 + 0.30 * _def_ratio_h)), 3)
                    # Si el visita concede menos que el promedio → reducir hxg
                    if _ga_away is not None and _avg_ga_league > 0:
                        _def_ratio_a = _ga_away / _avg_ga_league
                        hxg = round(max(0.20, hxg * (0.70 + 0.30 * _def_ratio_a)), 3)
                except: pass

                # ══ FULL INTEL KR — 6 fuentes en paralelo ══
                # FBref directo + Sofascore alineaciones + Sharp/Pinnacle + Arbitro + AltMkts
                # Understat/PPDA primero (rapido, solo Europa), luego Full Intel en paralelo.
                _fi = {}; _rxg_source = ""; _ou_signal_kr = "neutral"
                _injury_h_delta_kr = 0.0; _injury_a_delta_kr = 0.0
                try:
                    # Paso 1: Understat/PPDA
                    _rxg = _fetch_real_xg_football(m.get("home",""), m.get("away",""), slug)
                    if _rxg.get("confidence") in ("alta","media"):
                        if _rxg.get("hxg_real") is not None:
                            hxg = round(0.60*hxg + 0.40*_rxg["hxg_real"], 3)
                        if _rxg.get("axg_real") is not None:
                            axg = round(0.60*axg + 0.40*_rxg["axg_real"], 3)
                        if _rxg.get("hxga_real") is not None:
                            axg = max(0.20, axg + (_rxg["hxga_real"]-1.2)*0.08)
                        if _rxg.get("ppda_h") and _rxg["ppda_h"] < 8: hxg = min(3.5,hxg*1.06)
                        if _rxg.get("ppda_a") and _rxg["ppda_a"] < 8: axg = min(3.5,axg*1.05)
                    _injury_h_delta_kr = _rxg.get("injury_h_delta", 0.0)
                    _injury_a_delta_kr = _rxg.get("injury_a_delta", 0.0)
                    _ou_signal_kr = _rxg.get("ou_signal","neutral")
                    hxg = max(0.20, hxg + _injury_h_delta_kr*0.5)
                    axg = max(0.20, axg + _injury_a_delta_kr*0.5)
                    # Paso 2: Full Intel (FBref directo + Sofascore + Sharp + Arbitro + AltMkts)
                    _fi = _fetch_full_intel(
                        m.get("home",""), m.get("away",""), slug,
                        hxg=hxg, axg=axg, ph=0.45, pd=0.27, pa=0.28,
                        match_date=m.get("fecha","")
                    )
                    hxg = max(0.20, hxg + _fi.get("xg_adj_h", 0.0))
                    axg = max(0.20, axg + _fi.get("xg_adj_a", 0.0))
                    _ou_total_adj = _fi.get("ou_adj", 0.0)
                    if _ou_total_adj > 0.02:  _ou_signal_kr = "over"
                    elif _ou_total_adj < -0.02: _ou_signal_kr = "under"
                    _rxg_source = _fi.get("source_summary","") or _rxg.get("source_txt","")
                except: pass
                # ── Ajuste xG por tabla+GD ANTES del ensemble ──
                _tbl_pre_kr = {}
                try:
                    if slug: _tbl_pre_kr = _tabla_posicion_delta(m.get("home",""), m.get("away",""), slug)
                except: pass
                if _tbl_pre_kr.get("pos_h", 0) > 0:
                    _xg_tbl_adj = _tbl_pre_kr["delta_h"] * 0.25
                    hxg = max(0.30, hxg + _xg_tbl_adj)
                    axg = max(0.30, axg - _xg_tbl_adj)
                h2h = get_h2h(home_id, away_id, slug, m.get("home","?"), m.get("away","?"))
                h2s = h2h_stats(h2h, m.get("home","?"), m.get("away","?"))
                mc  = ensemble_football(hxg, axg, h2s, hf, af,
                                        m["home_id"], m["away_id"],
                                        odd_h=m.get("odd_h",0),
                                        odd_a=m.get("odd_a",0),
                                        odd_d=m.get("odd_d",0),
                                        slug=m.get("slug",""))
                dp  = diamond_engine(mc, h2s, hf, af, match=m)

                # ── Modelo exclusivo KR: Dixon-Coles bivariado ──
                try:
                    _dc = _kr_dixon_coles(hxg, axg, m.get("odd_h",0), m.get("odd_a",0), m.get("odd_d",0))
                    _dc_ph = _dc["ph"]; _dc_pa = _dc["pa"]; _dc_pd = _dc["pd"]
                except:
                    _dc_ph = 0; _dc_pa = 0; _dc_pd = 0

                # ── Blend ensemble + Dixon-Coles (KR usa ambos) ──
                _ph_base = dp["ph"]; _pa_base = dp["pa"]
                _ph = 0.70*_ph_base + 0.30*_dc_ph if _dc_ph>0 else _ph_base
                _pa = 0.70*_pa_base + 0.30*_dc_pa if _dc_pa>0 else _pa_base
                _pd   = mc.get("pd", max(0, 1-_ph-_pa))
                _o25  = mc["o25"]; _aa = mc["btts"]
                _o15  = mc.get("o15", min(0.90, _o25+0.18))
                _1xm  = min(0.82, _ph+0.12); _2xm = min(0.78, _pa+0.12)
                _do_h = min(0.95, _ph+_pd); _do_a = min(0.95, _pa+_pd)
                # Partido equilibrado si xG similares
                _xg_gap_kr = abs(hxg - axg)
                _xg_total_kr = hxg + axg
                _eq_kr = _xg_gap_kr < 0.55
                _muy_of_kr = _xg_total_kr >= 3.0
                _of_med_kr = 2.5 <= _xg_total_kr < 3.0

                _home = m.get("home","?"); _away = m.get("away","?")
                _hn = _home[:14]; _an = _away[:14]

                # ── King Rongo: variables extendidas desde mc50k ──
                _gcm_h_kr  = float(mc.get("gcm_h",0) or min(0.95, _ph*1.18+_pd*0.35))
                _gcm_a_kr  = float(mc.get("gcm_a",0) or min(0.95, _pa*1.18+_pd*0.35))
                _h_o05_kr  = float(mc.get("h_o05",0)); _h_u05_kr = float(mc.get("h_u05",0))
                _h_o15_kr  = float(mc.get("h_o15",0)); _h_u15_kr = float(mc.get("h_u15",0))
                _a_o05_kr  = float(mc.get("a_o05",0)); _a_u05_kr = float(mc.get("a_u05",0))
                _a_o15_kr  = float(mc.get("a_o15",0)); _a_u15_kr = float(mc.get("a_u15",0))
                _u25_kr    = 1 - _o25
                _o35_kr    = float(mc.get("o35",0))
                _u35_kr    = float(mc.get("u35", max(0, 1-_o35_kr)))

                # ── Cheat Sheet de liga: ajustar probs con datos históricos reales ──
                _kr_slug  = m.get("slug","")
                _kr_lst   = get_league_stats(_kr_slug)
                _kr_lo25  = _kr_lst["o25_rate"]
                _kr_uval  = _kr_lst.get("under_value", False)
                _kr_delta = _kr_lst.get("delta", 0.0)
                _kr_goals = _kr_lst.get("avg_goals", 2.65)
                # Ajuste suave O/U según base histórica (max ±3.5%)
                _kr_ou_adj = max(-0.035, min(0.035, (_kr_lo25 - 0.51) * 0.22))
                _o25    = max(0.06, min(0.91, _o25    + _kr_ou_adj))
                _u25_kr = max(0.06, min(0.91, 1 - _o25))
                _o35_kr = max(0.04, min(0.78, _o35_kr + _kr_ou_adj * 0.65))
                _u35_kr = max(0.06, min(0.91, 1 - _o35_kr))
                if _kr_uval:
                    _u25_kr = min(0.87, _u25_kr + 0.022)
                    _o25    = max(0.09, 1 - _u25_kr)
                if _kr_delta > 0.05:
                    _o25    = min(0.90, _o25 + 0.012)
                    _u25_kr = max(0.07, 1 - _o25)
                elif _kr_delta < -0.02:
                    _o25    = max(0.07, _o25 - 0.014)
                    _u25_kr = max(0.07, 1 - _o25)
                _kr_hist_confirms_over  = _kr_lo25 >= 0.54 and _o25 >= 0.52
                _kr_hist_confirms_under = _kr_uval and _u25_kr >= 0.50

                # ── Tabla completa de mercados King Rongo — selección por mayor prob ──
                _kr_all_mkts = [
                    (f"🏠 {_hn} gana",           _ph,       m.get("odd_h",0), "1X2"),
                    (f"✈️ {_an} gana",           _pa,       m.get("odd_a",0), "1X2"),
                    ("🤝 Empate",                 _pd,       m.get("odd_d",0), "1X2"),
                    (f"🔵 DO {_hn}",             _do_h,     1.30,             "DO"),
                    (f"🟣 DO {_an}",             _do_a,     1.50,             "DO"),
                    ("⚽ Over 1.5 Total",         _o15,      1.35,             "OU"),
                *([(f"🔥 {_hn} +1.5 goles", float(mc.get("h_o15_team",0)), 2.10, "TG_HOT")] if mc.get("h_hot") else []),
                *([(f"🔥 {_an} +1.5 goles", float(mc.get("a_o15_team",0)), 2.30, "TG_HOT")] if mc.get("a_hot") else []),
                    ("⚽ Over 2.5",              _o25,      m.get("odd_o25",0) or m.get("odd_over25",0) or 1.85, "OU"),
                    ("⚽⚽ Over 3.5",            _o35_kr,   m.get("odd_o35",0) or 2.50, "OU"),
                    ("🔒 Under 2.5",            _u25_kr,   m.get("odd_u25",0) or m.get("odd_under25",0) or 2.00, "OU"),
                    ("🔒🔒 Under 3.5",          _u35_kr,   m.get("odd_u35",0) or 1.50, "OU"),
                    ("⚡ Ambos Anotan",          _aa,       1.75,             "AA"),
                    (f"🌓 {_hn} gana c/mitad",  _gcm_h_kr, 1.55,             "GCM"),
                    (f"🌓 {_an} gana c/mitad",  _gcm_a_kr, 1.65,             "GCM"),
                    (f"🎯 {_hn} +0.5",          _h_o05_kr, 1.55,             "TG"),
                    (f"🛡️ {_hn} -0.5",         _h_u05_kr, 2.10,             "TG"),
                    (f"🎯🎯 {_hn} +1.5",        _h_o15_kr, 2.20,             "TG"),
                    (f"🛡️ {_hn} -1.5",         _h_u15_kr, 1.65,             "TG"),
                    (f"🎯 {_an} +0.5",          _a_o05_kr, 1.65,             "TG"),
                    (f"🛡️ {_an} -0.5",         _a_u05_kr, 2.00,             "TG"),
                    (f"🎯🎯 {_an} +1.5",        _a_o15_kr, 2.40,             "TG"),
                    (f"🛡️ {_an} -1.5",         _a_u15_kr, 1.75,             "TG"),
                ]
                _kr_all_mkts = [(l,p,o,g) for l,p,o,g in _kr_all_mkts if p >= 0.10]
                if not _kr_all_mkts: continue

                # ── Selección KR: por probabilidad con jerarquía de mercados ──
                #
                # Problema original: O1.5 siempre ~85%, DO siempre ~65%, AA ~55%
                # → nunca salían ML aunque tuvieran 60%+ bien fundamentada.
                #
                # Solución: cada mercado compite contra sus PROPIOS UMBRALES.
                # KR elige el mercado más "seguro" dentro de su categoría,
                # priorizando ML si tiene prob ≥ umbral_ml y es favorito claro.
                #
                # Jerarquía:
                #   1. ML favorito (1X2) si prob ≥ 0.55 — siempre preferido si hay favorito claro
                #   2. DO favorito si prob ≥ 0.68 — solo DO del equipo con más prob ML
                #   3. O/U si prob ≥ 0.60 — excluyendo O1.5 salvo ≥0.82
                #   4. AA si prob ≥ 0.62
                #   5. GCM/TG si prob ≥ 0.63

                def _is_o25_u25(lbl): return ("Over 2.5" in lbl or "Under 2.5" in lbl)

                _kr_valid = [(l,p,o,mk) for l,p,o,mk in _kr_all_mkts if p>0.01 and o>1.0]
                if not _kr_valid: _kr_valid = _kr_all_mkts

                # Identificar favorito ML (home o away, no empate)
                _ml_opts = [(l,p,o,mk) for l,p,o,mk in _kr_valid if mk == "1X2" and "Empate" not in l]
                _fav_ml  = max(_ml_opts, key=lambda x: x[1]) if _ml_opts else None
                _fav_prob = _fav_ml[1] if _fav_ml else 0
                _fav_lbl  = _fav_ml[0] if _fav_ml else ""
                _fav_is_home = _hn in _fav_lbl if _fav_ml else True

                # DO correcto: solo el del equipo favorito (mayor prob ML)
                _do_fav_lbl = f"🔵 DO {_hn}" if _fav_is_home else f"🟣 DO {_an}"
                _do_opts_fav = [(l,p,o,mk) for l,p,o,mk in _kr_valid
                                if mk == "DO" and _do_fav_lbl[:8] in l]

                # ── KR Pick 1 y Pick 2 — misma regla que cartelera (función central) ──
                _kr_pick1, _kr_pick2 = _soccer_pick_selector(
                    _kr_all_mkts, _ph, _pa,
                    odd_h=m.get("odd_h",0), odd_a=m.get("odd_a",0), odd_d=m.get("odd_d",0)
                )
                _best_kr_raw = _kr_pick1
                if _best_kr_raw is None: continue
                lbl, prob, odd, mkt = _best_kr_raw

                if prob < 0.52: continue  # umbral mínimo absoluto
                edge   = _kr_edge(prob, odd)
                kelly  = _kr_kelly(prob, odd)
                mv     = [mc.get("dc_ph",0.5), mc.get("bvp_ph",0.5),
                          mc.get("elo_ph",0.5), mc.get("h2h_ph",0.5)]
                spread = round((max(mv)-min(mv))*100, 1)
                contra = spread > _KR_CONFLICT_PP
                ce,cl,cc = _kr_conf(prob, edge, spread)

                _kr_ev_display = prob*(odd-1)-(1-prob) if odd > 1 else 0
                _kr_ev_tag = f" · EV {_kr_ev_display:+.1%}" if mkt in ("1X2","AA") or _is_o25_u25(lbl) else ""
                c = {
                    "deporte":"⚽ Fútbol","sport":"futbol",
                    "label":f"{_home} vs {_away}",
                    "liga":m.get("league",""),"hora":m.get("hora",""),
                    "pick":lbl,"prob":prob,"odd":odd,"edge":edge,
                    "kelly_pct":kelly,"mkt_type":mkt,
                    "contradiccion":contra,"model_spread":spread,
                    "conf_emoji":ce,"conf_label":cl,"conf_color":cc,
                    "ev": round(_kr_ev_display, 4),
                    "reasoning":f"xG {hxg:.2f}–{axg:.2f}{_kr_ev_tag} · {mc.get('consensus','')} · {dp.get('conf','')}",
                    "match":m,
                    "models":{"👑 D-Coles": round(_dc_ph*100,1) if _dc_ph>0 else "N/A",
                              "Ensemble":   round(_ph_base*100,1),
                              "xG H":       round(hxg,2),
                              "xG A":       round(axg,2)},
                    "hxg":hxg,"axg":axg,
                    "all_markets": _kr_all_mkts,
                }
                # CLV silencioso ajusta score KR
                _base_score = _kr_score(prob, edge, spread, kelly, contra)
                try:
                    _kr_clv = _clv_score_adj(
                        m.get("open_ml_h",0) or m.get("odd_h",0),
                        m.get("odd_h",0), prob)
                    _base_score = _base_score + _kr_clv * 0.5
                except:
                    pass
                _bonus_conv = 0.0
                if "Over" in lbl and _kr_hist_confirms_over:    _bonus_conv += 0.7
                if "Under" in lbl and _kr_hist_confirms_under:  _bonus_conv += 0.9
                if "Under" in lbl and _kr_lo25 >= 0.60:         _bonus_conv -= 0.5
                if "Over"  in lbl and _kr_uval:                 _bonus_conv -= 0.6
                if "Over"  in lbl and _xg_total_kr >= 2.9:      _bonus_conv += 0.4
                if "Under" in lbl and _xg_total_kr <= 2.1:      _bonus_conv += 0.5
                if "Over"  in lbl and _kr_delta > 0.05:         _bonus_conv += 0.3
                c["score"]       = max(0.0, _base_score + _bonus_conv)
                c["hist_signal"] = 1 if _kr_hist_confirms_over else (-1 if _kr_hist_confirms_under else 0)
                c["league_o25"]  = round(_kr_lo25*100,1)
                c["league_uval"] = _kr_uval
                # 📊 POSICIÓN EN TABLA → impacta probabilidad
                try:
                    _slug_kr = m.get("slug", "")
                    if _slug_kr:
                        _tbl = _tbl_pre_kr if _tbl_pre_kr.get("pos_h",0)>0 else _tabla_posicion_delta(_home, _away, _slug_kr)
                        if _tbl.get("pos_h", 0) > 0:
                            _tbl_w_kr = 1.0 if _tbl.get('pos_gap',0)>=8 else (0.90 if _tbl.get('pos_gap',0)>=4 else 0.70)
                            c["prob"] = max(0.10, min(0.92, c["prob"] + _tbl["delta_h"] * _tbl_w_kr))
                            c["tabla_desc"] = _tbl["desc"]
                            c["tabla_delta"] = _tbl["delta_h"]
                            c["pos_h"]    = _tbl["pos_h"]
                            c["pos_a"]    = _tbl["pos_a"]
                            c["pts_h"]    = _tbl.get("pts_h", 0)
                            c["pts_a"]    = _tbl.get("pts_a", 0)
                            c["gd_h"]     = _tbl.get("gd_h", 0)
                            c["gd_a"]     = _tbl.get("gd_a", 0)
                            c["avg_gf_h"] = _tbl.get("avg_gf_h", 0)
                            c["avg_gc_h"] = _tbl.get("avg_gc_h", 0)
                            c["avg_gf_a"] = _tbl.get("avg_gf_a", 0)
                            c["avg_gc_a"] = _tbl.get("avg_gc_a", 0)
                            # Boost score si la tabla confirma el pick
                            if _tbl["delta_h"] > 0.05 and lbl == "local":
                                c["score"] = min(10.0, c["score"] + 0.8)
                            elif _tbl["delta_a"] > 0.05 and lbl == "visitante":
                                c["score"] = min(10.0, c["score"] + 0.8)
                except: pass
                # SmallDays se aplica en enrichment (solo top 8) para no bloquear el scan
                c.setdefault("sd_flags", [])
                # ── Señales externas guardadas en el candidato ──
                c["rxg_source"]     = _rxg_source
                c["rxg_confidence"] = _rxg.get("confidence","baja") if _rxg else "baja"
                c["ou_signal_ext"]  = _ou_signal_kr
                # Ajuste de score con señales externas reales
                if _rxg.get("confidence") == "alta":
                    c["score"] = min(10.0, c["score"] + 0.5)  # datos de calidad → más confianza
                if _ou_signal_kr == "over" and "Over" in lbl:
                    c["score"] = min(10.0, c["score"] + 0.4)   # señal O/U externa confirma pick
                elif _ou_signal_kr == "under" and "Under" in lbl:
                    c["score"] = min(10.0, c["score"] + 0.4)
                elif _ou_signal_kr == "over" and "Under" in lbl:
                    c["score"] = max(0.0, c["score"] - 0.6)    # señal contradice pick
                elif _ou_signal_kr == "under" and "Over" in lbl:
                    c["score"] = max(0.0, c["score"] - 0.6)
                if (_injury_h_delta_kr < -0.03 or _injury_a_delta_kr < -0.03):
                    c["score"] = max(0.0, c["score"] - 0.3)    # lesiones = incertidumbre
                candidates.append(c)
            except Exception as _e_fut:
                continue  # partido fallido, continuar con el siguiente
    except Exception as _e_fut_outer:
        pass

    # ── 🏀 NBA ────────────────────────────────────────────────────────────
    try:
        for g in (nba_games or [])[:12]:
            # KR: solo partidos desde ahora (no pasados)
            _kr_state = g.get('state','pre')
            if _kr_state == 'post': continue
            try:
                from datetime import datetime as _dt_kr
                import pytz as _pz_kr
                _now_kr = _dt_kr.now(_pz_kr.timezone('America/Mexico_City'))
                _hora_kr = g.get('hora','') or ''
                if ':' in _hora_kr:
                    _hh_kr,_mm_kr = int(_hora_kr.split(':')[0]),int(_hora_kr.split(':')[1])
                    _gdt_kr = _now_kr.replace(hour=_hh_kr,minute=_mm_kr,second=0,microsecond=0)
                    _elapsed_kr = (_now_kr-_gdt_kr).total_seconds()

                    if _kr_state != 'in' and _elapsed_kr > 0: continue   # pre: hora ya pasó → skip
            except: pass
            # King Rongo analiza todos los juegos del día (usa cache si existe)
            try:
                res = (st.session_state.get("_nba_model_cache",{}).get(g.get("id",""))
                       or nba_ou_model(g["home_id"], g["away_id"], g["ou_line"],
                                   odd_h=g.get("odd_h",0), odd_a=g.get("odd_a",0),
                                   odd_over=g.get("odd_over",0), odd_under=g.get("odd_under",0)))
                p_h_base = res.get("p_h_win", 0.55); p_a_base = 1-p_h_base
                line= res["line"]

                # ── Modelo exclusivo KR: Pythagorean + Pace ──
                try:
                    _pyth = _kr_nba_pythagorean(g["home_id"], g["away_id"],
                                                 p_h_base, p_a_base,
                                                 res["p_over"], line)
                    # Blend: base 70%, Pythagorean 30%
                    p_h = 0.70*p_h_base + 0.30*_pyth["p_h"]
                    p_a = 1-p_h
                    p_over_kr  = 0.70*res["p_over"]  + 0.30*_pyth["p_over"]
                    p_under_kr = 1-p_over_kr
                    pace_note  = f"Pace H:{_pyth['pace_h']:.0f}/A:{_pyth['pace_a']:.0f}"
                except:
                    p_h = p_h_base; p_a = p_a_base
                    p_over_kr = res["p_over"]; p_under_kr = res["p_under"]
                    pace_note = ""

                # ── REAL STATS NBA: ajuste con datos reales de BRef/Injury/Árbitro ──
                _rnba = {}
                _rnba_source = ""
                try:
                    _rnba = _fetch_real_stats_nba(g.get("home",""), g.get("away",""))
                    _rnba_source = _rnba.get("source_txt","")
                    if _rnba.get("confidence") in ("alta","media"):
                        # Ajuste por lesiones reales
                        _inj_h_nba = _rnba.get("injury_h_delta", 0.0)
                        _inj_a_nba = _rnba.get("injury_a_delta", 0.0)
                        if _inj_h_nba < 0: p_h = max(0.10, p_h + _inj_h_nba * 0.6)
                        if _inj_a_nba < 0: p_a = max(0.10, p_a + _inj_a_nba * 0.6)
                        p_h = min(0.90, p_h); p_a = min(0.90, p_a)
                        # Ajuste árbitro O/U
                        _ref_adj = _rnba.get("ref_ou_adj", 0.0)
                        p_over_kr  = max(0.10, min(0.90, p_over_kr + _ref_adj))
                        p_under_kr = 1 - p_over_kr
                        # Net Rating real → ajusta ML
                        if _rnba.get("net_h_real") is not None:
                            _net_adj = _rnba["net_h_real"] / 200.0  # ±5 net = ±2.5% prob
                            p_h = max(0.10, min(0.90, p_h + _net_adj))
                            p_a = 1 - p_h
                except: pass

                # ── Todos los mercados disponibles ──
                _kr_nba_all = [
                    (f"🔥 Over {line}",      p_over_kr,  1.91,                          "O/U"),
                    (f"❄️ Under {line}",     p_under_kr, 1.91,                          "O/U"),
                    (f"🏠 {g['home'][:16]}", p_h,        g.get("odd_h",0) or 1.91,     "ML"),
                    (f"✈️ {g['away'][:16]}", p_a,        g.get("odd_a",0) or 1.91,     "ML"),
                ]
                _kr_nba_all = [(l,p,o,t) for l,p,o,t in _kr_nba_all if p >= 0.10]
                spread = round((1-abs(p_over_kr-p_under_kr))*50, 1)
                contra = abs(p_over_kr-p_under_kr) < 0.08

                # ── Generar DOS candidatos independientes: mejor O/U + mejor ML por EV ──
                def _nba_ev(p, o): return p*(o-1) - (1-p)
                _nba_ou_opts = [(l,p,o,t) for l,p,o,t in _kr_nba_all if t=="O/U" and p>=0.52]
                _nba_ml_opts = [(l,p,o,t) for l,p,o,t in _kr_nba_all if t=="ML"  and p>=0.54]
                _nba_picks = []
                # O/U: elegir por mayor probabilidad
                if _nba_ou_opts:
                    _nba_picks.append(max(_nba_ou_opts, key=lambda x: x[1]))
                # ML: elegir por mayor probabilidad
                if _nba_ml_opts:
                    _nba_picks.append(max(_nba_ml_opts, key=lambda x: x[1]))
                if not _nba_picks: continue

                for lbl, prob, odd, mkt in _nba_picks:
                    edge  = _kr_edge(prob, odd)
                    kelly = _kr_kelly(prob, odd)
                    ce,cl,cc = _kr_conf(prob, edge, spread)
                    # El companion muestra el "otro" mercado para contexto
                    _other_t = "ML" if mkt=="O/U" else "O/U"
                    _other_opts = [(l2,p2,o2,t2) for l2,p2,o2,t2 in _kr_nba_all if t2==_other_t]
                    _kr_comp_str = ""
                    if _other_opts:
                        _best_other = max(_other_opts, key=lambda x: x[1])
                        _kr_comp_str = f"{_best_other[0]} ({_best_other[1]*100:.0f}%)"
                    c = {
                        "deporte":"🏀 NBA","sport":"nba",
                        "label":f"{g['away']} @ {g['home']}",
                        "liga":"NBA","hora":g.get("hora",""),
                        "pick":lbl,"prob":prob,"odd":odd,"edge":edge,
                        "kelly_pct":kelly,"mkt_type":mkt,
                        "contradiccion":contra,"model_spread":spread,
                        "conf_emoji":ce,"conf_label":cl,"conf_color":cc,
                        "reasoning":f"Proy {res['proj']} pts · {pace_note} · NetRtg {res.get('net_h',0):+.1f}/{res.get('net_a',0):+.1f}",
                        "match":g,
                        "models":{"👑 Pyth%":round(p_h*100,1),
                                  "Over%":   round(p_over_kr*100,1),
                                  "Under%":  round(p_under_kr*100,1),
                                  "ML H%":   round(p_h*100,1)},
                        "all_markets": _kr_nba_all,
                        "companion": _kr_comp_str,
                        "p_over": p_over_kr, "p_under": p_under_kr,
                        "p_h": p_h, "p_a": p_a, "line": line,
                    }
                    c["score"] = _kr_score(prob, edge, spread, kelly, contra)
                    # Ajuste de score con datos externos NBA
                    c["rnba_source"] = _rnba_source
                    _rnba_ou = _rnba.get("ou_signal","neutral") if _rnba else "neutral"
                    if _rnba.get("confidence") == "alta":
                        c["score"] = min(10.0, c["score"] + 0.4)
                    if _rnba_ou == "over"  and "Over"  in lbl: c["score"] = min(10.0, c["score"]+0.35)
                    if _rnba_ou == "under" and "Under" in lbl: c["score"] = min(10.0, c["score"]+0.35)
                    if _rnba_ou == "over"  and "Under" in lbl: c["score"] = max(0.0,  c["score"]-0.5)
                    if _rnba_ou == "under" and "Over"  in lbl: c["score"] = max(0.0,  c["score"]-0.5)
                    # SmallDays se aplica en enrichment (solo top 8)
                    candidates.append(c)
            except: continue
    except: pass

    # ── 🎾 TENIS ──────────────────────────────────────────────────────────
    _smap = {"Indian Wells":"hard","Miami":"hard","Roland Garros":"clay",
             "Wimbledon":"grass","US Open":"hard","Australian Open":"hard",
             "Monte Carlo":"clay","Madrid":"clay","Barcelona":"clay",
             "Rome":"clay","Cincinnati":"hard","Toronto":"hard",
             "Halle":"grass","Queen":"grass","Dubai":"hard","Doha":"hard"}
    try:
        for m in (ten_matches or [])[:15]:
            # KR: solo partidos desde ahora (no pasados)
            _kr_state = m.get('state','pre')
            if _kr_state == 'post': continue
            try:
                from datetime import datetime as _dt_kr
                import pytz as _pz_kr
                _now_kr = _dt_kr.now(_pz_kr.timezone('America/Mexico_City'))
                _hora_kr = m.get('hora','') or ''
                if ':' in _hora_kr:
                    _hh_kr,_mm_kr = int(_hora_kr.split(':')[0]),int(_hora_kr.split(':')[1])
                    _gdt_kr = _now_kr.replace(hour=_hh_kr,minute=_mm_kr,second=0,microsecond=0)
                    _elapsed_kr = (_now_kr-_gdt_kr).total_seconds()

                    if _kr_state != 'in' and _elapsed_kr > 0: continue   # pre: hora ya pasó → skip
            except: pass
            # King Rongo analiza todos los partidos del día
            try:
                tor = m.get("torneo", m.get("tour",""))
                srf = next((v for k,v in _smap.items() if k.lower() in tor.lower()), "hard")
                r1 = m.get("rank1",0) or 0
                r2 = m.get("rank2",0) or 0
                p1_name = m.get("p1",""); p2_name = m.get("p2","")

                # ── Siempre resolver ranks desde nombre — misma lógica que cartelera ──
                if r1 <= 0 or r1 >= 150:
                    r1 = _resolve_rank(p1_name, _KNOWN_RANKS) or _resolve_rank_local(p1_name) or 120
                if r2 <= 0 or r2 >= 150:
                    r2 = _resolve_rank(p2_name, _KNOWN_RANKS) or _resolve_rank_local(p2_name) or 120

                odd_1 = m.get("odd_1", m.get("odd_h",0))
                odd_2 = m.get("odd_2", m.get("odd_a",0))

                # ── Usar MISMO modelo que la cartelera de tenis ──
                _vd = veredicto_academico_tenis(
                    p1_name=p1_name, p2_name=p2_name,
                    rank1=r1, rank2=r2,
                    odd_1=odd_1, odd_2=odd_2,
                    surface=srf, torneo=tor,
                    expert_p1=None
                )
                p1_vd = _vd["_p1_final"]
                # ── Modelo exclusivo KR: Pressure Index ──
                try:
                    p1_press = _kr_tennis_pressure(r1, r2, p1_name, p2_name, tor, odd_1, odd_2)
                    p1_final = 0.80*p1_vd + 0.20*p1_press
                except:
                    p1_final = p1_vd; p1_press = p1_vd

                # ── REAL STATS TENIS: TennisAbstract Elo + fatiga + lesiones ──
                _rten = {}
                _rten_source = ""
                try:
                    _rten = _fetch_real_stats_tennis(p1_name, p2_name, srf)
                    _rten_source = _rten.get("source_txt","")
                    if _rten.get("confidence") in ("alta","media"):
                        # ELO real de superficie → repondera el modelo
                        _elo_h_r = _rten.get("elo_h_surface")
                        _elo_a_r = _rten.get("elo_a_surface")
                        if _elo_h_r and _elo_a_r:
                            _elo_diff = _elo_h_r - _elo_a_r
                            _elo_adj  = _elo_diff / 800.0  # ±200 elo = ±25% prob
                            p1_final  = max(0.10, min(0.92, p1_final + _elo_adj * 0.25))
                        # Fatiga: reduce la prob del favorito si está más cansado
                        _fat_h = _rten.get("fatigue_h", 1.0)
                        _fat_a = _rten.get("fatigue_a", 1.0)
                        _fat_delta = (_fat_a - _fat_h) * 0.12  # visita más cansado → +prob local
                        p1_final = max(0.10, min(0.92, p1_final + _fat_delta))
                        # H2H en superficie
                        _h2h_sr = _rten.get("h2h_surface_win_rate")
                        if _h2h_sr is not None:
                            p1_final = max(0.10, min(0.92, 0.75*p1_final + 0.25*_h2h_sr))
                        # Lesiones
                        p1_final = max(0.10, min(0.92, p1_final + _rten.get("injury_delta_h",0)*0.5))
                        p1_final = max(0.10, min(0.92, p1_final - _rten.get("injury_delta_a",0)*0.5))
                except: pass

                p2_final = 1 - p1_final
                fav  = p1_name if p1_final >= p2_final else p2_name
                prob = max(p1_final, p2_final)
                odd  = odd_1 if p1_final >= p2_final else odd_2

                edge   = _kr_edge(prob, odd)
                kelly  = _kr_kelly(prob, odd)
                spread = round(abs(p1_final - p2_final) * 100, 1)
                contra = spread < 4
                ce,cl,cc = _kr_conf(prob, edge, _KR_CONFLICT_PP+5 if contra else 10)
                rd = abs(r1 - r2)
                c = {
                    "deporte":"🎾 Tenis","sport":"tenis",
                    "label":f"{p1_name} vs {p2_name}",
                    "liga":tor,"hora":m.get("hora",""),
                    "pick":f"🎾 {fav} gana","prob":prob,"odd":odd,"edge":edge,
                    "kelly_pct":kelly,"mkt_type":"ML",
                    "contradiccion":contra,"model_spread":spread,
                    "conf_emoji":ce,"conf_label":cl,"conf_color":cc,
                    "reasoning":f"Rk #{r1} vs #{r2} · {srf.title()} · Δ{spread:.0f}pp"
                                + (f" · ELO {_rten.get('elo_h_surface','?')}v{_rten.get('elo_a_surface','?')}" if _rten.get("elo_h_surface") else ""),
                    "match":m,
                    "rten_source": _rten_source,
                    "models":{
                        "Elo":     round(_vd.get("_p1_elo",   p1_final)*100, 1),
                        "Sup":     round(_vd.get("_p1_surf",  p1_final)*100, 1),
                        "MC50k":   round(_vd.get("_p1_mc",    p1_final)*100, 1),
                        "Moment":  round(_vd.get("_p1_mom",   p1_final)*100, 1),
                        "Serve":   round(_vd.get("_p1_srv",   p1_final)*100, 1),
                        "👑 Press":round(p1_press*100, 1),
                    },
                }
                # Clima + datos externos ajustan score KR tenis
                try:
                    _kr_wx = _weather_tennis_adj(p1_name, p2_name, srf, tor)
                    _wx_bonus = 0.3 if abs(_kr_wx) >= 0.02 else 0
                    c["score"] = _kr_score(prob, edge, spread if contra else 10, kelly, contra) + _wx_bonus
                except:
                    c["score"] = _kr_score(prob, edge, spread if contra else 10, kelly, contra)
                # Bonus por datos externos de calidad
                if _rten.get("confidence") == "alta":
                    c["score"] = min(10.0, c["score"] + 0.45)
                elif _rten.get("confidence") == "media":
                    c["score"] = min(10.0, c["score"] + 0.20)
                candidates.append(c)

                # ── GAMES O/U — mercado exclusivo KR tenis ──
                try:
                    _tour_kr = m.get("tour", "ATP")
                    _gou = _tennis_games_pick(
                        r1, r2, p1_name, p2_name, srf, _tour_kr,
                        odd_1=odd_1, odd_2=odd_2
                    )
                    if _gou and _gou.get("prob", 0) >= 0.54:
                        _g_edge   = _kr_edge(_gou["prob"], _gou["odd"])
                        _g_kelly  = _kr_kelly(_gou["prob"], _gou["odd"])
                        _g_ce, _g_cl, _g_cc = _kr_conf(_gou["prob"], _g_edge, 18)
                        _line_src = "📡 Línea real" if _gou.get("real_line") else "📊 Línea modelo"
                        _cg = {
                            "deporte":       "🎾 Tenis",
                            "sport":         "tenis",
                            "label":         f"{p1_name} vs {p2_name}",
                            "liga":          tor,
                            "hora":          m.get("hora",""),
                            "pick":          _gou["pick"],
                            "prob":          _gou["prob"],
                            "odd":           _gou["odd"],
                            "edge":          _g_edge,
                            "kelly_pct":     _g_kelly,
                            "mkt_type":      "GAMES_OU",
                            "contradiccion": False,
                            "model_spread":  0,
                            "conf_emoji":    _g_ce,
                            "conf_label":    _g_cl,
                            "conf_color":    _g_cc,
                            "reasoning":     (
                                f"Línea {_gou['line']:.1f} · Media modelo {_gou['avg_games']:.1f}g · "
                                f"O={_gou['p_over']*100:.0f}% U={_gou['p_under']*100:.0f}% · "
                                f"EV {_gou['ev']*100:+.1f}% · {_line_src} · {srf.title()}"
                            ),
                            "match":         m,
                            "models": {
                                "Media":  f"{_gou['avg_games']:.1f}g",
                                "P.Over": f"{_gou['p_over']*100:.0f}%",
                                "P.Under":f"{_gou['p_under']*100:.0f}%",
                                "Línea":  f"{_gou['line']:.1f}",
                                "Fuente": "Real" if _gou.get("real_line") else "Modelo",
                            },
                            "games_line":    _gou["line"],
                            "games_avg":     _gou["avg_games"],
                            "games_p_over":  _gou["p_over"],
                            "games_p_under": _gou["p_under"],
                            "games_real_line": _gou.get("real_line", False),
                        }
                        _cg["score"] = _kr_score(_gou["prob"], _g_edge, 0, _g_kelly, False)
                        candidates.append(_cg)
                except: pass
            except: continue
    except: pass

    # ── Rankear ──
    # GOD MODE pipeline
    pick_history = pick_history or []
    _brain_kr = _kr_brain_load()
    _elo_kr   = _kr_elo_load()
    _ph_t = tuple({"pick":p.get("pick",""),"result":"gano" if p.get("result") in ("ok","✅","gano") else "perdio"} for p in pick_history[-50:])
    # ── Enriquecimiento PARALELO: todos los candidatos simultáneamente ──
    import concurrent.futures as _cf_kr

    def _enrich_candidate(_c):
        """Enriquece un candidato con ultra+transicion+entrenador en paralelo interno."""
        try:
            _c["score"] = _kr_god_score(_c, _brain_kr, _elo_kr, _ph_t)
            _ev_c       = _kr_ev(_c.get("prob",0.5), _c.get("odd",0))
            _c["ev_pct"]    = _ev_c["ev_pct"]
            _c["ev_valor"]  = _ev_c["valor"]
            _c["cuota_justa"] = _ev_c["justa"]
            _home_c = _c.get("label","").split(" vs ")[0].split(" @ ")[-1].strip()
            _away_c = _c.get("label","").split(" vs ")[-1].split(" @ ")[0].strip()
            # Lanzar ultra + combinado (sit+trans+coach) en paralelo — 2 llamadas en vez de 4
            with _cf_kr.ThreadPoolExecutor(max_workers=2) as _ex3:
                _fut_ui  = _ex3.submit(_ultra_intel_full,
                    _home_c, _away_c,
                    _c.get("sport","futbol"), _c.get("liga",""), _c.get("hora",""),
                    _c.get("tabla_desc",""))
                _fut_comb = _ex3.submit(_kr_analisis_combinado,
                    _home_c, _away_c,
                    _c.get("sport","futbol"), _c.get("liga",""), _c.get("hora",""))
                try:
                    _ui = _fut_ui.result(timeout=10)
                    _c["prob"]        = max(0.10,min(0.92,_c["prob"]+_ui["delta_h"]*0.40))
                    _c["ultra_score"] = _ui["score_ultra"]
                    _c["ultra_ctx"]   = _ui["context_str"]
                    _c["ultra_flags"] = _ui["flags"]
                    if _ui["score_ultra"]>=7.0: _c["score"]=min(10.0,_c["score"]+0.6)
                    elif _ui["score_ultra"]<=3.0: _c["score"]=max(0.0,_c["score"]-0.8)
                except: _c.setdefault("ultra_flags",[])
                try:
                    _comb = _fut_comb.result(timeout=8)
                    # Situacional
                    _sf = float(_comb.get("sit_factor",0.0))
                    _c["prob"]    = max(0.10,min(0.92,_c["prob"]+_sf*0.35))
                    _c["sit_ctx"] = _comb.get("sit_ctx","")
                    if abs(_sf)>=0.05: _c["score"]=min(10.0,_c["score"]+abs(_sf)*4.0)
                    # Transicion
                    _c["trans_score"] = float(_comb.get("trans_score",5))
                    _c["trans_delta"] = float(_comb.get("trans_h",0))
                    _c["prob"] = max(0.10, min(0.92, _c["prob"] + _comb.get("trans_h",0)*0.55))
                    # Entrenador
                    _c["coach_score"] = float(_comb.get("coach_score",5))
                    _c["coach_delta"] = float(_comb.get("coach_h",0))
                    _c["prob"] = max(0.10, min(0.92, _c["prob"] + _comb.get("coach_h",0)*0.60))
                except:
                    _c.setdefault("sit_ctx",""); _c.setdefault("trans_score",5); _c.setdefault("coach_score",5)
            # SmallDays — solo para top candidates (ya paralelo, corre aquí una vez)
            try:
                _sport_c = _c.get("sport","futbol")
                _match_c = _c.get("match", {})
                _sd = _small_days_analyze(
                    _home_c, _away_c, _sport_c,
                    _match_c.get("fecha",""), _match_c.get("home_id",""),
                    _match_c.get("away_id",""), _c.get("liga",""))
                _sd_d = float(_sd.get("delta_h", 0.0))
                if abs(_sd_d) > 0.005:
                    _c["prob"] = max(0.10, min(0.92, _c["prob"] + _sd_d * 0.4))
                    _c["sd_flags"] = _sd.get("flags", [])
            except: pass
            # ── Full Intel enrichment — sharp money + alineaciones + arbitro ──
            if _c.get("sport","futbol") == "futbol":
                try:
                    _fi_e = _fetch_full_intel(
                        _home_c, _away_c,
                        _c.get("match",{}).get("slug",""),
                        hxg=_c.get("hxg",1.2), axg=_c.get("axg",1.0),
                        ph=_c.get("prob",0.45)*0.9, pd=0.27, pa=(1-_c.get("prob",0.45))*0.9,
                        match_date=_c.get("match",{}).get("fecha","")
                    )
                    if _fi_e.get("lineup_confirmed"):
                        _c["score"] = min(10.0, _c.get("score",5.0) + 0.3)
                        _c["prob"]  = max(0.10, min(0.92, _c["prob"] + _fi_e.get("prob_adj_h",0)*0.6))
                    _sh_side = _fi_e.get("sharp_side","none")
                    _sh_str  = _fi_e.get("sharp_strength",0)
                    _pick_lbl = _c.get("pick","").lower()
                    if _sh_side == "home" and any(w in _pick_lbl for w in ["local","home","gana","1x2"]):
                        _c["score"] = min(10.0, _c["score"] + _sh_str*0.35)
                        _c["prob"]  = min(0.92, _c["prob"] + _sh_str*0.015)
                    elif _sh_side == "away" and any(w in _pick_lbl for w in ["visit","away","visita"]):
                        _c["score"] = min(10.0, _c["score"] + _sh_str*0.35)
                    elif _sh_side != "none" and _sh_str >= 2:
                        _c["score"] = max(0.0, _c["score"] - _sh_str*0.20)
                    _ref_adj = _fi_e.get("referee_ou_adj",0.0)
                    if abs(_ref_adj) > 0.01:
                        if (_ref_adj > 0 and "over" in _pick_lbl) or (_ref_adj < 0 and "under" in _pick_lbl):
                            _c["score"] = min(10.0, _c["score"] + abs(_ref_adj)*30)
                    _c["full_intel_src"] = _fi_e.get("source_summary","")[:100]
                    _c["sharp_side"]     = _sh_side
                    _c["sharp_strength"] = _sh_str
                    _c["alt_picks"]      = _fi_e.get("alt_picks",[])[:3]
                    if _fi_e.get("referee"):
                        _c["reasoning"] = _c.get("reasoning","") + f" · \u2696\ufe0f {_fi_e['referee'][:15]}"
                except: pass

            # ── Bet365 Market Consensus — señal de mercado no-vig ──
            if _c.get("sport","futbol") == "futbol":
                try:
                    _b365 = _b365_market_consensus(_home_c, _away_c, sport_id=1)

                    # ── FALLBACK IA: si Bet365 no encontró el partido ──────
                    if not _b365.get("found"):
                        try:
                            _fb_hxg   = _c.get("hxg", 1.2)
                            _fb_axg   = _c.get("axg", 1.0)
                            _fb_prob  = _c.get("prob", 0.50)
                            _fb_mkt   = _c.get("mkt_type", "ML")
                            _fb_liga  = _c.get("liga", "")
                            _fb_score = _c.get("score", 5.0)
                            _fb_models = _c.get("models", {})
                            _fb_reasoning = _c.get("reasoning","")

                            _fb_prompt = f"""Partido de fútbol: {_home_c} vs {_away_c}
Liga: {_fb_liga}
Mercado del pick: {_fb_mkt}
Probabilidad modelo: {_fb_prob:.1%}
xG Local: {_fb_hxg:.2f} | xG Visita: {_fb_axg:.2f}
xG Total: {_fb_hxg+_fb_axg:.2f}
Score KR actual: {_fb_score:.1f}/10
Modelos internos: {_fb_models}
Contexto: {_fb_reasoning[:120]}

Basándote en estos datos estadísticos, estima las siguientes probabilidades de mercado (sin vig):
Responde SOLO con JSON exactamente así:
{{"ph_novig":0.00,"pd_novig":0.00,"pa_novig":0.00,"ou25_over_novig":0.00,"btts_yes_novig":0.00,"ah_line":0.0,"xg_total_impl":0.0,"xg_home_impl":0.0,"xg_away_impl":0.0,"confianza":"alta|media|baja"}}

Reglas:
- ph+pd+pa deben sumar exactamente 1.0
- ou25_over_novig: prob de que el partido tenga más de 2.5 goles
- btts_yes_novig: prob de que ambos equipos anoten
- ah_line: línea del hándicap asiático (negativo si local favorito)
- xg_total_impl debe ser consistente con ou25_over_novig via Poisson
- confianza: alta si xG claro (diff>0.5), media si equilibrado, baja si sin datos"""

                            _fb_raw = _gemini(_fb_prompt, json_mode=True, max_tokens=200, temperature=0.1)
                            _fb_d = {}
                            try:
                                import json as _json
                                _fb_d = _json.loads(_fb_raw) if isinstance(_fb_raw, str) else (_fb_raw if isinstance(_fb_raw, dict) else {})
                            except: pass

                            if _fb_d and "ph_novig" in _fb_d:
                                # Normalizar que sumen 1
                                _s3 = _fb_d.get("ph_novig",0) + _fb_d.get("pd_novig",0) + _fb_d.get("pa_novig",0)
                                if _s3 > 0:
                                    _fb_d["ph_novig"] = round(_fb_d["ph_novig"]/_s3, 4)
                                    _fb_d["pd_novig"] = round(_fb_d.get("pd_novig",0)/_s3, 4)
                                    _fb_d["pa_novig"] = round(_fb_d["pa_novig"]/_s3, 4)

                                # Construir b365 sintético con flag de origen
                                _b365 = {
                                    "found": True,
                                    "ph_novig":          float(_fb_d.get("ph_novig", _fb_prob)),
                                    "pd_novig":          float(_fb_d.get("pd_novig", 0.27)),
                                    "pa_novig":          float(_fb_d.get("pa_novig", 1-_fb_prob-0.27)),
                                    "ou25_over_novig":   float(_fb_d.get("ou25_over_novig", 0.55)),
                                    "ou25_under_novig":  round(1 - float(_fb_d.get("ou25_over_novig", 0.55)), 4),
                                    "ou_lines":          {},
                                    "btts_yes_novig":    float(_fb_d.get("btts_yes_novig", 0.50)),
                                    "btts_no_novig":     round(1 - float(_fb_d.get("btts_yes_novig", 0.50)), 4),
                                    "dnb_home_novig":    0.0,
                                    "dnb_away_novig":    0.0,
                                    "dc_1x_novig":       0.0, "dc_x2_novig": 0.0, "dc_12_novig": 0.0,
                                    "ht_home_novig":     0.0, "ht_draw_novig": 0.0, "ht_away_novig": 0.0,
                                    "ht_ou_over_novig":  0.0,
                                    "xg_home_impl":      float(_fb_d.get("xg_home_impl", _fb_hxg)),
                                    "xg_away_impl":      float(_fb_d.get("xg_away_impl", _fb_axg)),
                                    "xg_total_impl":     float(_fb_d.get("xg_total_impl", _fb_hxg+_fb_axg)),
                                    "ah_line":           float(_fb_d.get("ah_line", 0.0)),
                                    "ah_home_novig":     0.0, "ah_away_novig": 0.0,
                                    "corners_line":      0.0, "corners_over_novig": 0.0,
                                    "cards_line":        0.0, "cards_over_novig":   0.0,
                                    "combo_1x2_ou":      {},
                                    "market_favorite":   "home" if _fb_d.get("ph_novig",0) >= _fb_d.get("pa_novig",0) else "away",
                                    "market_fav_prob":   max(_fb_d.get("ph_novig",0), _fb_d.get("pa_novig",0)),
                                    "market_open_game":  _fb_d.get("ou25_over_novig",0) >= 0.58 and _fb_d.get("btts_yes_novig",0) >= 0.55,
                                    "b365_raw":          {},
                                    "source_txt":        f"🤖 IA estimada ({_fb_d.get('confianza','?')}) — Bet365 no disponible",
                                    "_is_ai_estimated":  True,   # flag para distinguir en UI
                                    "_ai_confidence":    _fb_d.get("confianza","media"),
                                }
                                _c["b365_estimated"] = True
                        except: pass
                    if _b365.get("found"):
                        _mkt_h   = _b365["ph_novig"]
                        _mkt_a   = _b365["pa_novig"]
                        _mkt_d   = _b365["pd_novig"]
                        _mod_prob = _c.get("prob", 0.45)
                        _pick_lbl2 = _c.get("pick","").lower()
                        _mkt_fav   = _b365["market_favorite"]

                        # ── Determinar prob del mercado para el outcome del pick ──
                        if any(w in _pick_lbl2 for w in ["local","home","gana"]):
                            _mkt_prob_pick = _mkt_h
                            # Draw No Bet del local — fuerza real sin ruido de empate
                            _dnb_adj = _b365["dnb_home_novig"]
                        elif any(w in _pick_lbl2 for w in ["visit","away","visita"]):
                            _mkt_prob_pick = _mkt_a
                            _dnb_adj = _b365["dnb_away_novig"]
                        elif "empate" in _pick_lbl2 or "draw" in _pick_lbl2:
                            _mkt_prob_pick = _mkt_d
                            _dnb_adj = 0.0
                        elif any(w in _pick_lbl2 for w in ["over","más","o2","o3"]):
                            _mkt_prob_pick = _b365["ou25_over_novig"] or _mkt_h
                            _dnb_adj = 0.0
                        elif any(w in _pick_lbl2 for w in ["under","menos","u2","u3"]):
                            _mkt_prob_pick = _b365["ou25_under_novig"] or (1 - _b365["ou25_over_novig"]) or _mkt_h
                            _dnb_adj = 0.0
                        elif "btts" in _pick_lbl2 or "ambos" in _pick_lbl2:
                            _mkt_prob_pick = _b365["btts_yes_novig"] or _mkt_h
                            _dnb_adj = 0.0
                        else:
                            _mkt_prob_pick = _mkt_h
                            _dnb_adj = 0.0

                        _delta_mkt = _mod_prob - _mkt_prob_pick
                        _b365_parts = []

                        # Factor de peso: datos reales de Bet365 pesan más que estimación IA
                        _is_estimated = _b365.get("_is_estimated") or _c.get("b365_estimated", False)
                        _ai_conf = _b365.get("_ai_confidence", "media")
                        _weight = 0.6 if _is_estimated and _ai_conf == "baja" else \
                                  0.8 if _is_estimated else 1.0

                        # ── 1. Confluencia modelo vs mercado 1X2 ──────────────
                        if _mkt_prob_pick > 0:
                            if _delta_mkt >= 0.05:
                                _b365_bonus = min(1.5, _delta_mkt * 12) * _weight
                                _c["score"] = min(10.0, _c["score"] + _b365_bonus)
                                _src = "🤖" if _is_estimated else "🎯"
                                _b365_parts.append(f"{_src} Modelo>{_mkt_prob_pick:.0%} mkt(+{_b365_bonus:.1f})")
                            elif abs(_delta_mkt) <= 0.04:

                                _c["score"] = min(10.0, _c["score"] + 0.5)
                                _b365_parts.append(f"{'🤖' if _is_estimated else '✅'} Confluencia {'est' if _is_estimated else 'B365'} {_mkt_prob_pick:.0%}")
                            elif _delta_mkt <= -0.08:
                                # Solo penalizar fuerte si es dato real, suave si es IA
                                _pen = 0.4 * _weight
                                _blend = _mod_prob * (0.65 + 0.15*(1-_weight)) + _mkt_prob_pick * (0.35 - 0.15*(1-_weight))
                                _c["prob"] = min(0.92, _blend)
                                _c["score"] = max(0.0, _c["score"] - _pen)
                                _b365_parts.append(f"⚠️ Mkt={_mkt_prob_pick:.0%}≠mod={_mod_prob:.0%}")
                            else:
                                _src2 = "🤖est" if _is_estimated else "🎰 B365"
                                _b365_parts.append(f"{_src2}:{_mkt_prob_pick:.0%}")

                        # ── 2. xG implícito vs nuestro xG ────────────────────
                        _xg_mkt = _b365["xg_total_impl"]
                        _xg_mod = _c.get("hxg", 0) + _c.get("axg", 0)
                        if _xg_mkt > 0 and _xg_mod > 0:
                            _xg_delta = _xg_mkt - _xg_mod
                            if abs(_xg_delta) >= 0.6:
                                if any(w in _pick_lbl2 for w in ["over","más","o2"]):
                                    _xg_adj = min(0.4, abs(_xg_delta) * 0.15 * _weight) * (1 if _xg_delta > 0 else -1)
                                    _c["score"] = min(10.0, max(0.0, _c["score"] + _xg_adj))
                                _b365_parts.append(f"xG={'est' if _is_estimated else 'mkt'}={_xg_mkt:.1f}(mod={_xg_mod:.1f})")

                        # ── 3. Asian Handicap — margen de victoria esperado ───
                        _ah_line = _b365["ah_line"]
                        if _ah_line != 0.0:
                            if _ah_line <= -1.5 and any(w in _pick_lbl2 for w in ["local","home","gana"]):
                                _c["score"] = min(10.0, _c["score"] + 0.3 * _weight)
                                _b365_parts.append(f"AH={_ah_line:+.1f}🔥")
                            elif _ah_line >= 1.5 and any(w in _pick_lbl2 for w in ["visit","away","visita"]):
                                _c["score"] = min(10.0, _c["score"] + 0.3 * _weight)
                                _b365_parts.append(f"AH={_ah_line:+.1f}🔥")
                            else:
                                _b365_parts.append(f"AH={_ah_line:+.1f}")

                        # ── 4. BTTS — señal de partido abierto ───────────────
                        _btts = _b365["btts_yes_novig"]
                        if _btts >= 0.62 and any(w in _pick_lbl2 for w in ["over","más","btts","ambos"]):
                            _c["score"] = min(10.0, _c["score"] + 0.25 * _weight)
                            _b365_parts.append(f"BTTS={_btts:.0%}✅")
                        elif _btts <= 0.35 and any(w in _pick_lbl2 for w in ["under","menos"]):
                            _c["score"] = min(10.0, _c["score"] + 0.25 * _weight)
                            _b365_parts.append(f"BTTS={_btts:.0%}✅")

                        # ── 5. Partido abierto → favorear picks dinámicos ────
                        if _b365["market_open_game"]:
                            if any(w in _pick_lbl2 for w in ["over","más","btts","ambos","o2","o3"]):
                                _c["score"] = min(10.0, _c["score"] + 0.3 * _weight)
                                _b365_parts.append("🔓partido_abierto")

                        # ── 6. Draw No Bet — fuerza real del favorito ────────
                        if _dnb_adj >= 0.72 and any(w in _pick_lbl2 for w in ["local","home","gana","visit","away","visita"]):
                            _c["score"] = min(10.0, _c["score"] + 0.2 * _weight)
                            _b365_parts.append(f"DNB={_dnb_adj:.0%}")

                        # ── 7. Córners — señal de presión/posesión ───────────
                        _corn_over = _b365["corners_over_novig"]
                        _corn_line = _b365["corners_line"]
                        if _corn_over >= 0.65 and any(w in _pick_lbl2 for w in ["corner","córner","corn"]):
                            _c["score"] = min(10.0, _c["score"] + 0.3 * _weight)
                            _b365_parts.append(f"Corn>{_corn_line:.0f}={_corn_over:.0%}")

                        _c["b365_signal"] = " · ".join(_b365_parts[:3])  # max 3 señales
                        _c["b365_novig"] = {
                            "ph": _mkt_h, "pd": _mkt_d, "pa": _mkt_a,
                            "ou25_o": _b365["ou25_over_novig"],
                            "btts":   _btts,
                            "xg_h":   _b365["xg_home_impl"],
                            "xg_a":   _b365["xg_away_impl"],
                            "ah":     _ah_line,
                            "dnb_h":  _b365["dnb_home_novig"],
                        }
                except: pass
        except: pass
        return _c

    # Enriquecer todos los candidatos en paralelo (hasta 15 simultáneos)
    with _cf_kr.ThreadPoolExecutor(max_workers=15) as _pool_kr:
        _futs = {_pool_kr.submit(_enrich_candidate, _c): _c for _c in candidates[:8]}
        for _fut in _cf_kr.as_completed(_futs, timeout=20):
            try: _fut.result()
            except: pass
    candidates.sort(key=lambda x: -x.get("score",0))
    contras = [c for c in candidates if c.get("contradiccion")]

    # Regla de probabilidad dominante: si hay candidato ≥70%, no elegir ninguno <62%
    _high_prob  = [c for c in candidates if not c.get("contradiccion") and c.get("prob",0) >= 0.70]
    _normal     = [c for c in candidates if not c.get("contradiccion")]
    _pool       = _high_prob if _high_prob else _normal

    # Cascada mejorada — prioriza EV+ real, luego prob alta, luego lo que haya
    _prob_solid = [c for c in _pool if c.get("prob",0) >= 0.62]
    _prob_ok    = [c for c in _pool if c.get("prob",0) >= 0.54]
    el_pick = (
        (max(_prob_solid, key=lambda c: c.get("prob",0)) if _prob_solid else None) or
        (max(_prob_ok,    key=lambda c: c.get("prob",0)) if _prob_ok    else None) or
        (max(_pool,       key=lambda c: c.get("prob",0)) if _pool       else None) or
        (candidates[0] if candidates else None)
    )
    # GOD BRAIN: Claude decide el pick final con datos externos incluidos
    try:
        _t5 = tuple((c.get("label",""),c.get("pick",""),c.get("prob",0.5),
                     c.get("odd",0.0),c.get("score",5.0),c.get("ev_pct",0.0),
                     (c.get("sit_ctx","") +
                      "|Ultra:" + str(round(c.get("ultra_score",5.0),1)) +
                      "|Trans:" + str(round(c.get("trans_score",5.0),1)) +
                      "|Coach:" + str(round(c.get("coach_score",5.0),1)) +
                      ("|Sharp:"+c.get("sharp_side","none")+"x"+str(c.get("sharp_strength",0)) if c.get("sharp_side","none")!="none" else "") +
                      ("|FI:"+c.get("full_intel_src","")[:60] if c.get("full_intel_src") else "") +
                      ("|B365:"+c.get("b365_signal","")[:40] if c.get("b365_signal") else "")),
                     c.get("contradiccion",False),
                     # Datos externos completos: xG real + Full Intel + Sharp
                     ((c.get("full_intel_src","") or c.get("rxg_source","") or
                       c.get("rnba_source","") or c.get("rten_source","")) + 
                      (" [SHARP_"+c.get("sharp_side","")+"_"+str(c.get("sharp_strength",0))+"]" if c.get("sharp_side","none")!="none" else ""))[:150]
                     ) for c in candidates[:5])
        _b2  = _kr_brain_load()
        _l5s = " ".join(p.get("result","?")[:1].upper() for p in _b2.get("last5",[]))
        _gd  = _kr_god_brain_call(_t5,_b2.get("wins",0),_b2.get("losses",0),_b2.get("hot",0),_b2.get("cold",0),_l5s)
        _idx = max(0,min(int(_gd.get("idx",0)),len(candidates)-1))
        if candidates:
            el_pick = candidates[_idx]
            el_pick["_god_razon"]  = _gd.get("razon","")
            el_pick["_god_conf"]   = float(_gd.get("confianza",el_pick.get("prob",0.5)))
            el_pick["_god_alerta"] = _gd.get("alerta")
            # Mostrar fuente de datos externos en el reasoning si existe
            _ext_src = (el_pick.get("rxg_source","") or
                        el_pick.get("rnba_source","") or
                        el_pick.get("rten_source",""))
            if _ext_src:
                el_pick["reasoning"] = el_pick.get("reasoning","") + f" · 📊 {_ext_src[:80]}"
            if el_pick.get("b365_signal"):
                el_pick["reasoning"] = el_pick.get("reasoning","") + f" · {el_pick['b365_signal']}"
    except: pass
    if el_pick:
        el_pick = {**el_pick, "is_rongo_pick": True}

    # TOP 3 DEL REY — el mejor de cada deporte, priorizando sin contradicción
    _top3 = []
    _deps_usados = set()
    # Primero: mejores sin contradicción
    for _c in candidates:
        if _c.get("contradiccion"): continue
        _dep = _c.get("deporte","")
        if _dep not in _deps_usados:
            _deps_usados.add(_dep)
            _top3.append({**_c, "is_rongo_pick": True})
        if len(_top3) == 3: break
    # Completar si hace falta (incluso con contradicción)
    if len(_top3) < 3:
        for _c in candidates:
            _dep = _c.get("deporte","")
            already = any(t.get("label")==_c.get("label") for t in _top3)
            if not already and _dep not in {t.get("deporte") for t in _top3}:
                _top3.append({**_c, "is_rongo_pick": True})
            elif not already and len(_top3) < 3:
                _top3.append({**_c, "is_rongo_pick": True})
            if len(_top3) == 3: break

    return el_pick, contras, candidates[:20], _top3


def _kr_parlay_del_rey(todos):
    """
    Arma EL PARLAY DEL REY: los 3 mejores picks de deportes distintos
    sin contradicción, máxima prob combinada.
    Retorna lista de hasta 3 candidatos o [] si no hay suficientes.
    """
    sin_contra = [c for c in todos if not c.get("contradiccion") and c.get("prob",0) >= 0.63]
    # Un pick por deporte
    usados_deportes = set()
    parlay = []
    for c in sin_contra:
        dep = c["deporte"]
        if dep not in usados_deportes:
            usados_deportes.add(dep)
            parlay.append(c)
        if len(parlay) == 3:
            break
    return parlay


