# MÓDULO ÉLITE — 6 FUENTES AVANZADAS PARA EL MEJOR PICK
# Cada función es independiente, tiene cache propio, falla silenciosamente.
# Se integran en _fetch_real_xg_football y en _enrich_candidate KR.
# ══════════════════════════════════════════════════════════════════════════════

@st.cache_data(ttl=10800, show_spinner=False)
def _fbref_direct_stats(team_name: str, slug: str = "") -> dict:
    """
    FUENTE 1: FBref directo — xG, xGA, PPDA para TODAS las ligas (incluyendo MLS/Liga MX).
    FBref cubre 30+ ligas con datos Opta/StatsBomb.
    Estrategia: scrape de la tabla de equipos en la página de la liga.
    Cache 3h. Retorna dict con xg_for, xga, ppda, deep, npxg.
    """
    import re as _re
    _UA = "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36"

    # Mapeo slug → path FBref
    _fbref_paths = {
        "eng.1": "9/Premier-League", "esp.1": "12/La-Liga",
        "ger.1": "20/Bundesliga",    "ita.1": "11/Serie-A",
        "fra.1": "13/Ligue-1",       "ned.1": "23/Eredivisie",
        "por.1": "32/Primeira-Liga", "bel.1": "37/Belgian-Pro-League",
        "mex.1": "31/Liga-MX",       "usa.1": "22/Major-League-Soccer",
        "bra.1": "24/Serie-A",       "arg.1": "21/Primera-Division",
        "col.1": "41/Primera-A",     "chi.1": "35/Primera-Division",
        "uru.1": "45/Primera-Division","ecu.1":"44/Serie-A",
        "conmebol.libertadores": "14/Copa-Libertadores",
        "uefa.champions": "8/Champions-League",
        "sau.1": "70/Saudi-Professional-League",
        "jpn.1": "25/J1-League",     "kor.1": "55/K-League-1",
        "sco.1": "40/Scottish-Premiership",
        "tur.1": "26/Super-Lig",     "gre.1": "27/Super-League-1",
    }
    _path = _fbref_paths.get(slug, "")
    if not _path:
        # Intentar búsqueda genérica por nombre de liga
        return {}

    _default = {"xg_for": None, "xga": None, "ppda": None,
                "npxg": None, "deep": None, "source": "FBref"}
    try:
        # Página de stats de equipos — shooting + pressing
        _base = f"https://fbref.com/en/comps/{_path}-Stats"
        r = requests.get(_base, timeout=8,
                         headers={"User-Agent": _UA,
                                  "Accept-Language": "en-US,en;q=0.9"})
        if r.status_code != 200:
            return _default

        html = r.text
        # Buscar la fila del equipo en la tabla de stats de equipos
        _tname_lower = team_name.lower().strip()
        # Extraer todas las filas de equipos con sus stats xG
        # FBref usa data-stat="squad" para nombres de equipo
        rows = _re.findall(
            r'<tr[^>]*>.*?data-stat="squad"[^>]*>.*?<a[^>]*>([^<]+)</a>.*?'
            r'data-stat="xg_for_per90"[^>]*>([^<]*)</td>.*?'
            r'data-stat="xga_per90"[^>]*>([^<]*)</td>',
            html, _re.DOTALL | _re.IGNORECASE
        )
        for row in rows:
            squad_name = row[0].strip().lower()
            if (squad_name in _tname_lower or _tname_lower in squad_name or
                    any(w in squad_name for w in _tname_lower.split() if len(w) > 3)):
                try:
                    xg  = float(row[1]) if row[1].strip() else None
                    xga = float(row[2]) if row[2].strip() else None
                    return {**_default, "xg_for": xg, "xga": xga}
                except: pass

        # Fallback: buscar con regex más simple en el HTML completo
        _squad_pattern = _re.compile(
            r'<a[^>]+squads[^>]*>([^<]*' + _re.escape(team_name[:5]) + r'[^<]*)</a>',
            _re.IGNORECASE
        )
        _m = _squad_pattern.search(html)
        if _m:
            # Extraer números xG de las celdas cercanas
            pos = _m.start()
            nearby = html[pos:pos+800]
            nums = _re.findall(r'>(\d+\.\d+)<', nearby)
            if len(nums) >= 2:
                try:
                    return {**_default,
                            "xg_for": float(nums[0]),
                            "xga":    float(nums[1])}
                except: pass
    except: pass
    return _default


@st.cache_data(ttl=1800, show_spinner=False)  # 30 min — alineaciones cambian
def _fetch_lineup_sofascore(home: str, away: str, match_date: str = "") -> dict:
    """
    FUENTE 2: Alineaciones confirmadas via Sofascore API no oficial.
    Las alineaciones se publican ~60-90min antes del partido.
    Si no hay alineaciones, retorna vacío — NO penaliza al modelo.
    Cache 30min (se actualiza frecuentemente antes del partido).

    Retorna:
      home_xi: lista de jugadores titulares local (nombres)
      away_xi: lista de jugadores titulares visita
      home_missing_key: True si falta jugador clave (capitán/estrella)
      away_missing_key: True si falta jugador clave
      home_formation: ej "4-3-3"
      away_formation: ej "4-2-3-1"
      home_avg_rating: promedio de rating Sofascore de la alineación
      away_avg_rating: promedio de rating Sofascore de la alineación
      confirmed: True si las alineaciones están confirmadas
      prob_adj_h: ajuste sugerido de prob local (-0.08 a +0.05)
      prob_adj_a: ajuste sugerido de prob visita
    """
    import re as _re, json as _jsf
    _UA = "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36"

    _default = {
        "home_xi": [], "away_xi": [],
        "home_missing_key": False, "away_missing_key": False,
        "home_formation": "", "away_formation": "",
        "home_avg_rating": 7.0, "away_avg_rating": 7.0,
        "confirmed": False, "prob_adj_h": 0.0, "prob_adj_a": 0.0,
        "source_txt": ""
    }

    try:
        # Sofascore tiene una API JSON no documentada pero pública
        # Buscar el partido primero via search
        _search_url = "https://www.sofascore.com/api/v1/search/events"
        _q = f"{home} {away}"
        r_s = requests.get(_search_url, params={"q": _q, "page": 0},
                           headers={"User-Agent": _UA,
                                    "Referer": "https://www.sofascore.com/"},
                           timeout=6)
        if r_s.status_code != 200:
            # Fallback: buscar via Google News si el partido tiene alineaciones confirmadas
            import urllib.parse as _up, xml.etree.ElementTree as _ET
            q = f"{home} vs {away} lineup confirmed starting XI today"
            url_g = f"https://news.google.com/rss/search?q={_up.quote(q)}&hl=en&gl=US&ceid=US:en"
            r_g = requests.get(url_g, timeout=5, headers={"User-Agent": _UA})
            src_txt = ""
            if r_g.status_code == 200:
                root = _ET.fromstring(r_g.content)
                items = root.findall(".//item")[:3]
                titles = [it.findtext("title","") for it in items]
                _kw = ["confirmed","lineup","starting xi","team news","xi announced"]
                src_txt = " | ".join(t for t in titles if any(k in t.lower() for k in _kw))
            # Analizar si hay señales de bajas clave
            _key_absence_kw = ["without","misses","ruled out","injury","suspended","doubt"]
            _home_miss = any(kw in src_txt.lower() for kw in _key_absence_kw) and home.lower()[:5] in src_txt.lower()
            _away_miss = any(kw in src_txt.lower() for kw in _key_absence_kw) and away.lower()[:5] in src_txt.lower()
            return {**_default,
                    "home_missing_key": _home_miss,
                    "away_missing_key": _away_miss,
                    "prob_adj_h": -0.05 if _home_miss else 0.0,
                    "prob_adj_a": -0.05 if _away_miss else 0.0,
                    "source_txt": src_txt[:200] if src_txt else ""}

        events = r_s.json().get("events", []) or []
        # Encontrar el partido correcto
        _hn = home.lower()[:6]; _an = away.lower()[:6]
        match_ev = None
        for ev in events:
            _eh = (ev.get("homeTeam",{}).get("name","") or "").lower()
            _ea = (ev.get("awayTeam",{}).get("name","") or "").lower()
            if (_hn in _eh or _eh in home.lower()) and (_an in _ea or _ea in away.lower()):
                match_ev = ev
                break

        if not match_ev:
            return _default

        ev_id = match_ev.get("id")
        if not ev_id:
            return _default

        # Fetch alineaciones
        _lineup_url = f"https://www.sofascore.com/api/v1/event/{ev_id}/lineups"
        r_l = requests.get(_lineup_url,
                           headers={"User-Agent": _UA,
                                    "Referer": f"https://www.sofascore.com/"},
                           timeout=6)
        if r_l.status_code != 200:
            return _default

        ldata = r_l.json()
        _confirmed = ldata.get("confirmed", False)

        def _parse_team(tdata):
            if not tdata: return [], "", 7.0, False
            players = tdata.get("players", [])
            starters = [p for p in players if p.get("position") and not p.get("substitute", True)]
            if not starters:
                starters = players[:11]
            names = [p.get("player",{}).get("name","") for p in starters if p.get("player",{}).get("name")]
            formation = tdata.get("formation", "")
            ratings = [float(p.get("statistics",{}).get("rating", 7.0) or 7.0) for p in starters]
            avg_r = sum(ratings)/len(ratings) if ratings else 7.0
            # Detectar si falta jugador de alta rating (estrella)
            missing_key = avg_r < 6.5  # Rating promedio bajo = titulares normales no están
            return names, formation, round(avg_r, 2), missing_key

        home_data = ldata.get("home", {})
        away_data = ldata.get("away", {})
        h_names, h_form, h_rating, h_miss = _parse_team(home_data)
        a_names, a_form, a_rating, a_miss = _parse_team(away_data)

        # Ajuste de prob según rating promedio de alineación
        _rating_base = 7.0
        _prob_adj_h = (h_rating - _rating_base) * 0.025  # ±2.5% por punto de rating
        _prob_adj_a = (a_rating - _rating_base) * 0.025
        if h_miss: _prob_adj_h -= 0.06
        if a_miss: _prob_adj_a -= 0.06

        _src = f"Sofascore {'✅ Confirmado' if _confirmed else '⏳ Provisional'}"
        if h_rating != 7.0: _src += f" | {home[:10]} rating={h_rating:.1f}"
        if a_rating != 7.0: _src += f" | {away[:10]} rating={a_rating:.1f}"

        return {
            "home_xi": h_names, "away_xi": a_names,
            "home_missing_key": h_miss, "away_missing_key": a_miss,
            "home_formation": h_form, "away_formation": a_form,
            "home_avg_rating": h_rating, "away_avg_rating": a_rating,
            "confirmed": _confirmed,
            "prob_adj_h": max(-0.10, min(0.05, _prob_adj_h)),
            "prob_adj_a": max(-0.10, min(0.05, _prob_adj_a)),
            "source_txt": _src
        }
    except:
        return _default


@st.cache_data(ttl=3600, show_spinner=False)
def _fetch_odds_movement(home: str, away: str, slug: str = "") -> dict:
    """
    FUENTE 3: Movimiento de cuota (apertura vs actual) via The Odds API.
    Sharp money = cuota baja = apostar el mismo lado.
    Steam move = cuota baja rápido en múltiples libros = señal máxima.

    Retorna:
      open_h / open_a / open_d: cuotas de apertura
      curr_h / curr_a / curr_d: cuotas actuales
      move_h: movimiento local (positivo = más favorito = sharp en local)
      move_a: movimiento visita
      sharp_side: "home" | "away" | "draw" | "none"
      sharp_strength: 0-3 (0=nada, 1=suave, 2=moderado, 3=fuerte)
      ou_move: movimiento Over/Under ("over" | "under" | "none")
      clv_adj: ajuste CLV para el score (-2 a +3)
      source_txt: descripción del movimiento
    """
    _default = {
        "open_h": 0, "open_a": 0, "open_d": 0,
        "curr_h": 0, "curr_a": 0, "curr_d": 0,
        "move_h": 0.0, "move_a": 0.0,
        "sharp_side": "none", "sharp_strength": 0,
        "ou_move": "none", "clv_adj": 0.0,
        "source_txt": ""
    }

    _slug_map = {
        "eng.1":"soccer_epl","esp.1":"soccer_spain_la_liga",
        "ger.1":"soccer_germany_bundesliga","ita.1":"soccer_italy_serie_a",
        "fra.1":"soccer_france_ligue_one","ned.1":"soccer_netherlands_eredivisie",
        "por.1":"soccer_portugal_primeira_liga",
        "mex.1":"soccer_mexico_ligamx","usa.1":"soccer_usa_mls",
        "bra.1":"soccer_brazil_campeonato","arg.1":"soccer_argentina_primera_division",
        "col.1":"soccer_colombia_primera_a","chi.1":"soccer_chile_campeonato",
        "conmebol.libertadores":"soccer_conmebol_copa_libertadores",
        "uefa.champions":"soccer_uefa_champs_league",
        "uefa.europa":"soccer_uefa_europa_league",
        "sau.1":"soccer_saudi_professional_league",
        "jpn.1":"soccer_japan_j_league",
    }
    sport_key = _slug_map.get(slug)
    if not sport_key or not ODDS_API_KEY:
        return _default

    try:
        # The Odds API v4 — odds con timestamps para detectar movimiento
        url = f"https://api.the-odds-api.com/v4/sports/{sport_key}/odds"
        r = requests.get(url, params={
            "apiKey": ODDS_API_KEY,
            "regions": "eu,us",
            "markets": "h2h,totals",
            "oddsFormat": "decimal",
            "bookmakers": "pinnacle,betfair_ex_eu,bet365,williamhill,draftkings",
        }, timeout=8)

        if r.status_code != 200:
            return _default

        _hn = home.lower()[:6]; _an = away.lower()[:6]
        match = None
        for g in r.json():
            _gh = (g.get("home_team","") or "").lower()
            _ga = (g.get("away_team","") or "").lower()
            if (_hn in _gh or _gh in home.lower()) and (_an in _ga or _ga in away.lower()):
                match = g; break

        if not match:
            return _default

        # Recopilar cuotas por bookmaker — Pinnacle es el oráculo sharp
        _books_h = []; _books_a = []; _books_d = []
        _pin_h = _pin_a = _pin_d = 0
        _ou_over = []; _ou_under = []

        for bk in match.get("bookmakers", []):
            bk_name = bk.get("key","")
            for mkt in bk.get("markets", []):
                if mkt["key"] == "h2h":
                    for out in mkt.get("outcomes", []):
                        nm = out["name"].lower(); pr = float(out.get("price",0))
                        if _hn in nm:   _books_h.append(pr)
                        elif _an in nm: _books_a.append(pr)
                        elif "draw" in nm: _books_d.append(pr)
                    if bk_name == "pinnacle":
                        for out in mkt.get("outcomes", []):
                            nm = out["name"].lower(); pr = float(out.get("price",0))
                            if _hn in nm:   _pin_h = pr
                            elif _an in nm: _pin_a = pr
                            elif "draw" in nm: _pin_d = pr
                elif mkt["key"] == "totals":
                    for out in mkt.get("outcomes", []):
                        nm = out["name"].lower(); pr = float(out.get("price",0))
                        pt = out.get("point", 2.5)
                        if abs(pt - 2.5) < 0.1:
                            if "over"  in nm: _ou_over.append(pr)
                            elif "under" in nm: _ou_under.append(pr)

        if not _books_h:
            return _default

        # Promedios del mercado
        _avg_h = sum(_books_h)/len(_books_h) if _books_h else 0
        _avg_a = sum(_books_a)/len(_books_a) if _books_a else 0
        _avg_d = sum(_books_d)/len(_books_d) if _books_d else 0

        # Movimiento implied probability (sin cuotas históricas de apertura,
        # usamos dispersión entre libros como proxy de steam):
        # Si Pinnacle es más corto que el promedio = sharp money está en ese lado
        out_d = dict(_default)
        out_d["curr_h"] = round(_avg_h, 3)
        out_d["curr_a"] = round(_avg_a, 3)
        out_d["curr_d"] = round(_avg_d, 3)

        _src_parts = []
        sharp_side = "none"; sharp_strength = 0; clv_adj = 0.0

        if _pin_h > 0 and _avg_h > 0:
            # Pinnacle más corto que promedio = sharp en local
            _pin_impl_h = 1/_pin_h; _avg_impl_h = 1/_avg_h
            _pin_impl_a = 1/_pin_a if _pin_a > 0 else 0
            _avg_impl_a = 1/_avg_a if _avg_a > 0 else 0

            _steam_h = _pin_impl_h - _avg_impl_h  # positivo = sharp en local
            _steam_a = _pin_impl_a - _avg_impl_a  # positivo = sharp en visita

            out_d["move_h"] = round(_steam_h, 4)
            out_d["move_a"] = round(_steam_a, 4)

            _max_steam = max(abs(_steam_h), abs(_steam_a))
            if _steam_h > _steam_a and _steam_h > 0.02:
                sharp_side = "home"
                sharp_strength = 3 if _steam_h > 0.06 else (2 if _steam_h > 0.04 else 1)
                clv_adj = min(3.0, _steam_h * 40)
                _src_parts.append(f"📊 Sharp LOCAL: Pinnacle {_pin_h:.2f} vs mkt {_avg_h:.2f} (steam {_steam_h:+.1%})")
            elif _steam_a > _steam_h and _steam_a > 0.02:
                sharp_side = "away"
                sharp_strength = 3 if _steam_a > 0.06 else (2 if _steam_a > 0.04 else 1)
                clv_adj = -min(3.0, _steam_a * 40)  # negativo para el local
                _src_parts.append(f"📊 Sharp VISITA: Pinnacle {_pin_a:.2f} vs mkt {_avg_a:.2f} (steam {_steam_a:+.1%})")
            else:
                _src_parts.append(f"📊 Sin steam claro: Pin {_pin_h:.2f}/{_pin_a:.2f}")

        # O/U movement
        _avg_over  = sum(_ou_over)/len(_ou_over)   if _ou_over  else 0
        _avg_under = sum(_ou_under)/len(_ou_under) if _ou_under else 0
        if _avg_over > 0 and _avg_under > 0:
            # Cuota Over más baja que Under ajustado por margen → over favorite del mercado
            _impl_over  = 1/_avg_over
            _impl_under = 1/_avg_under
            if _impl_over > _impl_under + 0.04:
                out_d["ou_move"] = "over"
                _src_parts.append(f"⚽ Mercado favorece OVER ({_avg_over:.2f})")
            elif _impl_under > _impl_over + 0.04:
                out_d["ou_move"] = "under"
                _src_parts.append(f"🔒 Mercado favorece UNDER ({_avg_under:.2f})")

        out_d["sharp_side"]     = sharp_side
        out_d["sharp_strength"] = sharp_strength
        out_d["clv_adj"]        = round(clv_adj, 3)
        out_d["source_txt"]     = " | ".join(_src_parts) if _src_parts else "Odds API: sin movimiento sharp"
        return out_d

    except:
        return _default


# ══════════════════════════════════════════════════════════════════
# BET365 MARKET CONSENSUS — cuotas no-vig via BetsAPI (RapidAPI)
# Fuente: https://rapidapi.com/b365api-b365api-default/api/betsapi2
#
# Mercados extraídos:
#   1X2, Asian Handicap, O/U múltiples líneas (0.5-4.5), BTTS,
#   Draw No Bet, Double Chance, Halftime Result, 1st Half O/U,
#   Team Goals O/U (local/visita), Corners O/U, Cards O/U,
#   Match Result & O/U, BTTS & O/U
#
# Señales derivadas:
#   xG implícito del mercado (ajuste Poisson sobre líneas O/U)
#   xG por equipo (Team Goals O/U)
#   Asian Handicap line → margen de victoria esperado
#   Draw No Bet → fuerza real del favorito sin ruido de empate
#   Confluencia mercado vs modelo propio
# ══════════════════════════════════════════════════════════════════
@st.cache_data(ttl=1800, show_spinner=False)
def _b365_market_consensus(home: str, away: str, sport_id: int = 1) -> dict:
    """
    Cuotas Bet365 pre-partido → señales completas de mercado.
    sport_id: 1=Fútbol, 18=Basketball, 13=Tenis
    """
    _default = {
        "found": False,
        # 1X2 no-vig
        "ph_novig": 0.0, "pd_novig": 0.0, "pa_novig": 0.0,
        # O/U 2.5 no-vig
        "ou25_over_novig": 0.0, "ou25_under_novig": 0.0,
        # O/U todas las líneas
        "ou_lines": {},          # {0.5: p_over, 1.5: p_over, ...}
        # BTTS no-vig
        "btts_yes_novig": 0.0, "btts_no_novig": 0.0,
        # Draw No Bet no-vig
        "dnb_home_novig": 0.0, "dnb_away_novig": 0.0,
        # Double Chance no-vig
        "dc_1x_novig": 0.0, "dc_x2_novig": 0.0, "dc_12_novig": 0.0,
        # Halftime no-vig
        "ht_home_novig": 0.0, "ht_draw_novig": 0.0, "ht_away_novig": 0.0,
        # 1st Half O/U 0.5
        "ht_ou_over_novig": 0.0,
        # Team Goals O/U (xG implícito por equipo)
        "xg_home_impl": 0.0,    # goles esperados local según mercado
        "xg_away_impl": 0.0,    # goles esperados visita según mercado
        "xg_total_impl": 0.0,   # xG total implícito (ajuste Poisson)
        # Asian Handicap
        "ah_line": 0.0,          # línea AH (negativo = favorito local)
        "ah_home_novig": 0.0,
        "ah_away_novig": 0.0,
        # Corners O/U
        "corners_line": 0.0,
        "corners_over_novig": 0.0,
        # Cards O/U
        "cards_line": 0.0,
        "cards_over_novig": 0.0,
        # Combinados
        "combo_1x2_ou": {},      # {"home_over": p, "draw_over": p, ...}
        # Meta
        "market_favorite": "",
        "market_fav_prob": 0.0,
        "market_open_game": False,  # True si el mercado espera partido abierto
        "b365_raw": {},
        "source_txt": ""
    }

    if not BETSAPI_KEY:
        return _default

    _HEADERS = {
        "x-rapidapi-host": "betsapi2.p.rapidapi.com",
        "x-rapidapi-key": BETSAPI_KEY,
    }

    def _novig(probs: list) -> list:
        total = sum(p for p in probs if p > 0)
        if total <= 0: return probs
        return [p / total for p in probs]

    def _dec_to_impl(dec: float) -> float:
        return 1.0 / dec if dec > 1.0 else 0.0

    def _fuzzy(a: str, b: str) -> bool:
        a, b = a.lower().strip(), b.lower().strip()
        return a[:6] in b or b[:6] in a or a[:8] in b or b[:8] in a

    import math
    def _poisson_ou(lam: float, line: float) -> float:
        """P(goles > line) bajo Poisson(lam)."""
        k = int(line)
        try:
            p_under = sum(math.exp(-lam) * lam**i / math.factorial(i) for i in range(k+1))
            return max(0.0, min(1.0, 1.0 - p_under))
        except: return 0.5

    def _fit_poisson_xg(ou_lines_novig: dict) -> float:
        """Ajuste Poisson sobre múltiples líneas O/U → xG total del mercado."""
        if len(ou_lines_novig) < 2: return 0.0
        best_lam, best_err = 2.5, float('inf')
        for lam_x10 in range(5, 70):
            lam = lam_x10 / 10.0
            err = sum((_poisson_ou(lam, l) - p)**2 for l, p in ou_lines_novig.items())
            if err < best_err:
                best_err = err; best_lam = lam
        return round(best_lam, 2)

    try:
        # ── PASO 1: Buscar FI del evento ──────────────────────────────
        _fi = None
        _home_l = home.lower().strip()
        _away_l = away.lower().strip()

        for _page in range(1, 4):
            _r1 = requests.get(
                "https://betsapi2.p.rapidapi.com/v1/bet365/upcoming",
                headers=_HEADERS,
                params={"sport_id": sport_id, "page": _page},
                timeout=8
            )
            if _r1.status_code != 200: break
            _events = _r1.json().get("results", [])
            if not _events: break

            for _ev in _events:
                _ev_name = (_ev.get("name") or "").lower()
                _teams = _ev_name.replace(" vs ", "|").replace(" v ", "|").split("|")
                _ev_home = _teams[0].strip() if len(_teams) >= 2 else _ev_name
                _ev_away = _teams[1].strip() if len(_teams) >= 2 else _ev_name

                _h2 = (_ev.get("home", {}).get("name") or "").lower()
                _a2 = (_ev.get("away", {}).get("name") or "").lower()

                if (_fuzzy(_home_l, _ev_home) and _fuzzy(_away_l, _ev_away)) or \
                   (_h2 and _a2 and _fuzzy(_home_l, _h2) and _fuzzy(_away_l, _a2)):
                    _fi = _ev.get("id") or _ev.get("FI")
                    break
            if _fi: break

        if not _fi:
            return {**_default, "source_txt": "⚠️ Evento no encontrado en Bet365"}

        # ── PASO 2: Traer cuotas ──────────────────────────────────────
        _r2 = requests.get(
            "https://betsapi2.p.rapidapi.com/v3/bet365/prematch",
            headers=_HEADERS,
            params={"FI": _fi},
            timeout=8
        )
        if _r2.status_code != 200:
            return {**_default, "source_txt": f"⚠️ BetsAPI {_r2.status_code}"}

        _results = _r2.json().get("results", [])
        if not _results:
            return {**_default, "source_txt": "⚠️ Sin cuotas"}

        # ── PASO 3: Parsear estructura sp{} de BetsAPI ────────────────
        _raw = {}
        def _parse(obj, depth=0):
            if depth > 6 or not isinstance(obj, (dict, list)): return
            if isinstance(obj, list):
                for item in obj: _parse(item, depth+1)
                return
            _sp = obj.get("sp") or {}
            for _mid, _md in _sp.items():
                if not isinstance(_md, dict): continue
                _mname = (_md.get("name") or _mid).lower()
                _odds_list = _md.get("odds", [])
                _raw[_mname] = {}
                for _out in _odds_list:
                    _oname = (_out.get("name") or "").strip()
                    _oval  = float(_out.get("odds") or 0)
                    _hdr   = (_out.get("header") or "").strip()
                    _hdcp  = (_out.get("handicap") or "").strip()
                    _key   = "|".join(filter(None, [_oname, _hdr, _hdcp]))
                    if _oval > 1.0:
                        _raw[_mname][_key] = _oval
            # Recursivo para sub-estructuras
            for _v in obj.values():
                if isinstance(_v, (dict, list)): _parse(_v, depth+1)
        _parse(_results[0] if _results else {})

        # ── PASO 4: 1X2 ──────────────────────────────────────────────
        _ph_i = _pd_i = _pa_i = 0.0
        for _k, _mv in _raw.items():
            if any(t in _k for t in ["match result","1x2","full time result","match winner"]):
                for _ok, _ov in _mv.items():
                    _okl = _ok.lower()
                    if "home" in _okl or _ok.startswith("1|") or _ok == "1":
                        _ph_i = _dec_to_impl(_ov)
                    elif "draw" in _okl or _ok.lower().startswith("x"):
                        _pd_i = _dec_to_impl(_ov)
                    elif "away" in _okl or _ok.startswith("2|") or _ok == "2":
                        _pa_i = _dec_to_impl(_ov)
                break
        _ph_nv = _pd_nv = _pa_nv = 0.0
        if _ph_i > 0 and _pa_i > 0:
            _nv = _novig([_ph_i, _pd_i, _pa_i])
            _ph_nv, _pd_nv, _pa_nv = _nv

        # ── PASO 5: O/U todas las líneas ─────────────────────────────
        _ou_raw = {}     # line → (over_impl, under_impl)
        for _k, _mv in _raw.items():
            if any(t in _k for t in ["over/under","total goals","goals over","match goals"]):
                for _ok, _ov in _mv.items():
                    _okl = _ok.lower()
                    for _line in [0.5, 1.5, 2.5, 3.5, 4.5]:
                        if str(_line) in _ok:
                            _impl = _dec_to_impl(_ov)
                            if _line not in _ou_raw:
                                _ou_raw[_line] = [0.0, 0.0]
                            if "over" in _okl:
                                _ou_raw[_line][0] = _impl
                            elif "under" in _okl:
                                _ou_raw[_line][1] = _impl
                break

        _ou_lines_nv = {}
        _ou25_over_nv = _ou25_under_nv = 0.0
        for _line, (_ov_i, _un_i) in _ou_raw.items():
            if _ov_i > 0 and _un_i > 0:
                _nv2 = _novig([_ov_i, _un_i])
                _ou_lines_nv[_line] = _nv2[0]
                if _line == 2.5:
                    _ou25_over_nv, _ou25_under_nv = _nv2[0], _nv2[1]

        # xG total implícito del mercado (ajuste Poisson)
        _xg_total = _fit_poisson_xg(_ou_lines_nv) if len(_ou_lines_nv) >= 2 else 0.0

        # ── PASO 6: BTTS ─────────────────────────────────────────────
        _btts_y = _btts_n = 0.0
        for _k, _mv in _raw.items():
            if any(t in _k for t in ["both teams","btts","bts","gg/ng"]):
                for _ok, _ov in _mv.items():
                    _okl = _ok.lower()
                    if any(w in _okl for w in ["yes","gg","si"]): _btts_y = _dec_to_impl(_ov)
                    elif any(w in _okl for w in ["no","ng"]):     _btts_n = _dec_to_impl(_ov)
                break
        _btts_y_nv = _btts_n_nv = 0.0
        if _btts_y > 0 and _btts_n > 0:
            _nv3 = _novig([_btts_y, _btts_n])
            _btts_y_nv, _btts_n_nv = _nv3

        # ── PASO 7: Draw No Bet ───────────────────────────────────────
        _dnb_h = _dnb_a = 0.0
        for _k, _mv in _raw.items():
            if "draw no bet" in _k or "dnb" in _k:
                for _ok, _ov in _mv.items():
                    _okl = _ok.lower()
                    if "home" in _okl: _dnb_h = _dec_to_impl(_ov)
                    elif "away" in _okl: _dnb_a = _dec_to_impl(_ov)
                break
        _dnb_h_nv = _dnb_a_nv = 0.0
        if _dnb_h > 0 and _dnb_a > 0:
            _nv4 = _novig([_dnb_h, _dnb_a])
            _dnb_h_nv, _dnb_a_nv = _nv4

        # ── PASO 8: Double Chance ─────────────────────────────────────
        _dc_1x = _dc_x2 = _dc_12 = 0.0
        for _k, _mv in _raw.items():
            if "double chance" in _k:
                for _ok, _ov in _mv.items():
                    _okl = _ok.lower()
                    if "1x" in _okl or "home or draw" in _okl: _dc_1x = _dec_to_impl(_ov)
                    elif "x2" in _okl or "draw or away" in _okl: _dc_x2 = _dec_to_impl(_ov)
                    elif "12" in _okl or "home or away" in _okl: _dc_12 = _dec_to_impl(_ov)
                break
        _dc_1x_nv = _dc_x2_nv = _dc_12_nv = 0.0
        if _dc_1x > 0 and _dc_x2 > 0:
            _s = _dc_1x + _dc_x2 + _dc_12
            if _s > 0:
                _dc_1x_nv = _dc_1x/_s; _dc_x2_nv = _dc_x2/_s; _dc_12_nv = _dc_12/_s

        # ── PASO 9: Halftime Result ───────────────────────────────────
        _ht_h = _ht_d = _ht_a = 0.0
        for _k, _mv in _raw.items():
            if "half time result" in _k or "half-time result" in _k or "1st half result" in _k:
                for _ok, _ov in _mv.items():
                    _okl = _ok.lower()
                    if "home" in _okl: _ht_h = _dec_to_impl(_ov)
                    elif "draw" in _okl: _ht_d = _dec_to_impl(_ov)
                    elif "away" in _okl: _ht_a = _dec_to_impl(_ov)
                break
        _ht_h_nv = _ht_d_nv = _ht_a_nv = 0.0
        if _ht_h > 0 and _ht_a > 0:
            _nv5 = _novig([_ht_h, _ht_d, _ht_a])
            _ht_h_nv, _ht_d_nv, _ht_a_nv = _nv5

        # ── PASO 10: 1st Half O/U 0.5 ────────────────────────────────
        _ht_ou_over = 0.0
        for _k, _mv in _raw.items():
            if ("1st half" in _k or "half time" in _k) and ("goal" in _k or "over" in _k):
                for _ok, _ov in _mv.items():
                    if "0.5" in _ok and "over" in _ok.lower():
                        _ht_ou_raw = _dec_to_impl(_ov)
                        # Buscar el under correspondiente
                        _ht_un = next((v for k2,v in _mv.items() if "0.5" in k2 and "under" in k2.lower()), 0)
                        if _ht_un > 0:
                            _ht_ou_over = _novig([_ht_ou_raw, _dec_to_impl(_ht_un)])[0]
                        break
                break

        # ── PASO 11: Team Goals O/U → xG implícito por equipo ─────────
        _xg_home = _xg_away = 0.0
        _team_ou_home = {}
        _team_ou_away = {}
        for _k, _mv in _raw.items():
            _is_home = "home team" in _k and ("goal" in _k or "over" in _k)
            _is_away = "away team" in _k and ("goal" in _k or "over" in _k)
            if _is_home or _is_away:
                _target = _team_ou_home if _is_home else _team_ou_away
                for _ok, _ov in _mv.items():
                    for _tline in [0.5, 1.5, 2.5]:
                        if str(_tline) in _ok:
                            _impl_v = _dec_to_impl(_ov)
                            if "over" in _ok.lower():
                                if _tline not in _target: _target[_tline] = [0.0, 0.0]
                                _target[_tline][0] = _impl_v
                            elif "under" in _ok.lower():
                                if _tline not in _target: _target[_tline] = [0.0, 0.0]
                                _target[_tline][1] = _impl_v

        _team_ou_home_nv = {}
        _team_ou_away_nv = {}
        for _tl, (_ov_i, _un_i) in _team_ou_home.items():
            if _ov_i > 0 and _un_i > 0:
                _team_ou_home_nv[_tl] = _novig([_ov_i, _un_i])[0]
        for _tl, (_ov_i, _un_i) in _team_ou_away.items():
            if _ov_i > 0 and _un_i > 0:
                _team_ou_away_nv[_tl] = _novig([_ov_i, _un_i])[0]

        if len(_team_ou_home_nv) >= 1:
            _xg_home = _fit_poisson_xg(_team_ou_home_nv)
        if len(_team_ou_away_nv) >= 1:
            _xg_away = _fit_poisson_xg(_team_ou_away_nv)

        # Si no hay team O/U, estimar desde xG total + BTTS
        if _xg_total > 0 and _xg_home == 0 and _xg_away == 0:
            if _btts_y_nv > 0.5:
                # Partido abierto → distribución más simétrica
                _h_share = _ph_nv if _ph_nv > 0 else 0.55
                _xg_home = round(_xg_total * (_h_share * 0.6 + 0.4 * 0.5), 2)
                _xg_away = round(_xg_total - _xg_home, 2)
            elif _ph_nv > 0:
                _xg_home = round(_xg_total * 0.58, 2)
                _xg_away = round(_xg_total * 0.42, 2)

        # ── PASO 12: Asian Handicap ───────────────────────────────────
        _ah_line = _ah_h = _ah_a = 0.0
        for _k, _mv in _raw.items():
            if "asian handicap" in _k:
                # Buscar la línea principal (más cercana a 0)
                _best_line = None; _best_dist = 99
                for _ok, _ov in _mv.items():
                    # Extraer número del handicap
                    _nums = re.findall(r'[-+]?\d+\.?\d*', _ok)
                    if _nums:
                        _n = float(_nums[0])
                        if abs(_n) < _best_dist:
                            _best_dist = abs(_n); _best_line = _n
                if _best_line is not None:
                    _ah_line = _best_line
                    for _ok, _ov in _mv.items():
                        if str(_best_line) in _ok or str(abs(_best_line)) in _ok:
                            if "home" in _ok.lower(): _ah_h = _dec_to_impl(_ov)
                            elif "away" in _ok.lower(): _ah_a = _dec_to_impl(_ov)
                if _ah_h > 0 and _ah_a > 0:
                    _nv_ah = _novig([_ah_h, _ah_a])
                    _ah_h, _ah_a = _nv_ah
                break

        # ── PASO 13: Corners O/U ─────────────────────────────────────
        _corn_line = _corn_over = 0.0
        for _k, _mv in _raw.items():
            if "corner" in _k and ("over" in _k or "under" in _k or "total" in _k):
                for _ok, _ov in _mv.items():
                    _nums2 = re.findall(r'\d+\.?\d*', _ok)
                    if _nums2 and "over" in _ok.lower():
                        _cl = float(_nums2[0])
                        if 8.0 <= _cl <= 11.0:  # líneas comunes
                            _corn_line = _cl
                            _corn_u = next((v for k2,v in _mv.items() if str(_cl) in k2 and "under" in k2.lower()), 0)
                            if _corn_u > 0:
                                _corn_over = _novig([_dec_to_impl(_ov), _dec_to_impl(_corn_u)])[0]
                            break
                break

        # ── PASO 14: Cards O/U ───────────────────────────────────────
        _cards_line = _cards_over = 0.0
        for _k, _mv in _raw.items():
            if ("card" in _k or "booking" in _k) and ("over" in _k or "under" in _k or "total" in _k):
                for _ok, _ov in _mv.items():
                    _nums3 = re.findall(r'\d+\.?\d*', _ok)
                    if _nums3 and "over" in _ok.lower():
                        _cardl = float(_nums3[0])
                        if 2.0 <= _cardl <= 6.0:
                            _cards_line = _cardl
                            _card_u = next((v for k2,v in _mv.items() if str(_cardl) in k2 and "under" in k2.lower()), 0)
                            if _card_u > 0:
                                _cards_over = _novig([_dec_to_impl(_ov), _dec_to_impl(_card_u)])[0]
                            break
                break

        # ── PASO 15: Combinados 1X2 & O/U ────────────────────────────
        _combo = {}
        for _k, _mv in _raw.items():
            if ("result" in _k or "1x2" in _k) and ("over" in _k or "under" in _k or "goals" in _k):
                for _ok, _ov in _mv.items():
                    _okl = _ok.lower()
                    _ckey = None
                    if "home" in _okl and "over" in _okl: _ckey = "home_over"
                    elif "home" in _okl and "under" in _okl: _ckey = "home_under"
                    elif "draw" in _okl and "over" in _okl: _ckey = "draw_over"
                    elif "draw" in _okl and "under" in _okl: _ckey = "draw_under"
                    elif "away" in _okl and "over" in _okl: _ckey = "away_over"
                    elif "away" in _okl and "under" in _okl: _ckey = "away_under"
                    if _ckey:
                        _combo[_ckey] = round(_dec_to_impl(_ov), 4)
                if _combo: break

        # ── PASO 16: Señales derivadas ────────────────────────────────
        _market_fav = "home"; _market_fav_p = _ph_nv
        if _pa_nv > _ph_nv and _pa_nv > _pd_nv: _market_fav = "away"; _market_fav_p = _pa_nv
        elif _pd_nv > _ph_nv and _pd_nv > _pa_nv: _market_fav = "draw"; _market_fav_p = _pd_nv

        # Partido abierto: BTTS alto + O/U 2.5 alto
        _open_game = (_btts_y_nv >= 0.55 and _ou25_over_nv >= 0.58)

        # ── Texto de diagnóstico ──────────────────────────────────────
        _parts = []
        if _ph_nv > 0:
            _parts.append(f"🎰 B365 1X2: L={_ph_nv:.0%} E={_pd_nv:.0%} V={_pa_nv:.0%}")
        if _xg_total > 0:
            _parts.append(f"xG_mkt={_xg_total:.1f}({_xg_home:.1f}h/{_xg_away:.1f}v)")
        if _btts_y_nv > 0:
            _parts.append(f"BTTS={_btts_y_nv:.0%}")
        if _ou25_over_nv > 0:
            _parts.append(f"O2.5={_ou25_over_nv:.0%}")
        if _ah_line != 0:
            _parts.append(f"AH={_ah_line:+.1f}")
        if _dnb_h_nv > 0:
            _parts.append(f"DNB_H={_dnb_h_nv:.0%}")
        if _corn_over > 0:
            _parts.append(f"Corn>{_corn_line:.0f}={_corn_over:.0%}")

        return {
            "found": True,
            "ph_novig": round(_ph_nv, 4), "pd_novig": round(_pd_nv, 4), "pa_novig": round(_pa_nv, 4),
            "ou25_over_novig": round(_ou25_over_nv, 4), "ou25_under_novig": round(1-_ou25_over_nv, 4),
            "ou_lines": {str(k): round(v,4) for k,v in _ou_lines_nv.items()},
            "btts_yes_novig": round(_btts_y_nv, 4), "btts_no_novig": round(_btts_n_nv, 4),
            "dnb_home_novig": round(_dnb_h_nv, 4), "dnb_away_novig": round(_dnb_a_nv, 4),
            "dc_1x_novig": round(_dc_1x_nv, 4), "dc_x2_novig": round(_dc_x2_nv, 4), "dc_12_novig": round(_dc_12_nv, 4),
            "ht_home_novig": round(_ht_h_nv, 4), "ht_draw_novig": round(_ht_d_nv, 4), "ht_away_novig": round(_ht_a_nv, 4),
            "ht_ou_over_novig": round(_ht_ou_over, 4),
            "xg_home_impl": round(_xg_home, 2), "xg_away_impl": round(_xg_away, 2), "xg_total_impl": round(_xg_total, 2),
            "ah_line": _ah_line, "ah_home_novig": round(_ah_h, 4), "ah_away_novig": round(_ah_a, 4),
            "corners_line": _corn_line, "corners_over_novig": round(_corn_over, 4),
            "cards_line": _cards_line, "cards_over_novig": round(_cards_over, 4),
            "combo_1x2_ou": _combo,
            "market_favorite": _market_fav, "market_fav_prob": round(_market_fav_p, 4),
            "market_open_game": _open_game,
            "b365_raw": _raw,
            "source_txt": " · ".join(_parts)
        }

    except Exception as _e:
        return {**_default, "source_txt": f"⚠️ BetsAPI exc: {str(_e)[:80]}"}


@st.cache_data(ttl=7200, show_spinner=False)
def _fetch_referee_stats(home: str, away: str, slug: str = "") -> dict:
    """
    FUENTE 4: Árbitro — historial de tarjetas y Over/Under via Google News + Transfermarkt.
    Un árbitro permisivo sube Over. Uno estricto baja Over y sube Under.

    Retorna:
      referee_name: nombre del árbitro (vacío si no se encontró)
      avg_cards: promedio tarjetas/partido del árbitro
      avg_goals: promedio goles/partido partidos arbitrados
      over_tendency: True si tiende a Over
      ou_adj: ajuste O/U por árbitro (-0.04 a +0.04)
      cards_adj: ajuste de picks de tarjetas
      source_txt: descripción
    """
    import re as _re
    _UA = "Mozilla/5.0"

    _default = {
        "referee_name": "", "avg_cards": 3.5, "avg_goals": 2.6,
        "over_tendency": False, "ou_adj": 0.0, "cards_adj": 0.0,
        "source_txt": ""
    }

    def _gnews(q, n=5):
        try:
            import urllib.parse as _up, xml.etree.ElementTree as _ET
            url = f"https://news.google.com/rss/search?q={_up.quote(q)}&hl=es&gl=MX&ceid=MX:es"
            r = requests.get(url, timeout=5, headers={"User-Agent": _UA})
            if r.status_code != 200: return []
            root = _ET.fromstring(r.content)
            return [it.findtext("title","") + " " + (it.findtext("description","") or "")
                    for it in root.findall(".//item")[:n]]
        except: return []

    try:
        # 1. Encontrar el árbitro asignado
        texts_ref = _gnews(f"{home} vs {away} arbitro referee designado partido", n=5)
        referee = ""
        _ref_patterns = [
            r'árbitro[:\s]+([A-ZÁÉÍÓÚÑ][a-záéíóúñ]+\s+[A-ZÁÉÍÓÚÑ][a-záéíóúñ]+)',
            r'referee[:\s]+([A-Z][a-z]+\s+[A-Z][a-z]+)',
            r'dirigido por\s+([A-ZÁÉÍÓÚÑ][a-záéíóúñ]+\s+[A-ZÁÉÍÓÚÑ][a-záéíóúñ]+)',
        ]
        for t in texts_ref:
            for pat in _ref_patterns:
                m = _re.search(pat, t, _re.IGNORECASE)
                if m:
                    referee = m.group(1).strip()
                    break
            if referee: break

        if not referee:
            return _default

        # 2. Historial del árbitro
        texts_hist = _gnews(f'árbitro "{referee}" tarjetas goles partido historial estadísticas', n=5)
        texts_hist += _gnews(f'referee "{referee}" cards goals per game statistics', n=3)

        _src_parts = [f"Árbitro: {referee}"]
        avg_cards = 3.5; avg_goals = 2.6; over_tendency = False

        # Extraer estadísticas del árbitro de los snippets
        for t in texts_hist:
            tl = t.lower()
            # Tarjetas por partido
            m_cards = _re.search(r'(\d+\.?\d*)\s*(tarjetas?|cards?)\s*(por|per)\s*(partido|game)', tl)
            if m_cards:
                v = float(m_cards.group(1))
                if 0 < v < 15: avg_cards = v; _src_parts.append(f"{v:.1f} tarjetas/p")
            # Goles por partido
            m_goals = _re.search(r'(\d+\.?\d*)\s*(goles?|goals?)\s*(por|per)\s*(partido|game)', tl)
            if m_goals:
                v = float(m_goals.group(1))
                if 0 < v < 10: avg_goals = v; _src_parts.append(f"{v:.1f} goles/p")
            # Señales Over
            if any(kw in tl for kw in ["permissive","permisivo","muchos goles","high scoring"]):
                over_tendency = True
            if any(kw in tl for kw in ["strict","estricto","pocos goles","low scoring"]):
                over_tendency = False

        # Calcular ajuste O/U por árbitro
        _league_avg_goals = 2.65  # promedio general
        if avg_goals > _league_avg_goals + 0.4:
            ou_adj = +0.035; over_tendency = True
            _src_parts.append("↑ Favorece Over")
        elif avg_goals < _league_avg_goals - 0.4:
            ou_adj = -0.035
            _src_parts.append("↓ Favorece Under")
        else:
            ou_adj = (avg_goals - _league_avg_goals) * 0.05

        # Ajuste de mercados de tarjetas
        cards_adj = (avg_cards - 3.5) * 0.04  # +4% prob por tarjeta extra vs promedio

        return {
            "referee_name": referee,
            "avg_cards": round(avg_cards, 1),
            "avg_goals": round(avg_goals, 1),
            "over_tendency": over_tendency,
            "ou_adj": round(max(-0.04, min(0.04, ou_adj)), 4),
            "cards_adj": round(cards_adj, 3),
            "source_txt": " | ".join(_src_parts)
        }
    except:
        return _default


@st.cache_data(ttl=3600, show_spinner=False)
def _fetch_alt_markets(home: str, away: str, slug: str = "",
                       hxg: float = 1.2, axg: float = 1.0,
                       ph: float = 0.45, pd: float = 0.27, pa: float = 0.28) -> dict:
    """
    FUENTE 5: Mercados alternativos — corners, tarjetas, primer gol, handicap asiático.
    Actualmente no analizados en el modelo base.

    Calcula probabilidades basadas en xG del partido y datos de liga.
    Retorna picks con EV estimado para cada mercado alternativo.

    Retorna dict con picks_alt: lista de dicts {mercado, pick, prob, odd_ref, ev, desc}
    """
    import math as _math

    # ── Modelo de corners basado en xG total (calibrado Opta 2020-25) ──
    # Correlación corners ~ 0.71 con ataques totales
    # Formula: E(corners) = 9.2 + (hxg + axg - 2.5) * 2.1
    _xg_total = hxg + axg
    _exp_corners = max(5.0, min(18.0, 9.2 + (_xg_total - 2.5) * 2.1))
    # Distribución Poisson para corners
    def _pois_gt(lam, k):
        """P(X > k) con distribución Poisson."""
        prob = 0.0
        for i in range(int(k)+1):
            prob += _math.exp(-lam) * lam**i / _math.factorial(min(i, 20))
        return max(0, min(1, 1 - prob))

    _p_corners_over9   = _pois_gt(_exp_corners, 8.5)
    _p_corners_over10  = _pois_gt(_exp_corners, 9.5)
    _p_corners_over11  = _pois_gt(_exp_corners, 10.5)
    _p_corners_under9  = 1 - _p_corners_over9
    _p_corners_under10 = 1 - _p_corners_over10

    # ── Modelo de tarjetas basado en liga y paridad ──
    # Partidos equilibrados → más tarjetas. Partidos desequilibrados → menos.
    _match_balance = abs(ph - pa)  # 0 = parejo, 1 = unilateral
    _exp_cards = max(1.5, min(8.0, 3.8 - _match_balance * 1.2))
    _p_cards_over3  = _pois_gt(_exp_cards, 2.5)
    _p_cards_over4  = _pois_gt(_exp_cards, 3.5)
    _p_cards_under3 = 1 - _p_cards_over3

    # ── Primer gol: local vs visita ──
    # P(local marca primero) ~ ph_scoring_first
    # Calibración: local marca primero en ~58% cuando ph=0.5, escala con ph
    _p_home_first = max(0.30, min(0.75, 0.42 + ph * 0.32))
    _p_away_first = max(0.15, min(0.55, 0.28 + pa * 0.30))
    _p_no_goal_first_half = max(0.05, 1 - min(0.95, _xg_total * 0.28))

    # ── Handicap Asiático ──
    # AH -0.5 local = local gana (sin empate). AH +0.5 visita = visita gana o empata.
    _p_ah_home_minus05 = ph          # = ph (gana sin handicap)
    _p_ah_away_plus05  = pa + pd     # = pa + empate

    # ── Construir lista de picks con EV estimado ──
    # Cuotas de referencia calibradas con datos históricos de Pinnacle
    picks_alt = []

    def _ev(p, o): return p*(o-1) - (1-p)

    _candidates = [
        ("🔲 Corners Over 9.5",  _p_corners_over10,  1.92, "corners"),
        ("🔲 Corners Over 10.5", _p_corners_over11,  2.20, "corners"),
        ("🔲 Corners Under 9.5", _p_corners_under10, 1.88, "corners"),
        ("🟡 Cards Over 3.5",    _p_cards_over4,     1.95, "cards"),
        ("🟡 Cards Under 3.5",   _p_cards_under3,    1.85, "cards"),
        ("⚡ 1er Gol Local",     _p_home_first,      2.30, "firstgoal"),
        ("⚡ 1er Gol Visita",    _p_away_first,      2.80, "firstgoal"),
        (f"🎯 AH {home[:10]} -0.5", _p_ah_home_minus05, 2.05, "ah"),
        (f"🎯 AH {away[:10]} +0.5", _p_ah_away_plus05,  1.85, "ah"),
    ]

    for lbl, prob, odd_ref, mkt in _candidates:
        ev = _ev(prob, odd_ref)
        if prob >= 0.42 and ev > -0.05:  # umbral bajo para mercados alt
            picks_alt.append({
                "mercado": mkt, "pick": lbl, "prob": round(prob, 3),
                "odd_ref": odd_ref, "ev": round(ev, 4),
                "desc": f"{prob*100:.1f}% · EV {ev:+.2f}"
            })

    # Ordenar por EV
    picks_alt.sort(key=lambda x: -x["ev"])

    return {
        "picks_alt": picks_alt[:6],
        "exp_corners": round(_exp_corners, 1),
        "exp_cards":   round(_exp_cards,   1),
        "p_home_first": round(_p_home_first, 3),
        "best_alt_pick": picks_alt[0] if picks_alt else None,
    }


@st.cache_data(ttl=10800, show_spinner=False)
def _fetch_full_intel(home: str, away: str, slug: str = "",
                      hxg: float = 1.2, axg: float = 1.0,
                      ph: float = 0.45, pd: float = 0.27, pa: float = 0.28,
                      match_date: str = "") -> dict:
    """
    FUENTE 6 (ORQUESTADOR): Ejecuta las 5 fuentes en paralelo y retorna
    un dict unificado con todos los ajustes listos para aplicar al modelo.

    Este es el único punto de entrada que llaman KR, diamond_engine y la cartelera.
    Reemplaza las llamadas individuales y garantiza un máximo de latencia de 12s.

    Retorna:
      xg_adj_h / xg_adj_a: ajuste TOTAL de xG (acumulado de todas las fuentes)
      prob_adj_h / prob_adj_a: ajuste TOTAL de prob (post-xG)
      ou_adj: ajuste acumulado Over/Under
      sharp_side: "home"|"away"|"none"
      sharp_strength: 0-3
      alt_picks: lista de picks alternativos (corners, tarjetas, etc.)
      confidence: "alta"|"media"|"baja"
      sources_used: lista de fuentes que retornaron datos reales
      source_summary: string para mostrar en UI y reasoning
    """
    import concurrent.futures as _cffi

    out = {
        "xg_adj_h": 0.0, "xg_adj_a": 0.0,
        "prob_adj_h": 0.0, "prob_adj_a": 0.0,
        "ou_adj": 0.0, "sharp_side": "none", "sharp_strength": 0,
        "alt_picks": [], "confidence": "baja",
        "sources_used": [], "source_summary": "",
        "lineup_confirmed": False,
        "referee": "", "referee_ou_adj": 0.0,
    }

    with _cffi.ThreadPoolExecutor(max_workers=5) as ex:
        futs = {
            "fbref":   ex.submit(_fbref_direct_stats, home, slug),
            "lineup":  ex.submit(_fetch_lineup_sofascore, home, away, match_date),
            "odds_mv": ex.submit(_fetch_odds_movement, home, away, slug),
            "referee": ex.submit(_fetch_referee_stats, home, away, slug),
            "alt_mkt": ex.submit(_fetch_alt_markets, home, away, slug, hxg, axg, ph, pd, pa),
        }
        res = {}
        for k, f in futs.items():
            try: res[k] = f.result(timeout=12)
            except: res[k] = {}

    _src_parts = []; _conf_pts = 0

    # ── FBref direct ──
    fbref = res.get("fbref") or {}
    if fbref.get("xg_for") is not None:
        # Ajuste de xG local basado en datos FBref directos
        _xg_diff_h = fbref["xg_for"] - hxg
        out["xg_adj_h"] += _xg_diff_h * 0.35  # blend 35% FBref
        _src_parts.append(f"FBref {home[:8]}: xG {fbref['xg_for']:.2f}/p")
        _conf_pts += 2
    if fbref.get("xga") is not None:
        # xGA del local → afecta al visitante
        _xga_diff = fbref["xga"] - axg
        out["xg_adj_a"] += _xga_diff * 0.20
        _src_parts.append(f"xGA {fbref['xga']:.2f}/p")
        out["sources_used"].append("FBref")

    # ── Alineaciones confirmadas ──
    lineup = res.get("lineup") or {}
    if lineup.get("confirmed") or lineup.get("prob_adj_h") or lineup.get("prob_adj_a"):
        out["prob_adj_h"] += lineup.get("prob_adj_h", 0.0)
        out["prob_adj_a"] += lineup.get("prob_adj_a", 0.0)
        if lineup.get("confirmed"):
            _src_parts.append(f"✅ Alineaciones confirmadas · {lineup.get('home_formation','')} vs {lineup.get('away_formation','')}")
            out["lineup_confirmed"] = True
            _conf_pts += 2
        elif lineup.get("source_txt"):
            _src_parts.append(lineup["source_txt"][:60])
        if lineup.get("home_missing_key") or lineup.get("away_missing_key"):
            _src_parts.append("⚠️ Posible baja de titular")
            _conf_pts += 1
        out["sources_used"].append("Sofascore")

    # ── Movimiento de cuota (Sharp money) ──
    odds_mv = res.get("odds_mv") or {}
    if odds_mv.get("sharp_strength", 0) >= 1:
        out["sharp_side"]     = odds_mv["sharp_side"]
        out["sharp_strength"] = odds_mv["sharp_strength"]
        out["ou_adj"]        += odds_mv.get("ou_move_adj", 0.0)
        # Si sharp está en local → boost prob local
        if odds_mv["sharp_side"] == "home":
            out["prob_adj_h"] += min(0.06, odds_mv["sharp_strength"] * 0.02)
        elif odds_mv["sharp_side"] == "away":
            out["prob_adj_a"] += min(0.06, odds_mv["sharp_strength"] * 0.02)
        _src_parts.append(odds_mv.get("source_txt","")[:80])
        _conf_pts += odds_mv["sharp_strength"]
        out["sources_used"].append("Sharp/Pinnacle")

    # O/U movement
    _ou_mv = odds_mv.get("ou_move","none")
    if _ou_mv == "over":
        out["ou_adj"] += 0.025
        _src_parts.append("📈 Mercado mueve a Over")
    elif _ou_mv == "under":
        out["ou_adj"] -= 0.025
        _src_parts.append("📉 Mercado mueve a Under")

    # ── Árbitro ──
    ref = res.get("referee") or {}
    if ref.get("referee_name"):
        out["referee"]        = ref["referee_name"]
        out["referee_ou_adj"] = ref.get("ou_adj", 0.0)
        out["ou_adj"]        += ref.get("ou_adj", 0.0)
        _src_parts.append(ref.get("source_txt","")[:60])
        _conf_pts += 1
        out["sources_used"].append(f"Árbitro:{ref['referee_name'][:12]}")

    # ── Mercados alternativos ──
    alt = res.get("alt_mkt") or {}
    out["alt_picks"] = alt.get("picks_alt", [])
    if alt.get("best_alt_pick"):
        _src_parts.append(f"🎯 Alt: {alt['best_alt_pick']['pick']} {alt['best_alt_pick']['prob']*100:.0f}%")
        out["sources_used"].append("AltMarkets")

    out["confidence"]      = "alta" if _conf_pts >= 4 else ("media" if _conf_pts >= 2 else "baja")
    out["source_summary"]  = " · ".join(_src_parts) if _src_parts else "Sin datos de fuentes externas"
    return out


@st.cache_data(ttl=7200, show_spinner=False)
def _small_days_analyze(home: str, away: str, sport: str,
                         fecha: str,
                         home_id: str = "", away_id: str = "",
                         slug: str = "",
                         context_hint: str = "") -> dict:
    """
    Small Days \u2014 Motor de ponderación de 60+ variables ocultas.
    Fusiona 3 fuentes reales + Claude Haiku con scoring estructurado.

    Score = \u03a3(variable_detectada \u00d7 peso) por equipo
    Cuando score_negativo > umbral \u2192 prob real baja significativamente.

    Retorna deltas calibrados que se aplican silenciosamente a todos los picks.
    Cache 1 hora. Se llama en todos los deportes.
    """
    _default = {
        "soft_delta": 0.0, "home_delta": 0.0, "away_delta": 0.0,
        "ou_delta": 0.0, "flags": [], "confidence": "baja",
        "raw_summary": "", "score_h": 0.0, "score_a": 0.0,
    }
    try:
        # ── Fetch REALMENTE paralelo: todas las fuentes simultáneas ──
        import concurrent.futures as _cf_sd
        _espn_h = _espn_a = _google_h = _google_a = _ten_h = _ten_a = ""
        _sport_q = {"futbol":"fútbol","nba":"NBA","tenis":"tenis"}.get(sport, sport)

        with _cf_sd.ThreadPoolExecutor(max_workers=6) as _exsd:
            _futs_sd = {}
            if sport in ("futbol", "nba") and home_id:
                _futs_sd["espn_h"] = _exsd.submit(_sd_espn_injuries, home_id, slug, sport)
            if sport in ("futbol", "nba") and away_id:
                _futs_sd["espn_a"] = _exsd.submit(_sd_espn_injuries, away_id, slug, sport)
            _futs_sd["google_h"] = _exsd.submit(_sd_google_news, f"{home} {_sport_q} lesion injury noticias")
            _futs_sd["google_a"] = _exsd.submit(_sd_google_news, f"{away} {_sport_q} lesion injury noticias")
            if sport == "tenis":
                _futs_sd["ten_h"] = _exsd.submit(_sd_tennis_news, home)
                _futs_sd["ten_a"] = _exsd.submit(_sd_tennis_news, away)
            for _k, _fut in _futs_sd.items():
                try:
                    val = _fut.result(timeout=5)
                    if _k == "espn_h":   _espn_h   = val
                    elif _k == "espn_a": _espn_a   = val
                    elif _k == "google_h": _google_h = val
                    elif _k == "google_a": _google_a = val
                    elif _k == "ten_h":  _ten_h    = val
                    elif _k == "ten_a":  _ten_a    = val
                except: pass

        _all_info = []
        if _espn_h:   _all_info.append(f"ESPN LOCAL ({home}): {_espn_h}")
        if _espn_a:   _all_info.append(f"ESPN VISITA ({away}): {_espn_a}")
        if _google_h: _all_info.append(f"NOTICIAS LOCAL ({home}): {_google_h}")
        if _google_a: _all_info.append(f"NOTICIAS VISITA ({away}): {_google_a}")
        if _ten_h:    _all_info.append(f"TENNIS-API ({home}): {_ten_h}")
        if _ten_a:    _all_info.append(f"TENNIS-API ({away}): {_ten_a}")

        # ── Enriquecer con datos avanzados (FBref, Understat, Transfermarkt, SoccerStats) ──
        try:
            _adv_sd = _fetch_advanced_stats_for_match(home, away, sport, slug)
            if _adv_sd:
                _all_info.append(_adv_sd)
        except: pass

        if not _all_info:
            return _default

        _news = "\n".join(_all_info)
        _sport_es = {"futbol":"fútbol","nba":"baloncesto NBA","tenis":"tenis"}.get(sport, sport)

        # ── Prompt con tabla de ponderación completa ──
        _prompt = f"""Eres Small Days, motor de inteligencia soft para apuestas deportivas.
Partido de {_sport_es}: {away} @ {home} — {fecha}
Modelo base: {context_hint[:150] if context_hint else "N/A"}

DATOS REALES (ESPN + Google News + FBref + Understat + Transfermarkt + SoccerStats + Sofascore):
{_news[:2500]}

INSTRUCCI\u00d3N: Evalúa cada variable que encuentres en los datos. Usa esta tabla de pesos:

F\u00cdSICO: fatiga_acumulada=5, microlesion_oculta=5, recuperacion_incompleta=5,
        dormir_mal=4, jet_lag=4, deshidratacion=4, resaca=4, enfermedad_leve=4,
        alimentacion_mala=3, medicamentos=3

EMOCIONAL: fallecimiento_cercano=5, ansiedad_presion=4, miedo_titularidad=4,
           baja_confianza=4, divorcio=4, problemas_disciplinarios=4,
           pareja=3, pelea_familiar=3, criticas_redes=3, quiere_irse=3

MOTIVACION: problemas_entrenador=5, quiere_mostrarse=4, nervios_partido_grande=4,
            temporada_perdida=4, contrato_negociacion=3, fiestas_recientes=3,
            problemas_legales=4, rumores_transferencia=3

EQUIPO: conflictos_vestuario=5, problemas_salariales=5, mala_relacion_entrenador=5,
        calendario_congestionado=5, cambio_entrenador=4, jugadores_divididos=4,
        falta_liderazgo=4, viaje_largo=4, estrategia_mal_preparada=4,
        clima_extremo=4, altitud=4

PARTIDO: evitar_descenso=5, clasificar_torneo=5, clasico=4, partido_irrelevante=4,
         rival_debil_relajacion=3, rival_fuerte_motivacion=3, partido_revancha=3,
         estadio_hostil=3

Para LOCAL ({home}), detecta variables negativas y positivas presentes.
Para VISITA ({away}), igual.

Calcula:
  score_h = suma(peso \u00d7 -1 por negativa, +0.5 por positiva) para {home}
  score_a = suma(peso \u00d7 -1 por negativa, +0.5 por positiva) para {away}

Regla de delta:
  Si score_h <= -8: home_delta = -0.10
  Si score_h <= -5: home_delta = -0.06
  Si score_h <= -3: home_delta = -0.03
  Si score_h >= +3: home_delta = +0.03
  Si score_h >= +5: home_delta = +0.05
  (misma regla para away_delta y score_a)

  soft_delta = home_delta - away_delta (pick favorito)
  ou_delta: si hay fatiga/viaje/clima \u2192 negativo; si hay motivacion alta \u2192 0
  confidence: "alta" si detectas 3+ variables con peso>=4, "media" si 1-2, "baja" si ninguna

Responde SOLO JSON sin markdown:
{{
  "score_h": <float>,
  "score_a": <float>,
  "home_delta": <-0.10 a 0.10>,
  "away_delta": <-0.10 a 0.10>,
  "soft_delta": <-0.12 a 0.12>,
  "ou_delta": <-0.08 a 0.08>,
  "flags": ["variable detectada peso=X equipo Y", ...],
  "confidence": "alta|media|baja",
  "raw_summary": "max 15 palabras resumen impacto"
}}
Si no detectas variables relevantes, pon 0.0 en todo y confidence=baja."""

        _r = type("_R",(),{"status_code":200,"json":lambda s=None:{"content":[{"type":"text","text":_gemini(_prompt,use_search=False,max_tokens=250)}]}})()  # gemini
        if _r.status_code == 200:
            import json as _jsd
            _txt = _r.json()["content"][0]["text"].strip()
            _txt = _txt.replace("```json","").replace("```","").strip()
            _data = _jsd.loads(_txt)
            # Clamp all values
            _data["soft_delta"]  = max(-0.12, min(0.12, float(_data.get("soft_delta", 0))))
            _data["home_delta"]  = max(-0.10, min(0.10, float(_data.get("home_delta", 0))))
            _data["away_delta"]  = max(-0.10, min(0.10, float(_data.get("away_delta", 0))))
            _data["ou_delta"]    = max(-0.08, min(0.08, float(_data.get("ou_delta",   0))))
            _data["score_h"]     = float(_data.get("score_h", 0))
            _data["score_a"]     = float(_data.get("score_a", 0))
            _data["flags"]       = [str(f)[:70] for f in _data.get("flags", [])[:6]]
            _data["confidence"]  = _data.get("confidence", "baja")
            _data["raw_summary"] = str(_data.get("raw_summary", ""))[:120]
            # Safety: baja confidence + no flags = no adjustment
            if _data["confidence"] == "baja" and not _data["flags"]:
                for k in ("soft_delta","home_delta","away_delta","ou_delta"):
                    _data[k] = 0.0
            return _data
    except:
        pass
    return _default




def _small_days_apply(pick_prob: float, pick_lbl: str,
                      ph: float, pd: float, pa: float,
                      o25: float, btts: float,
                      sd: dict) -> tuple:
    """
    Aplica los deltas de Small Days. Peso según confianza.
    Retorna (ph_adj, pd_adj, pa_adj, o25_adj, btts_adj).
    Regla: Small Days complementa, nunca domina (max 70% del delta).
    """
    if not sd or (sd.get("confidence","baja") == "baja" and not sd.get("flags")):
        return ph, pd, pa, o25, btts
    _w = {"alta": 0.70, "media": 0.45, "baja": 0.20}.get(sd.get("confidence","baja"), 0.20)
    ph_adj  = max(0.04, min(0.93, ph  + sd.get("home_delta",0) * _w))
    pa_adj  = max(0.04, min(0.93, pa  + sd.get("away_delta",0) * _w))
    _tot    = ph_adj + (pd or 0) + pa_adj
    pd_adj  = ((pd or 0) / _tot) if _tot > 0 else (pd or 0)
    ph_adj /= _tot if _tot > 0 else 1
    pa_adj /= _tot if _tot > 0 else 1
    o25_adj  = max(0.08, min(0.92, o25  + sd.get("ou_delta",0) * _w))
    btts_adj = max(0.08, min(0.92, btts + sd.get("ou_delta",0) * _w * 0.5))
    return ph_adj, pd_adj, pa_adj, o25_adj, btts_adj





@st.cache_data(ttl=1800, show_spinner=False)
def _ia_actuario(home: str, away: str, sport: str,
                 prob_modelo: float, cuota: float, tabla_ctx: str = "") -> dict:
    """El Actuario — Detecta valor real de cuota. TTL=1800s."""
    try:
        prob_mercado = (1 / cuota) if cuota > 1 else prob_modelo
        edge = prob_modelo - prob_mercado
        cuota_justa = round(1 / prob_modelo, 3) if prob_modelo > 0 else cuota
        tabla_line = (f"\nPosicion en tabla: {tabla_ctx}" if tabla_ctx else "")
        prompt = (
            f"Eres El Actuario, especialista en valor de cuota deportiva.\n"
            f"Partido: {home} vs {away} | Deporte: {sport}\n"
            f"Prob modelo: {prob_modelo*100:.1f}% | Cuota: {cuota:.2f} "
            f"(implica {prob_mercado*100:.1f}%) | Edge: {edge*100:.2f}pp\n"
            f"Cuota justa segun modelo: {cuota_justa:.2f}{tabla_line}\n\n"
            f"Analiza si hay valor real. Considera vig casa (~4.5%) y si la posicion "
            f"en tabla sugiere que el mercado sobre/sub valora al equipo.\n"
            f"SOLO JSON sin backticks: "
            f'{{"edge_real": {edge:.4f}, "valor": "positivo|neutro|negativo", '
            f'"cuota_justa": {cuota_justa}, "score": 0-10, '
            f'"razon": "max 15 palabras", "alerta": "max 10 palabras o null"}}'
        )
        r = type("_R",(),{"status_code":200,"json":lambda s=None:{"content":[{"type":"text","text":_gemini(prompt,use_search=False,max_tokens=200)}]}})()  # gemini
        if r.status_code == 200:
            txt = re.sub(r"```json|```", "", r.json()["content"][0]["text"]).strip()
            d = json.loads(txt)
            d.setdefault("edge_real", edge)
            d.setdefault("cuota_justa", cuota_justa)
            d.setdefault("valor", "positivo" if edge > 0.03 else ("neutro" if edge > 0 else "negativo"))
            d.setdefault("score", min(10, max(0, 5 + edge * 40)))
            return d
    except: pass
    val = "positivo" if edge > 0.03 else ("neutro" if edge > 0 else "negativo")
    return {"edge_real": edge, "cuota_justa": cuota_justa, "valor": val,
            "score": max(0, min(10, 5 + edge*40)), "razon": f"Edge {edge*100:.1f}pp vs mercado",
            "alerta": None}


